window.walesCastles=[{"name":"Conwy Castle","lat":53.2802,"lng":-3.8265,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"Built by Edward I between 1283-1287, Conwy Castle is one of the finest surviving medieval fortifications in Europe. Its eight massive towers and town walls are a UNESCO World Heritage Site.","history":"Conwy Castle is a fortification in Conwy, located in North Wales. It was built by Edward I, during his conquest of Wales, between 1283 and 1287. Constructed as part of a wider project to create the walled town of Conwy, the combined defences cost around £15,000, a massive sum for the period. Over the next few centuries, the castle played an important part in several wars. It withstood the siege of Madog ap Llywelyn in the winter of 1294–95, acted as a temporary haven for Richard II in 1399 and was held for several months by forces loyal to Owain Glyndŵr in 1401.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4a/Conwy_Castle%2C_water_view1.jpg/500px-Conwy_Castle%2C_water_view1.jpg","rating":4.6,"reviewCount":12000,"county":"Conwy","tags":["well-preserved","photogenic","kid-friendly"],"access":"paid","_index":195,"gallery":["https://img.castlecore.uk/conwy-castle-2.jpg","https://img.castlecore.uk/conwy-castle-3.jpg","https://img.castlecore.uk/conwy-castle-4.jpg","https://img.castlecore.uk/conwy-castle-5.jpg","https://img.castlecore.uk/conwy-castle-interior-2.jpg","https://img.castlecore.uk/conwy-castle-interior-3.jpg","https://img.castlecore.uk/conwy-castle-interior-4.jpg","https://img.castlecore.uk/conwy-castle-interior-5.jpg"]},{"name":"Caernarfon Castle","lat":53.1393,"lng":-4.2769,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"Edward I's most ambitious castle, Caernarfon was designed to echo the walls of Constantinople. It was the site of the investiture of the Prince of Wales in 1969.","history":"Caernarfon Castle is a medieval fortress in Gwynedd, north-west Wales. The first fortification on the site was a motte-and-bailey castle built in the late 11th century, which King Edward I of England began to replace with the current stone structure in 1283. The castle and town established by Edward acted as the administrative centre of north Wales, and as a result the defences were built on a grand scale. There was a deliberate link with Caernarfon's Roman past—nearby is the Roman fort of Segontium—and the castle's walls are reminiscent of the Walls of Constantinople.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/fa/Caernarfon_Castle_1994.jpg/500px-Caernarfon_Castle_1994.jpg","rating":4.6,"reviewCount":14000,"county":"Gwynedd","tags":["well-preserved","photogenic","kid-friendly"],"access":"paid","_index":196,"gallery":["https://img.castlecore.uk/caernarfon-castle-2.jpg","https://img.castlecore.uk/caernarfon-castle-3.jpg","https://img.castlecore.uk/caernarfon-castle-4.jpg","https://img.castlecore.uk/caernarfon-castle-5.jpg","https://img.castlecore.uk/caernarfon-castle-interior-2.jpg","https://img.castlecore.uk/caernarfon-castle-interior-3.jpg","https://img.castlecore.uk/caernarfon-castle-interior-4.jpg","https://img.castlecore.uk/caernarfon-castle-interior-5.jpg"]},{"name":"Harlech Castle","lat":52.8602,"lng":-4.1094,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"Perched on a rocky crag with views across Snowdonia and Cardigan Bay, Harlech Castle inspired the famous Welsh song 'Men of Harlech'. It withstood several legendary sieges.","history":"Harlech Castle in Harlech, Gwynedd, Wales, is a Grade I listed medieval fortification built onto a rocky knoll close to the Irish Sea. It was built by Edward I during his invasion of Wales between 1282 and 1289 at the relatively modest cost of £8,190. Over the next few centuries, the castle played an important part in several wars, withstanding the siege of Madog ap Llywelyn between 1294 and 1295, but falling to Prince Owain Glyndŵr in 1404. It then became Glyndŵr's residence and military headquarters for the remainder of the uprising until being recaptured by English forces in 1409.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ab/Harlech_Castle_-_Cadw_photograph.jpg/500px-Harlech_Castle_-_Cadw_photograph.jpg","rating":4.5,"reviewCount":5200,"county":"Gwynedd","tags":["dramatic-ruin","photogenic"],"access":"paid","_index":197,"gallery":["https://img.castlecore.uk/harlech-castle-2.jpg","https://img.castlecore.uk/harlech-castle-3.jpg","https://img.castlecore.uk/harlech-castle-4.jpg","https://img.castlecore.uk/harlech-castle-5.jpg","https://img.castlecore.uk/harlech-castle-interior-2.jpg","https://img.castlecore.uk/harlech-castle-interior-3.jpg","https://img.castlecore.uk/harlech-castle-interior-4.jpg","https://img.castlecore.uk/harlech-castle-interior-5.jpg","https://img.castlecore.uk/harlech-castle-gatehouse-2.jpg","https://img.castlecore.uk/harlech-castle-gatehouse-3.jpg","https://img.castlecore.uk/harlech-castle-gatehouse-4.jpg","https://img.castlecore.uk/harlech-castle-gatehouse-5.jpg"]},{"name":"Beaumaris Castle","lat":53.2628,"lng":-4.0906,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"The last and largest of Edward I's Welsh castles, Beaumaris is considered the most technically perfect castle in Britain. Though never completed, its concentric design is a masterpiece.","history":"Beaumaris Castle, in Beaumaris, Anglesey, Wales, was built as part of Edward I's campaign to conquer north Wales after 1282. Plans were probably first made to construct the castle in 1284, but this was delayed due to lack of funds and work only began in 1295 following the Madog ap Llywelyn uprising. A substantial workforce was employed in the initial years under the direction of James of St George. Edward's invasion of Scotland soon diverted funding from the project, however, and work stopped, only recommencing after an invasion scare in 1306. When work finally ceased around 1330 a total of £15,000 had been spent, a huge sum for the period, but the castle remained incomplete.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/95/Flint_-_Flint_Castle_-_20220322133345.jpg/500px-Flint_-_Flint_Castle_-_20220322133345.jpg","rating":4.5,"reviewCount":6800,"county":"Anglesey","tags":["dramatic-ruin","photogenic","kid-friendly"],"access":"paid","_index":198,"gallery":["https://img.castlecore.uk/beaumaris-castle-2.jpg","https://img.castlecore.uk/beaumaris-castle-3.jpg","https://img.castlecore.uk/beaumaris-castle-4.jpg","https://img.castlecore.uk/beaumaris-castle-5.jpg","https://img.castlecore.uk/beaumaris-castle-interior-2.jpg","https://img.castlecore.uk/beaumaris-castle-interior-3.jpg","https://img.castlecore.uk/beaumaris-castle-interior-4.jpg","https://img.castlecore.uk/beaumaris-castle-interior-5.jpg"]},{"name":"Flint Castle","lat":53.2479,"lng":-3.134,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"The first of Edward I's Welsh castles, begun in 1277. Its unique detached great tower was the scene of Richard II's fateful meeting with Bolingbroke, dramatized by Shakespeare.","history":"Flint Castle in Flint, Flintshire, was the first of a series of castles built during King Edward I's campaign to conquer Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Aberystwyth_castle_edit1.jpg/500px-Aberystwyth_castle_edit1.jpg","rating":4.1,"reviewCount":1500,"county":"Flintshire","tags":["dramatic-ruin","hidden-gem","free"],"access":"free","_index":199,"gallery":["https://img.castlecore.uk/flint-castle-2.jpg","https://img.castlecore.uk/flint-castle-3.jpg","https://img.castlecore.uk/flint-castle-4.jpg","https://img.castlecore.uk/flint-castle-5.jpg","https://img.castlecore.uk/flint-castle-ruins-2.jpg","https://img.castlecore.uk/flint-castle-ruins-3.jpg","https://img.castlecore.uk/flint-castle-ruins-4.jpg","https://img.castlecore.uk/flint-castle-ruins-5.jpg","https://img.castlecore.uk/flint-castle-keep-2.jpg","https://img.castlecore.uk/flint-castle-keep-3.jpg","https://img.castlecore.uk/flint-castle-keep-4.jpg","https://img.castlecore.uk/flint-castle-keep-5.jpg","https://img.castlecore.uk/flint-castle-main-2.jpg","https://img.castlecore.uk/flint-castle-main-3.jpg","https://img.castlecore.uk/flint-castle-main-4.jpg","https://img.castlecore.uk/flint-castle-main-5.jpg"]},{"name":"Aberystwyth Castle","lat":52.4154,"lng":-4.0876,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"One of Edward I's ring of castles, Aberystwyth was largely destroyed during the Civil War and much stone was reused. Dramatic ruins remain on the headland above the seafront.","history":"Aberystwyth Castle is a Grade I listed Edwardian fortress located in Aberystwyth, Ceredigion, Mid Wales. It was built in response to the First Welsh War in the late 13th century, replacing an earlier fortress located a mile to the south. During a national uprising by Owain Glyndŵr, the Welsh captured the castle in 1404, but it was recaptured by the English four years later. From 1637 it housed a Royal mint of Charles I, which minted coins from locally mined silver. The castle was slighted by Oliver Cromwell in 1649.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9d/Rhuddlan_Castle%2C_May_2012.jpg/500px-Rhuddlan_Castle%2C_May_2012.jpg","rating":3.9,"reviewCount":1560,"county":"Ceredigion","tags":["dramatic-ruin","hidden-gem","free"],"access":"free","_index":200,"gallery":["https://img.castlecore.uk/aberystwyth-castle-2.jpg","https://img.castlecore.uk/aberystwyth-castle-3.jpg","https://img.castlecore.uk/aberystwyth-castle-4.jpg","https://img.castlecore.uk/aberystwyth-castle-5.jpg","https://img.castlecore.uk/aberystwyth-castle-ruins-2.jpg","https://img.castlecore.uk/aberystwyth-castle-ruins-3.jpg","https://img.castlecore.uk/aberystwyth-castle-ruins-4.jpg","https://img.castlecore.uk/aberystwyth-castle-ruins-5.jpg","https://img.castlecore.uk/aberystwyth-castle-keep-2.jpg","https://img.castlecore.uk/aberystwyth-castle-keep-3.jpg","https://img.castlecore.uk/aberystwyth-castle-keep-4.jpg","https://img.castlecore.uk/aberystwyth-castle-keep-5.jpg"]},{"name":"Rhuddlan Castle","lat":53.2893,"lng":-3.4636,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"Edward I diverted the course of the River Clwyd to supply this concentric castle by sea. The Statute of Rhuddlan, establishing English law in Wales, was issued here in 1284.","history":"Rhuddlan Castle is a castle located in Rhuddlan, Denbighshire, Wales. It was erected by Edward I in 1277, following the First Welsh War.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/37/Aerial_view_of_Cardiff_Castle.jpg/500px-Aerial_view_of_Cardiff_Castle.jpg","rating":4.1,"reviewCount":1670,"county":"Denbighshire","tags":["dramatic-ruin","hidden-gem"],"access":"paid","_index":201,"gallery":["https://img.castlecore.uk/rhuddlan-castle-2.jpg","https://img.castlecore.uk/rhuddlan-castle-3.jpg","https://img.castlecore.uk/rhuddlan-castle-4.jpg","https://img.castlecore.uk/rhuddlan-castle-5.jpg","https://img.castlecore.uk/rhuddlan-castle-keep-2.jpg","https://img.castlecore.uk/rhuddlan-castle-keep-3.jpg","https://img.castlecore.uk/rhuddlan-castle-keep-4.jpg","https://img.castlecore.uk/rhuddlan-castle-keep-5.jpg","https://img.castlecore.uk/rhuddlan-castle-main-2.jpg","https://img.castlecore.uk/rhuddlan-castle-main-3.jpg","https://img.castlecore.uk/rhuddlan-castle-main-4.jpg","https://img.castlecore.uk/rhuddlan-castle-main-5.jpg"]},{"name":"Caerphilly Castle","lat":51.576,"lng":-3.22,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"The largest castle in Wales and second largest in Britain, Caerphilly introduced concentric castle design to the British Isles. Its famous leaning tower out-leans Pisa.","history":"Caerphilly Castle is a medieval fortification in Caerphilly in South Wales. The castle was constructed by Gilbert de Clare in the 13th century as part of his campaign to maintain control of Glamorgan, and saw extensive fighting between Gilbert, his descendants, and the native Welsh rulers. Surrounded by extensive artificial lakes – considered by historian Allen Brown to be \"the most elaborate water defences in all Britain\" – it occupies around 30 acres (12 ha) and is the largest castle in Wales and the third-largest castle in the United Kingdom. It is famous for having introduced concentric castle defences to Britain and for its large gatehouses.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Caerphilly_aerial.jpg/500px-Caerphilly_aerial.jpg","rating":4.5,"reviewCount":8500,"county":"Caerphilly","tags":["dramatic-ruin","photogenic","kid-friendly"],"access":"paid","_index":202,"gallery":["https://img.castlecore.uk/caerphilly-castle-2.jpg","https://img.castlecore.uk/caerphilly-castle-3.jpg","https://img.castlecore.uk/caerphilly-castle-4.jpg","https://img.castlecore.uk/caerphilly-castle-5.jpg","https://img.castlecore.uk/caerphilly-castle-interior-2.jpg","https://img.castlecore.uk/caerphilly-castle-interior-3.jpg","https://img.castlecore.uk/caerphilly-castle-interior-4.jpg","https://img.castlecore.uk/caerphilly-castle-interior-5.jpg"]},{"name":"Cardiff Castle","lat":51.4822,"lng":-3.181,"country":"Wales","type":"castle","era":"11th century","condition":"intact","description":"A Norman castle transformed into a Victorian Gothic fantasy by the Marquess of Bute and architect William Burges. Its lavish Arab Room and banqueting hall are extraordinary.","history":"Cardiff Castle is a medieval castle and Victorian Gothic revival mansion located in the city centre of Cardiff, Wales. The original motte and bailey castle was built in the late 11th century by Norman invaders on top of a 3rd-century Roman fort. The castle was commissioned either by William the Conqueror or by Robert Fitzhamon, and formed the heart of the medieval town of Cardiff and the Marcher Lord territory of Glamorgan. In the 12th century the castle began to be rebuilt in stone, probably by Robert of Gloucester, with a shell keep and substantial defensive walls being erected. Further work was conducted by the 6th Earl of Gloucester in the second half of the 13th century.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/37/Aerial_view_of_Cardiff_Castle.jpg/500px-Aerial_view_of_Cardiff_Castle.jpg","rating":4.6,"reviewCount":12000,"county":"Cardiff","tags":["well-preserved","kid-friendly","photogenic"],"access":"paid","_index":203,"gallery":["https://img.castlecore.uk/cardiff-castle-2.jpg","https://img.castlecore.uk/cardiff-castle-3.jpg","https://img.castlecore.uk/cardiff-castle-4.jpg","https://img.castlecore.uk/cardiff-castle-5.jpg","https://img.castlecore.uk/cardiff-castle-interior-2.jpg","https://img.castlecore.uk/cardiff-castle-interior-3.jpg","https://img.castlecore.uk/cardiff-castle-interior-4.jpg","https://img.castlecore.uk/cardiff-castle-interior-5.jpg"]},{"name":"Castell Coch","lat":51.5321,"lng":-3.2548,"country":"Wales","type":"castle","era":"19th century","condition":"intact","description":"A Victorian Gothic fairy-tale castle rebuilt on medieval foundations by the Marquess of Bute. Its conical towers and lavishly decorated interiors make it one of Wales' most unusual castles.","history":"Castell Coch is a 19th-century Gothic Revival castle built above the village of Tongwynlais in Wales. The first castle on the site was built by the Normans after 1081 to protect the newly conquered town of Cardiff and control the route along the River Taff. Abandoned shortly afterwards, the castle's earth motte was reused by Gilbert de Clare as the basis for a new stone fortification, which he built between 1267 and 1277 to control his freshly annexed Welsh lands. This castle may have been destroyed in the native Welsh rebellion of 1314.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/34/Raglan_Castle%27s_main_entrance.jpg/500px-Raglan_Castle%27s_main_entrance.jpg","rating":4.3,"reviewCount":3450,"county":"Cardiff","tags":["well-preserved","photogenic","kid-friendly"],"access":"paid","_index":204,"gallery":["https://img.castlecore.uk/castell-coch-2.jpg","https://img.castlecore.uk/castell-coch-3.jpg","https://img.castlecore.uk/castell-coch-4.jpg","https://img.castlecore.uk/castell-coch-5.jpg","https://img.castlecore.uk/castell-coch-interior-2.jpg","https://img.castlecore.uk/castell-coch-interior-3.jpg","https://img.castlecore.uk/castell-coch-interior-4.jpg","https://img.castlecore.uk/castell-coch-interior-5.jpg","https://img.castlecore.uk/castell-coch-interior-main-2.jpg","https://img.castlecore.uk/castell-coch-interior-main-3.jpg","https://img.castlecore.uk/castell-coch-interior-main-4.jpg","https://img.castlecore.uk/castell-coch-interior-main-5.jpg"]},{"name":"Raglan Castle","lat":51.7673,"lng":-2.8514,"country":"Wales","type":"castle","era":"15th century","condition":"ruin","description":"A late medieval castle with grand hexagonal keep known as the Great Tower, Raglan was the last castle in Wales to fall during the English Civil War. Its ruins are remarkably elegant.","history":"Raglan Castle is a late medieval castle located just north of the village of Raglan in the county of Monmouthshire in south east Wales. The modern castle dates from between the 15th and early 17th centuries, when the successive ruling families of the Herberts and the Somersets created a luxurious, fortified castle, complete with a large hexagonal keep, known as the Great Tower or the Yellow Tower of Gwent. Surrounded by parkland, water gardens and terraces, the castle was considered by contemporaries to be the equal of any other in England or Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6c/Pembroke_Castle_-_June_2011.jpg/500px-Pembroke_Castle_-_June_2011.jpg","rating":4.5,"reviewCount":3800,"county":"Monmouthshire","tags":["dramatic-ruin","photogenic"],"access":"paid","_index":205,"gallery":["https://img.castlecore.uk/raglan-castle-2.jpg","https://img.castlecore.uk/raglan-castle-3.jpg","https://img.castlecore.uk/raglan-castle-4.jpg","https://img.castlecore.uk/raglan-castle-5.jpg","https://img.castlecore.uk/raglan-castle-keep-2.jpg","https://img.castlecore.uk/raglan-castle-keep-3.jpg","https://img.castlecore.uk/raglan-castle-keep-4.jpg","https://img.castlecore.uk/raglan-castle-keep-5.jpg"]},{"name":"Pembroke Castle","lat":51.6746,"lng":-4.9838,"country":"Wales","type":"castle","era":"11th century","condition":"partial ruin","description":"Birthplace of Henry VII, founder of the Tudor dynasty, Pembroke Castle features a massive circular keep. It was one of the most important Norman strongholds in Wales.","history":"Pembroke Castle is a medieval castle in the centre of Pembroke, Pembrokeshire in Wales. The castle was the original family seat of the Earldom of Pembroke. A Grade I listed building since 1951, it underwent major restoration during the early 20th century.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/cf/Kidwelly_castle_whole.JPG/500px-Kidwelly_castle_whole.JPG","rating":4.6,"reviewCount":6500,"county":"Pembrokeshire","tags":["well-preserved","kid-friendly","photogenic"],"access":"paid","_index":206,"gallery":["https://img.castlecore.uk/pembroke-castle-2.jpg","https://img.castlecore.uk/pembroke-castle-3.jpg","https://img.castlecore.uk/pembroke-castle-4.jpg","https://img.castlecore.uk/pembroke-castle-5.jpg","https://img.castlecore.uk/pembroke-castle-interior-2.jpg","https://img.castlecore.uk/pembroke-castle-interior-3.jpg","https://img.castlecore.uk/pembroke-castle-interior-4.jpg","https://img.castlecore.uk/pembroke-castle-interior-5.jpg","https://img.castlecore.uk/pembroke-castle-keep-2.jpg","https://img.castlecore.uk/pembroke-castle-keep-3.jpg","https://img.castlecore.uk/pembroke-castle-keep-4.jpg","https://img.castlecore.uk/pembroke-castle-keep-5.jpg"]},{"name":"Kidwelly Castle","lat":51.7383,"lng":-4.3108,"country":"Wales","type":"castle","era":"12th century","condition":"partial ruin","description":"A remarkably well-preserved concentric castle above the River Gwendraeth, Kidwelly was the setting for the opening scene of Monty Python and the Holy Grail.","history":"Kidwelly Castle is a Norman castle overlooking the River Gwendraeth and the town of Kidwelly, Carmarthenshire, Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/20/Carreg_Cennen_Castle_on_its_crag_and_in_its_Carmarthenshire_landscape%2C_autumn_light.jpg/500px-Carreg_Cennen_Castle_on_its_crag_and_in_its_Carmarthenshire_landscape%2C_autumn_light.jpg","rating":4.5,"reviewCount":3200,"county":"Carmarthenshire","tags":["dramatic-ruin","filming-location","photogenic","hidden-gem"],"access":"paid","_index":207,"gallery":["https://img.castlecore.uk/kidwelly-castle-2.jpg","https://img.castlecore.uk/kidwelly-castle-3.jpg","https://img.castlecore.uk/kidwelly-castle-4.jpg","https://img.castlecore.uk/kidwelly-castle-5.jpg","https://img.castlecore.uk/kidwelly-castle-interior-2.jpg","https://img.castlecore.uk/kidwelly-castle-interior-3.jpg","https://img.castlecore.uk/kidwelly-castle-interior-4.jpg","https://img.castlecore.uk/kidwelly-castle-interior-5.jpg","https://img.castlecore.uk/kidwelly-castle-keep-2.jpg","https://img.castlecore.uk/kidwelly-castle-keep-3.jpg","https://img.castlecore.uk/kidwelly-castle-keep-4.jpg","https://img.castlecore.uk/kidwelly-castle-keep-5.jpg"]},{"name":"Carreg Cennen Castle","lat":51.8556,"lng":-3.9379,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"Dramatically perched on a limestone cliff in the Brecon Beacons, Carreg Cennen is perhaps the most spectacularly sited castle in Wales. A natural cave extends beneath the fortification.","history":"Carreg Cennen Castle is a castle sited on a high rocky outcrop overlooking the River Cennen, close to the village of Trap, four miles south east of Llandeilo in Carmarthenshire, Wales. Castell Carreg Cennen means castle on a rock next to Cennen, the river name itself being a reference either to cen meaning lichen or perhaps a personal name.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/3c/Dylan_admires_......._the_medieval_Laugharne_castle_-_geograph.org.uk_-_1708250.jpg/500px-Dylan_admires_......._the_medieval_Laugharne_castle_-_geograph.org.uk_-_1708250.jpg","rating":4.5,"reviewCount":2800,"county":"Carmarthenshire","tags":["dramatic-ruin","photogenic","hidden-gem"],"access":"paid","_index":208,"gallery":["https://img.castlecore.uk/carreg-cennen-castle-2.jpg","https://img.castlecore.uk/carreg-cennen-castle-3.jpg","https://img.castlecore.uk/carreg-cennen-castle-4.jpg","https://img.castlecore.uk/carreg-cennen-castle-5.jpg","https://img.castlecore.uk/carreg-cennen-castle-keep-2.jpg","https://img.castlecore.uk/carreg-cennen-castle-keep-3.jpg","https://img.castlecore.uk/carreg-cennen-castle-keep-4.jpg","https://img.castlecore.uk/carreg-cennen-castle-keep-5.jpg"]},{"name":"Laugharne Castle","lat":51.7712,"lng":-4.4625,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"Overlooking the Taf estuary, Laugharne Castle was converted into a Tudor mansion. Dylan Thomas described it as 'the best castle in the world' and lived in its shadow.","history":"Laugharne Castle is in Laugharne, Carmarthenshire, Wales. The castle, located on the estuary of the River Tâf, was originally established in 1116. It was rebuilt as a Norman stronghold. There have been many alterations since then, including becoming a Tudor fortified manor house in the sixteenth century. It changed hands twice during the English Civil War, being eventually captured by Parliamentary forces in 1644.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/13/Llansteffan_Castle_and_Beach.jpg/500px-Llansteffan_Castle_and_Beach.jpg","rating":4,"reviewCount":1780,"county":"Carmarthenshire","tags":["romantic-ruin","hidden-gem"],"access":"paid","_index":209,"gallery":["https://img.castlecore.uk/laugharne-castle-2.jpg","https://img.castlecore.uk/laugharne-castle-3.jpg","https://img.castlecore.uk/laugharne-castle-4.jpg","https://img.castlecore.uk/laugharne-castle-5.jpg","https://img.castlecore.uk/laugharne-castle-interior-2.jpg","https://img.castlecore.uk/laugharne-castle-interior-3.jpg","https://img.castlecore.uk/laugharne-castle-interior-4.jpg","https://img.castlecore.uk/laugharne-castle-interior-5.jpg","https://img.castlecore.uk/laugharne-castle-main-2.jpg","https://img.castlecore.uk/laugharne-castle-main-3.jpg","https://img.castlecore.uk/laugharne-castle-main-4.jpg","https://img.castlecore.uk/laugharne-castle-main-5.jpg"]},{"name":"Llansteffan Castle","lat":51.7674,"lng":-4.3863,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A Norman castle overlooking the Towy estuary, Llansteffan changed hands between Welsh and English multiple times. The twin-towered gatehouse and curtain walls survive on the hilltop.","history":"Llansteffan Castle is a privately owned castle in Llansteffan, Carmarthenshire, Wales, overlooking the River Tywi estuary in Carmarthen Bay.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/Oystermouth_Castle_-_geograph.org.uk_-_292767.jpg/500px-Oystermouth_Castle_-_geograph.org.uk_-_292767.jpg","rating":4,"reviewCount":1120,"county":"Carmarthenshire","tags":["dramatic-ruin","hidden-gem","free","photogenic"],"access":"free","_index":210,"gallery":["https://img.castlecore.uk/llansteffan-castle-2.jpg","https://img.castlecore.uk/llansteffan-castle-3.jpg","https://img.castlecore.uk/llansteffan-castle-4.jpg","https://img.castlecore.uk/llansteffan-castle-5.jpg","https://img.castlecore.uk/llansteffan-castle-keep-2.jpg","https://img.castlecore.uk/llansteffan-castle-keep-3.jpg","https://img.castlecore.uk/llansteffan-castle-keep-4.jpg","https://img.castlecore.uk/llansteffan-castle-keep-5.jpg","https://img.castlecore.uk/llansteffan-castle-main-2.jpg","https://img.castlecore.uk/llansteffan-castle-main-3.jpg","https://img.castlecore.uk/llansteffan-castle-main-4.jpg","https://img.castlecore.uk/llansteffan-castle-main-5.jpg"]},{"name":"Oystermouth Castle","lat":51.5718,"lng":-3.9918,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A Norman castle overlooking Swansea Bay, Oystermouth was rebuilt several times after Welsh attacks. The decorated chapel with its piscina is a rare survival.","history":"Oystermouth Castle is a Norman stone castle in Wales, overlooking Swansea Bay on the east side of the Gower Peninsula in the village of Mumbles.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d8/Neath_abbey%2C_Glamorgan_-_founded_by_Richard_De_Cranville%2C_circa_1129.jpeg/500px-Neath_abbey%2C_Glamorgan_-_founded_by_Richard_De_Cranville%2C_circa_1129.jpeg","rating":4.2,"reviewCount":1400,"county":"Swansea","tags":["dramatic-ruin","hidden-gem"],"access":"paid","_index":211,"gallery":["https://img.castlecore.uk/oystermouth-castle-2.jpg","https://img.castlecore.uk/oystermouth-castle-3.jpg","https://img.castlecore.uk/oystermouth-castle-4.jpg","https://img.castlecore.uk/oystermouth-castle-5.jpg","https://img.castlecore.uk/oystermouth-castle-interior-2.jpg","https://img.castlecore.uk/oystermouth-castle-interior-3.jpg","https://img.castlecore.uk/oystermouth-castle-interior-4.jpg","https://img.castlecore.uk/oystermouth-castle-interior-5.jpg","https://img.castlecore.uk/oystermouth-castle-main-2.jpg","https://img.castlecore.uk/oystermouth-castle-main-3.jpg","https://img.castlecore.uk/oystermouth-castle-main-4.jpg","https://img.castlecore.uk/oystermouth-castle-main-5.jpg"]},{"name":"Neath Abbey","lat":51.6544,"lng":-3.8004,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"A Cistercian abbey whose impressive ruins include the dormitory undercroft and chapter house. Unusually, a Tudor mansion was built within the abbey ruins after the Dissolution.","history":"Neath Abbey was a Cistercian monastery, located near the present-day town of Neath in South Wales, UK. It was once the largest abbey in Wales. Substantial ruins can still be seen, and are in the care of Cadw. Tudor historian John Leland called Neath Abbey \"the fairest abbey of all Wales.\"","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/Ewenny_Priory_Church.jpg/500px-Ewenny_Priory_Church.jpg","rating":4,"reviewCount":1120,"county":"Neath Port Talbot","tags":["dramatic-ruin","hidden-gem","free"],"access":"free","_index":212,"gallery":["https://img.castlecore.uk/neath-abbey-2.jpg","https://img.castlecore.uk/neath-abbey-3.jpg","https://img.castlecore.uk/neath-abbey-4.jpg","https://img.castlecore.uk/neath-abbey-5.jpg","https://img.castlecore.uk/neath-abbey-ruins-2.jpg","https://img.castlecore.uk/neath-abbey-ruins-3.jpg","https://img.castlecore.uk/neath-abbey-ruins-4.jpg","https://img.castlecore.uk/neath-abbey-ruins-5.jpg","https://img.castlecore.uk/neath-abbey-main-2.jpg","https://img.castlecore.uk/neath-abbey-main-3.jpg","https://img.castlecore.uk/neath-abbey-main-4.jpg","https://img.castlecore.uk/neath-abbey-main-5.jpg"]},{"name":"Ewenny Priory","lat":51.4771,"lng":-3.5251,"country":"Wales","type":"abbey","era":"12th century","condition":"partial ruin","description":"One of the most fortified religious houses in Britain, Ewenny's precinct walls have drum towers. The Norman nave of the priory church is still in use as the parish church.","history":"Ewenny Priory, in Ewenny in the Vale of Glamorgan, Wales, was a monastery of the Benedictine order, founded in the 12th century. The priory was unusual in having extensive military-style defences and in its state of preservation; the architectural historian John Newman described it as “the most complete and impressive Norman ecclesiastical building in Glamorgan”. Following the Dissolution of the Monasteries, parts of the priory were converted into a private house by Sir Edward Carne, a lawyer and diplomat. This Elizabethan house was demolished between 1803 and 1805 and replaced by a Georgian mansion, Ewenny Priory House.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1c/Margamabbey-wyrdlight-7458.jpg/500px-Margamabbey-wyrdlight-7458.jpg","rating":3.9,"reviewCount":670,"county":"Vale of Glamorgan","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":213,"gallery":["https://img.castlecore.uk/ewenny-priory-2.jpg","https://img.castlecore.uk/ewenny-priory-3.jpg","https://img.castlecore.uk/ewenny-priory-4.jpg","https://img.castlecore.uk/ewenny-priory-5.jpg"]},{"name":"Margam Abbey","lat":51.5549,"lng":-3.7299,"country":"Wales","type":"abbey","era":"12th century","condition":"partial ruin","description":"A Cistercian abbey whose chapter house is one of the finest in Wales. The nave still serves as the parish church, while the ruins sit in Margam Country Park.","history":"Margam Abbey was a Cistercian monastery, located in the village of Margam, a suburb of modern Port Talbot in Wales. The nave of the abbey church is still in use as the church of St Mary in the Church in Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/33/Chepstow_Castle_%284197%29.jpg/500px-Chepstow_Castle_%284197%29.jpg","rating":4,"reviewCount":1340,"county":"Neath Port Talbot","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":214,"gallery":["https://img.castlecore.uk/margam-abbey-2.jpg","https://img.castlecore.uk/margam-abbey-3.jpg","https://img.castlecore.uk/margam-abbey-4.jpg","https://img.castlecore.uk/margam-abbey-5.jpg"]},{"name":"Chepstow Castle","lat":51.6442,"lng":-2.6747,"country":"Wales","type":"castle","era":"11th century","condition":"partial ruin","description":"The oldest surviving post-Roman stone fortification in Britain, begun in 1067. It stretches along a limestone cliff above the Wye with buildings from every century up to the 17th.","history":"Chepstow Castle at Chepstow, Monmouthshire, Wales, is the oldest surviving post-Roman stone fortification in Britain. Located above cliffs on the River Wye, construction began in 1067 under the instruction of the Norman Lord William FitzOsbern. Originally known as Striguil, it was the southernmost of a chain of castles built in the Welsh Marches, and with its attached Lordship of Striguil took the name of the adjoining market town in about the 14th century.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/46/SKENFRITH_CASTLE.jpg/500px-SKENFRITH_CASTLE.jpg","rating":4.5,"reviewCount":5200,"county":"Monmouthshire","tags":["dramatic-ruin","photogenic","kid-friendly"],"access":"paid","_index":215,"gallery":["https://img.castlecore.uk/chepstow-castle-2.jpg","https://img.castlecore.uk/chepstow-castle-3.jpg","https://img.castlecore.uk/chepstow-castle-4.jpg","https://img.castlecore.uk/chepstow-castle-5.jpg","https://img.castlecore.uk/chepstow-castle-interior-2.jpg","https://img.castlecore.uk/chepstow-castle-interior-3.jpg","https://img.castlecore.uk/chepstow-castle-interior-4.jpg","https://img.castlecore.uk/chepstow-castle-interior-5.jpg"]},{"name":"Tintern Abbey","lat":51.6966,"lng":-2.6783,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"Founded by Cistercian monks in 1131, Tintern Abbey inspired Wordsworth's famous poem. Its graceful Gothic arches stand nearly complete in the wooded Wye Valley.","history":"Tintern Abbey is a ruined medieval abbey adjacent to the village of Tintern in Monmouthshire, on the Welsh bank of the River Wye, which at this location forms the border between Monmouthshire in Wales and Gloucestershire in England. Founded on 9 May 1131 by Walter de Clare, Lord of Chepstow, it was the first Cistercian foundation in Wales, and the second in Britain.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/23/TinternAbbey_WestEnd.jpg/500px-TinternAbbey_WestEnd.jpg","rating":4.7,"reviewCount":7500,"county":"Monmouthshire","tags":["romantic-ruin","hidden-gem"],"access":"paid","_index":216,"gallery":["https://img.castlecore.uk/tintern-abbey-2.jpg","https://img.castlecore.uk/tintern-abbey-3.jpg","https://img.castlecore.uk/tintern-abbey-4.jpg","https://img.castlecore.uk/tintern-abbey-5.jpg","https://img.castlecore.uk/tintern-abbey-ruins-2.jpg","https://img.castlecore.uk/tintern-abbey-ruins-3.jpg","https://img.castlecore.uk/tintern-abbey-ruins-4.jpg","https://img.castlecore.uk/tintern-abbey-ruins-5.jpg","https://img.castlecore.uk/tintern-abbey-interior-2.jpg","https://img.castlecore.uk/tintern-abbey-interior-3.jpg","https://img.castlecore.uk/tintern-abbey-interior-4.jpg","https://img.castlecore.uk/tintern-abbey-interior-5.jpg"]},{"name":"White Castle","lat":51.8095,"lng":-2.8817,"country":"Wales","type":"castle","era":"11th-13th century","condition":"ruin","description":"A ghostly moated fortress in the Welsh Marches — one of three sister castles that guarded the road from Wales to Hereford for centuries.","history":"Established by the Normans after 1066 to protect the route to Hereford. Part of the Three Castles lordship with Grosmont and Skenfrith from 1135. Given to Hubert de Burgh by King John in 1201. Substantially rebuilt with stone curtain walls and mural towers. Named for its white-plastered walls.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/3/31/GrosmontCastle4.jpg/500px-GrosmontCastle4.jpg","rating":4.3,"reviewCount":1200,"county":"Monmouthshire","tags":["romantic-ruin","hidden-gem","photogenic","free-entry","medieval","norman"],"access":"paid","_index":217,"gallery":["https://img.castlecore.uk/white-castle-2.jpg","https://img.castlecore.uk/white-castle-3.jpg","https://img.castlecore.uk/white-castle-4.jpg","https://img.castlecore.uk/white-castle-5.jpg","https://img.castlecore.uk/white-castle-ruins-2.jpg","https://img.castlecore.uk/white-castle-ruins-3.jpg","https://img.castlecore.uk/white-castle-ruins-4.jpg","https://img.castlecore.uk/white-castle-ruins-5.jpg","https://img.castlecore.uk/white-castle-keep-2.jpg","https://img.castlecore.uk/white-castle-keep-3.jpg","https://img.castlecore.uk/white-castle-keep-4.jpg","https://img.castlecore.uk/white-castle-keep-5.jpg"],"youtube":["G-UjT8jGLoA","_F8kSwh8xQI","J-0d-ttEsgY"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/White_Castle_(castle)"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/white-castle"},{"name":"Three Castles Walk","url":"https://www.threecastleswalk.co.uk/"}]},{"name":"Skenfrith Castle","lat":51.8545,"lng":-2.7834,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"One of the Three Castles built to guard the route from England into South Wales. Its round keep stands within a four-sided curtain wall surrounded by a moat.","history":"Skenfrith Castle is a ruined castle in the village of Skenfrith in Monmouthshire, Wales. The fortification was established by the Normans in the wake of the invasion of England in 1066, to protect the route from Wales to Hereford. Possibly commissioned by William fitz Osbern, the Earl of Hereford, the castle comprised earthworks with timber defences. In 1135, a major Welsh revolt took place and in response King Stephen brought together Skenfrith Castle and its sister fortifications of Grosmont and White Castle to form a lordship known as the \"Three Castles\", which continued to play a role in defending the region from Welsh attack for several centuries.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/6f/Aerial_view_of_Denbigh_Castle%2C_by_Cadw.jpg/500px-Aerial_view_of_Denbigh_Castle%2C_by_Cadw.jpg","rating":3.9,"reviewCount":780,"county":"Monmouthshire","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":218,"gallery":["https://img.castlecore.uk/skenfrith-castle-2.jpg","https://img.castlecore.uk/skenfrith-castle-3.jpg","https://img.castlecore.uk/skenfrith-castle-4.jpg","https://img.castlecore.uk/skenfrith-castle-5.jpg","https://img.castlecore.uk/skenfrith-castle-ruins-2.jpg","https://img.castlecore.uk/skenfrith-castle-ruins-3.jpg","https://img.castlecore.uk/skenfrith-castle-ruins-4.jpg","https://img.castlecore.uk/skenfrith-castle-ruins-5.jpg","https://img.castlecore.uk/skenfrith-castle-keep-2.jpg","https://img.castlecore.uk/skenfrith-castle-keep-3.jpg","https://img.castlecore.uk/skenfrith-castle-keep-4.jpg","https://img.castlecore.uk/skenfrith-castle-keep-5.jpg"]},{"name":"Grosmont Castle","lat":51.8872,"lng":-2.8636,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"The third of the Three Castles, Grosmont was a favoured residence of the Lancastrian dukes. Its chimney, one of the earliest in any English or Welsh castle, still stands.","history":"Grosmont Castle is a ruined castle in the village of Grosmont, Monmouthshire, Wales. The fortification was established by the Normans in the wake of the invasion of England in 1066, to protect the route from Wales to Hereford. Possibly commissioned by William FitzOsbern, 1st Earl of Hereford, it was originally an earthwork design with timber defences. In 1135, a major Welsh revolt took place, and in response King Stephen brought together Grosmont Castle and its sister fortifications of Skenfrith and White Castle to form a lordship known as the \"Three Castles\", which continued to play a role in defending the region from Welsh attack for several centuries.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/2/24/Castell_Cricieth_o%27r_awyr_yn_2023_-_Cricieth_Castle_from_a_drone_-_Welsg_built_castle_in_Gwynedd%2C_Wales_41_%28cropped%29.png/500px-Castell_Cricieth_o%27r_awyr_yn_2023_-_Cricieth_Castle_from_a_drone_-_Welsg_built_castle_in_Gwynedd%2C_Wales_41_%28cropped%29.png","rating":3.8,"reviewCount":560,"county":"Monmouthshire","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":219,"gallery":["https://img.castlecore.uk/grosmont-castle-2.jpg","https://img.castlecore.uk/grosmont-castle-3.jpg","https://img.castlecore.uk/grosmont-castle-4.jpg","https://img.castlecore.uk/grosmont-castle-5.jpg","https://img.castlecore.uk/grosmont-castle-ruins-2.jpg","https://img.castlecore.uk/grosmont-castle-ruins-3.jpg","https://img.castlecore.uk/grosmont-castle-ruins-4.jpg","https://img.castlecore.uk/grosmont-castle-ruins-5.jpg","https://img.castlecore.uk/grosmont-castle-keep-2.jpg","https://img.castlecore.uk/grosmont-castle-keep-3.jpg","https://img.castlecore.uk/grosmont-castle-keep-4.jpg","https://img.castlecore.uk/grosmont-castle-keep-5.jpg"]},{"name":"Denbigh Castle","lat":53.1841,"lng":-3.4172,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"Crowning a hilltop above the Vale of Clwyd, Denbigh Castle was built by Henry de Lacy after Edward I's conquest. Its unusual triple-towered gatehouse is unique in Britain.","history":"Denbigh Castle and town walls were built to control the lordship of Denbigh after the Conquest of Wales by Edward I of England in 1282. The lands were granted to Henry de Lacy, Earl of Lincoln, who began to build a new walled town, colonised by immigrants from England, protected by a substantial castle and surrounded by deer parks for hunting. The work had not been completed by 1294, when the Welsh temporarily seized the castle during the Madog ap Llywelyn revolt. The defences continued to be improved, although the castle was not completely finished by the time of Henry's death in 1311.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/db/Dolbadarn_Castle_Cadw.jpg/500px-Dolbadarn_Castle_Cadw.jpg","rating":4.1,"reviewCount":1560,"county":"Denbighshire","tags":["dramatic-ruin","hidden-gem"],"access":"paid","_index":220,"gallery":["https://img.castlecore.uk/denbigh-castle-2.jpg","https://img.castlecore.uk/denbigh-castle-3.jpg","https://img.castlecore.uk/denbigh-castle-4.jpg","https://img.castlecore.uk/denbigh-castle-5.jpg","https://img.castlecore.uk/denbigh-castle-interior-2.jpg","https://img.castlecore.uk/denbigh-castle-interior-3.jpg","https://img.castlecore.uk/denbigh-castle-interior-4.jpg","https://img.castlecore.uk/denbigh-castle-interior-5.jpg","https://img.castlecore.uk/denbigh-castle-main-2.jpg","https://img.castlecore.uk/denbigh-castle-main-3.jpg","https://img.castlecore.uk/denbigh-castle-main-4.jpg","https://img.castlecore.uk/denbigh-castle-main-5.jpg"]},{"name":"Criccieth Castle","lat":52.917,"lng":-4.2325,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A native Welsh castle built by Llywelyn the Great, later modified by Edward I. Its twin-towered gatehouse overlooks Cardigan Bay from a rocky headland.","history":"Criccieth Castle is a ruined thirteenth-century castle in Criccieth, Gwynedd, Wales. It is located on a rocky headland overlooking Tremadog Bay and consists of an inner ward almost surrounded by an outer ward. The twin-towered inner gatehouse is the most prominent remaining feature and survives to almost its full height, as does the inner curtain wall. The outer curtain wall, the inner ward buildings, and the castle's other three towers are significantly more ruinous, and in places survive only as foundations.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Dolwyddelan_Castle%2C_Conwy%2C_Wales_%28cropped%29.jpg/500px-Dolwyddelan_Castle%2C_Conwy%2C_Wales_%28cropped%29.jpg","rating":4.2,"reviewCount":1890,"county":"Gwynedd","tags":["dramatic-ruin","photogenic","hidden-gem"],"access":"paid","_index":221,"gallery":["https://img.castlecore.uk/criccieth-castle-2.jpg","https://img.castlecore.uk/criccieth-castle-3.jpg","https://img.castlecore.uk/criccieth-castle-4.jpg","https://img.castlecore.uk/criccieth-castle-5.jpg","https://img.castlecore.uk/criccieth-castle-ruins-2.jpg","https://img.castlecore.uk/criccieth-castle-ruins-3.jpg","https://img.castlecore.uk/criccieth-castle-ruins-4.jpg","https://img.castlecore.uk/criccieth-castle-ruins-5.jpg","https://img.castlecore.uk/criccieth-castle-keep-2.jpg","https://img.castlecore.uk/criccieth-castle-keep-3.jpg","https://img.castlecore.uk/criccieth-castle-keep-4.jpg","https://img.castlecore.uk/criccieth-castle-keep-5.jpg"]},{"name":"Dolbadarn Castle","lat":53.118,"lng":-4.1166,"country":"Wales","type":"tower house","era":"13th century","condition":"ruin","description":"A native Welsh castle built by Llywelyn the Great at the foot of Snowdon, guarding the Llanberis Pass. Its round tower is one of the finest surviving examples of a Welsh princely castle.","history":"Dolbadarn Castle is a fortification built by the Welsh prince Llywelyn the Great during the early 13th century, at the base of the Llanberis Pass, in northern Wales. The castle was important both militarily and as a symbol of Llywelyn's power and authority. The castle features a large stone keep, which historian Richard Avent considers \"the finest surviving example of a Welsh round tower\". In 1284 Dolbadarn was taken by Edward I, who removed some of its timbers to build his new castle at Caernarfon. The castle was used as a manor house for some years, before falling into ruin.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4b/CastellybereFMA01.jpg/500px-CastellybereFMA01.jpg","rating":4.4,"reviewCount":1600,"county":"Gwynedd","tags":["dramatic-ruin","photogenic","hidden-gem","free"],"access":"free","_index":222,"gallery":["https://img.castlecore.uk/dolbadarn-castle-2.jpg","https://img.castlecore.uk/dolbadarn-castle-3.jpg","https://img.castlecore.uk/dolbadarn-castle-4.jpg","https://img.castlecore.uk/dolbadarn-castle-5.jpg","https://img.castlecore.uk/dolbadarn-castle-ruins-2.jpg","https://img.castlecore.uk/dolbadarn-castle-ruins-3.jpg","https://img.castlecore.uk/dolbadarn-castle-ruins-4.jpg","https://img.castlecore.uk/dolbadarn-castle-ruins-5.jpg","https://img.castlecore.uk/dolbadarn-castle-keep-2.jpg","https://img.castlecore.uk/dolbadarn-castle-keep-3.jpg","https://img.castlecore.uk/dolbadarn-castle-keep-4.jpg","https://img.castlecore.uk/dolbadarn-castle-keep-5.jpg","https://img.castlecore.uk/dolbadarn-castle-main-2.jpg","https://img.castlecore.uk/dolbadarn-castle-main-3.jpg","https://img.castlecore.uk/dolbadarn-castle-main-4.jpg","https://img.castlecore.uk/dolbadarn-castle-main-5.jpg"]},{"name":"Dolwyddelan Castle","lat":52.9997,"lng":-3.8866,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"Reputed birthplace of Llywelyn the Great, this Welsh-built castle commands the Lledr Valley. Its rectangular keep was repaired by Edward I after capturing it in 1283.","history":"Dolwyddelan Castle is a thirteenth-century castle located west of Dolwyddelan in Conwy County Borough, Wales. Tomen Castell, a late twelfth-century tower, is located south-east of the castle.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/89/Ewloe_Castle_-_geograph.org.uk_-_878422.jpg/500px-Ewloe_Castle_-_geograph.org.uk_-_878422.jpg","rating":4.1,"reviewCount":1230,"county":"Conwy","tags":["dramatic-ruin","hidden-gem","photogenic"],"access":"paid","_index":223,"gallery":["https://img.castlecore.uk/dolwyddelan-castle-2.jpg","https://img.castlecore.uk/dolwyddelan-castle-3.jpg","https://img.castlecore.uk/dolwyddelan-castle-4.jpg","https://img.castlecore.uk/dolwyddelan-castle-5.jpg","https://img.castlecore.uk/dolwyddelan-castle-ruins-2.jpg","https://img.castlecore.uk/dolwyddelan-castle-ruins-3.jpg","https://img.castlecore.uk/dolwyddelan-castle-ruins-4.jpg","https://img.castlecore.uk/dolwyddelan-castle-ruins-5.jpg","https://img.castlecore.uk/dolwyddelan-castle-keep-2.jpg","https://img.castlecore.uk/dolwyddelan-castle-keep-3.jpg","https://img.castlecore.uk/dolwyddelan-castle-keep-4.jpg","https://img.castlecore.uk/dolwyddelan-castle-keep-5.jpg"]},{"name":"Castell y Bere","lat":52.692,"lng":-3.952,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"The last native Welsh castle to fall to Edward I, Castell y Bere occupies a rocky ridge in a remote valley below Cadair Idris. Its D-shaped towers are distinctively Welsh.","history":"Castell y Bere is a Welsh castle near Llanfihangel-y-pennant in Gwynedd, Wales. Constructed by Llywelyn the Great in the 1220s, the stone castle was intended to maintain his authority over the local people and to defend the south-west part of the princedom of Gwynedd. In 1282, war with Edward I of England resulted in the death of Llywelyn's grandson, Llywelyn ap Gruffudd, and Castell y Bere fell to English forces. Edward I expanded the castle further and established a small town beside it. In 1294 the Welsh leader Madog ap Llywelyn mounted a major revolt and the castle was besieged and apparently burnt. Edward did not repair it and it became ruined.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b6/ChirkCastle1.JPG/500px-ChirkCastle1.JPG","rating":4,"reviewCount":890,"county":"Gwynedd","tags":["romantic-ruin","hidden-gem","free","photogenic"],"access":"free","_index":224,"gallery":["https://img.castlecore.uk/castell-y-bere-2.jpg","https://img.castlecore.uk/castell-y-bere-3.jpg","https://img.castlecore.uk/castell-y-bere-4.jpg","https://img.castlecore.uk/castell-y-bere-5.jpg","https://img.castlecore.uk/castell-y-bere-ruins-2.jpg","https://img.castlecore.uk/castell-y-bere-ruins-3.jpg","https://img.castlecore.uk/castell-y-bere-ruins-4.jpg","https://img.castlecore.uk/castell-y-bere-ruins-5.jpg","https://img.castlecore.uk/castell-y-bere-keep-2.jpg","https://img.castlecore.uk/castell-y-bere-keep-3.jpg","https://img.castlecore.uk/castell-y-bere-keep-4.jpg","https://img.castlecore.uk/castell-y-bere-keep-5.jpg"]},{"name":"Ewloe Castle","lat":53.1817,"lng":-3.0742,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A Welsh-built castle hidden in woodland, Ewloe was constructed by Llywelyn ap Gruffudd. Its D-shaped Welsh tower is one of the best-preserved examples of native Welsh castle architecture.","history":"Ewloe Castle is a native Welsh castle built by the Kingdom of Gwynedd near the village of Ewloe in Flintshire, Wales. The castle, which was one of the last fortifications to be built by the native Princes of Wales, was abandoned at the beginning of the invasion of Wales by Edward I in 1277. Using locally quarried sandstone, its construction appears to have continued piecemeal over many years and may have not been completed. On taking the castle, the English Crown gave it little military value and allowed it to fall into ruin.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Powis_Castle_2016_116_%28cropped%29.jpg/500px-Powis_Castle_2016_116_%28cropped%29.jpg","rating":3.8,"reviewCount":670,"county":"Flintshire","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":225,"gallery":["https://img.castlecore.uk/ewloe-castle-2.jpg","https://img.castlecore.uk/ewloe-castle-3.jpg","https://img.castlecore.uk/ewloe-castle-4.jpg","https://img.castlecore.uk/ewloe-castle-5.jpg","https://img.castlecore.uk/ewloe-castle-ruins-2.jpg","https://img.castlecore.uk/ewloe-castle-ruins-3.jpg","https://img.castlecore.uk/ewloe-castle-ruins-4.jpg","https://img.castlecore.uk/ewloe-castle-ruins-5.jpg","https://img.castlecore.uk/ewloe-castle-main-2.jpg","https://img.castlecore.uk/ewloe-castle-main-3.jpg","https://img.castlecore.uk/ewloe-castle-main-4.jpg","https://img.castlecore.uk/ewloe-castle-main-5.jpg"]},{"name":"Chirk Castle","lat":52.9369,"lng":-3.1007,"country":"Wales","type":"castle","era":"13th century","condition":"intact","description":"The last of the Edwardian castles still inhabited, Chirk has been continuously occupied for 700 years. Its interiors span from medieval dungeon to elegant 18th-century state rooms.","history":"Chirk Castle is a Grade I listed castle located in Chirk, Wrexham County Borough, Wales, 1.5 mi (2.4 km) from Chirk railway station, now owned and run by the National Trust.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/f/fa/Castle_and_Path.JPG/500px-Castle_and_Path.JPG","rating":4.3,"reviewCount":2800,"county":"Wrexham","tags":["well-preserved","kid-friendly","photogenic","hidden-gem"],"access":"paid","_index":226,"gallery":["https://img.castlecore.uk/chirk-castle-2.jpg","https://img.castlecore.uk/chirk-castle-3.jpg","https://img.castlecore.uk/chirk-castle-4.jpg","https://img.castlecore.uk/chirk-castle-5.jpg","https://img.castlecore.uk/chirk-castle-interior-2.jpg","https://img.castlecore.uk/chirk-castle-interior-3.jpg","https://img.castlecore.uk/chirk-castle-interior-4.jpg","https://img.castlecore.uk/chirk-castle-interior-5.jpg"]},{"name":"Powis Castle","lat":52.661,"lng":-3.1669,"country":"Wales","type":"castle","era":"13th century","condition":"intact","description":"A medieval castle transformed into a grand country mansion, Powis is famous for its spectacular Italianate terraced gardens. It houses the Clive Museum of Indian treasures.","history":"Powis Castle is a medieval castle, fortress and grand country house near Welshpool, in Powys, Wales. The seat of the Herbert family, earls of Powis, the castle is known for its formal gardens and for its interiors, the former having been described as \"the most important\", and the latter \"the most magnificent\", in the country. The castle and gardens are under the care of the National Trust. Powis Castle is a Grade I listed building, while its gardens have their own Grade I listing on the Cadw/ICOMOS Register of Parks and Gardens of Special Historic Interest in Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8c/Bronllys_Castle_-_geograph.org.uk_-_1921221.jpg/500px-Bronllys_Castle_-_geograph.org.uk_-_1921221.jpg","rating":4.5,"reviewCount":4800,"county":"Powys","tags":["well-preserved","photogenic","kid-friendly"],"access":"paid","_index":227,"gallery":["https://img.castlecore.uk/powis-castle-2.jpg","https://img.castlecore.uk/powis-castle-3.jpg","https://img.castlecore.uk/powis-castle-4.jpg","https://img.castlecore.uk/powis-castle-5.jpg","https://img.castlecore.uk/powis-castle-interior-2.jpg","https://img.castlecore.uk/powis-castle-interior-3.jpg","https://img.castlecore.uk/powis-castle-interior-4.jpg","https://img.castlecore.uk/powis-castle-interior-5.jpg"]},{"name":"Montgomery Castle","lat":52.5621,"lng":-3.1504,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A castle built by Henry III to control the Welsh Marches, Montgomery's twin-towered gatehouse overlooks the border town. Its rocky hilltop site has views into both England and Wales.","history":"Montgomery Castle is a stone castle looking over the town of Montgomery in Powys, Mid Wales. It is one of many Norman castles on the border between Wales and England.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/DSCN4297-strata-florida-arch.JPG/500px-DSCN4297-strata-florida-arch.JPG","rating":3.9,"reviewCount":890,"county":"Powys","tags":["dramatic-ruin","hidden-gem","free"],"access":"free","_index":228,"gallery":["https://img.castlecore.uk/montgomery-castle-2.jpg","https://img.castlecore.uk/montgomery-castle-3.jpg","https://img.castlecore.uk/montgomery-castle-4.jpg","https://img.castlecore.uk/montgomery-castle-5.jpg","https://img.castlecore.uk/montgomery-castle-ruins-2.jpg","https://img.castlecore.uk/montgomery-castle-ruins-3.jpg","https://img.castlecore.uk/montgomery-castle-ruins-4.jpg","https://img.castlecore.uk/montgomery-castle-ruins-5.jpg","https://img.castlecore.uk/montgomery-castle-keep-2.jpg","https://img.castlecore.uk/montgomery-castle-keep-3.jpg","https://img.castlecore.uk/montgomery-castle-keep-4.jpg","https://img.castlecore.uk/montgomery-castle-keep-5.jpg"]},{"name":"Bronllys Castle","lat":51.9565,"lng":-3.2447,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A small Norman castle with a well-preserved round tower on a motte. It was an outpost of the de Braose Marcher lordship and offers views across the Llynfi Valley.","history":"Bronllys Castle is a motte and bailey fortress standing south of Bronllys, towards Talgarth in Powys, Wales. The original castle, constructed of wood, was founded in or soon after 1100 by Richard Fitz Pons, the owner of the nearby Herefordshire barony of Clifford, who was a supporter of Bernard of Neufmarché.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/51/Mynydd_Felfed_%28Coed_Hyrddyn%29_-_Velvet_Hill%2C_Llantysilio%2C_Llangollen%2C_Sir_Ddinbych%2C_Cymru_%28Wales%29_70.jpg/500px-Mynydd_Felfed_%28Coed_Hyrddyn%29_-_Velvet_Hill%2C_Llantysilio%2C_Llangollen%2C_Sir_Ddinbych%2C_Cymru_%28Wales%29_70.jpg","rating":3.6,"reviewCount":340,"county":"Powys","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":230,"gallery":["https://img.castlecore.uk/bronllys-castle-2.jpg","https://img.castlecore.uk/bronllys-castle-3.jpg","https://img.castlecore.uk/bronllys-castle-4.jpg","https://img.castlecore.uk/bronllys-castle-5.jpg","https://img.castlecore.uk/bronllys-castle-keep-2.jpg","https://img.castlecore.uk/bronllys-castle-keep-3.jpg","https://img.castlecore.uk/bronllys-castle-keep-4.jpg","https://img.castlecore.uk/bronllys-castle-keep-5.jpg","https://img.castlecore.uk/bronllys-castle-main-2.jpg","https://img.castlecore.uk/bronllys-castle-main-3.jpg","https://img.castlecore.uk/bronllys-castle-main-4.jpg","https://img.castlecore.uk/bronllys-castle-main-5.jpg"]},{"name":"Strata Florida Abbey","lat":52.2891,"lng":-3.828,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"The spiritual centre of medieval Wales, Strata Florida was where Dafydd ap Gwilym, Wales' greatest poet, is said to be buried. Only the magnificent Romanesque west doorway survives intact.","history":"Strata Florida Abbey is a former Cistercian abbey situated just outside Pontrhydfendigaid, near Tregaron in the county of Ceredigion, Wales. The abbey was founded in 1164. After the region around St Davids was firmly occupied by the Norman Marcher lordship of Pembroke by the early 12th century, with St Davids firmly under Norman influence thereafter, the princely Dinefwr family of Deheubarth transferred their patronage to Strata Florida, and interred many of their family members there.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a6/Aerial_View_of_Basingwerk_Abbey%2C.jpg/500px-Aerial_View_of_Basingwerk_Abbey%2C.jpg","rating":4.1,"reviewCount":1120,"county":"Ceredigion","tags":["romantic-ruin","hidden-gem"],"access":"paid","_index":231,"gallery":["https://img.castlecore.uk/strata-florida-abbey-2.jpg","https://img.castlecore.uk/strata-florida-abbey-3.jpg","https://img.castlecore.uk/strata-florida-abbey-4.jpg","https://img.castlecore.uk/strata-florida-abbey-5.jpg","https://img.castlecore.uk/strata-florida-abbey-ruins-2.jpg","https://img.castlecore.uk/strata-florida-abbey-ruins-3.jpg","https://img.castlecore.uk/strata-florida-abbey-ruins-4.jpg","https://img.castlecore.uk/strata-florida-abbey-ruins-5.jpg","https://img.castlecore.uk/strata-florida-abbey-main-2.jpg","https://img.castlecore.uk/strata-florida-abbey-main-3.jpg","https://img.castlecore.uk/strata-florida-abbey-main-4.jpg","https://img.castlecore.uk/strata-florida-abbey-main-5.jpg"]},{"name":"Talley Abbey","lat":51.9581,"lng":-3.9189,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"The only Premonstratensian monastery in Wales, Talley's twin towers stand beside a peaceful lake. It was founded by Rhys ap Gruffydd, prince of Deheubarth.","history":"Talley Abbey is a ruined former monastery of the Premonstratensians in the village of Talley in Carmarthenshire, Wales, six miles (10 km) north of the market town of Llandeilo. It lies in the River Cothi valley. Access to the site of the abbey is free, and the site is maintained by Cadw.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/77/The_Ruins_of_Cymer_Abbey_-_geograph.org.uk_-_3795241.jpg/500px-The_Ruins_of_Cymer_Abbey_-_geograph.org.uk_-_3795241.jpg","rating":3.9,"reviewCount":670,"county":"Carmarthenshire","tags":["romantic-ruin","hidden-gem","free","photogenic"],"access":"free","_index":232,"gallery":["https://img.castlecore.uk/talley-abbey-2.jpg","https://img.castlecore.uk/talley-abbey-3.jpg","https://img.castlecore.uk/talley-abbey-4.jpg","https://img.castlecore.uk/talley-abbey-5.jpg","https://img.castlecore.uk/talley-abbey-ruins-2.jpg","https://img.castlecore.uk/talley-abbey-ruins-3.jpg","https://img.castlecore.uk/talley-abbey-ruins-4.jpg","https://img.castlecore.uk/talley-abbey-ruins-5.jpg","https://img.castlecore.uk/talley-abbey-main-2.jpg","https://img.castlecore.uk/talley-abbey-main-3.jpg","https://img.castlecore.uk/talley-abbey-main-4.jpg","https://img.castlecore.uk/talley-abbey-main-5.jpg"]},{"name":"Valle Crucis Abbey","lat":52.9838,"lng":-3.1767,"country":"Wales","type":"abbey","era":"13th century","condition":"ruin","description":"The best-preserved medieval Cistercian abbey in Wales, Valle Crucis was founded in 1201 by Madog ap Gruffydd Maelor. The fish pond and chapter house are particularly fine.","history":"Valle Crucis Abbey is a Cistercian abbey located in Llantysilio in Denbighshire, north Wales. More formally the Abbey Church of the Blessed Virgin Mary, Valle Crucis it is known in Welsh both as Abaty Glyn Egwestl and Abaty Glyn y Groes. The abbey was built in 1201 by Madog ap Gruffydd Maelor, Prince of Powys Fadog. Valle Crucis was dissolved in 1537 during the dissolution of the monasteries, and subsequently fell into serious disrepair. The building is now a ruin, though large parts of the original structure still survive. Valle Crucis Abbey is now under the care of Cadw. The abbey received 5,690 visitors in 2018.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4b/Manorbier_Castle.jpg/500px-Manorbier_Castle.jpg","rating":4.5,"reviewCount":2400,"county":"Denbighshire","tags":["romantic-ruin","photogenic","hidden-gem"],"access":"paid","_index":233,"gallery":["https://img.castlecore.uk/valle-crucis-abbey-2.jpg","https://img.castlecore.uk/valle-crucis-abbey-3.jpg","https://img.castlecore.uk/valle-crucis-abbey-4.jpg","https://img.castlecore.uk/valle-crucis-abbey-5.jpg","https://img.castlecore.uk/valle-crucis-abbey-ruins-2.jpg","https://img.castlecore.uk/valle-crucis-abbey-ruins-3.jpg","https://img.castlecore.uk/valle-crucis-abbey-ruins-4.jpg","https://img.castlecore.uk/valle-crucis-abbey-ruins-5.jpg","https://img.castlecore.uk/valle-crucis-abbey-interior-2.jpg","https://img.castlecore.uk/valle-crucis-abbey-interior-3.jpg","https://img.castlecore.uk/valle-crucis-abbey-interior-4.jpg","https://img.castlecore.uk/valle-crucis-abbey-interior-5.jpg","https://img.castlecore.uk/valle-crucis-abbey-main-2.jpg","https://img.castlecore.uk/valle-crucis-abbey-main-3.jpg","https://img.castlecore.uk/valle-crucis-abbey-main-4.jpg","https://img.castlecore.uk/valle-crucis-abbey-main-5.jpg"]},{"name":"Basingwerk Abbey","lat":53.2723,"lng":-3.2209,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"A Cistercian abbey in the Greenfield Valley, Basingwerk was dissolved in 1536. The refectory and chapter house walls survive, and the valley's industrial heritage is nearby.","history":"Basingwerk Abbey is a Grade I listed ruined abbey near Holywell, Flintshire, Wales. The abbey, which was founded in the 12th century, belonged to the Order of Cistercians. It maintained significant lands in the English county of Derbyshire. The abbey was abandoned and its assets sold following the Dissolution of the Monasteries in 1536.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/17/Carew_Castle%2C_Pembrokeshire%2C_UK.jpg/500px-Carew_Castle%2C_Pembrokeshire%2C_UK.jpg","rating":4.1,"reviewCount":800,"county":"Flintshire","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":234,"gallery":["https://img.castlecore.uk/basingwerk-abbey-2.jpg","https://img.castlecore.uk/basingwerk-abbey-3.jpg","https://img.castlecore.uk/basingwerk-abbey-4.jpg","https://img.castlecore.uk/basingwerk-abbey-5.jpg","https://img.castlecore.uk/basingwerk-abbey-ruins-2.jpg","https://img.castlecore.uk/basingwerk-abbey-ruins-3.jpg","https://img.castlecore.uk/basingwerk-abbey-ruins-4.jpg","https://img.castlecore.uk/basingwerk-abbey-ruins-5.jpg","https://img.castlecore.uk/basingwerk-abbey-main-2.jpg","https://img.castlecore.uk/basingwerk-abbey-main-3.jpg","https://img.castlecore.uk/basingwerk-abbey-main-4.jpg","https://img.castlecore.uk/basingwerk-abbey-main-5.jpg"]},{"name":"Cymer Abbey","lat":52.7766,"lng":-3.9265,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"A small Cistercian abbey in the Mawddach valley near Dolgellau. Never wealthy, its modest ruins are set against the dramatic backdrop of the Rhinogydd mountains.","history":"Cymer Abbey is a ruined Cistercian abbey near the village of Llanelltyd, just north of Dolgellau, Gwynedd, in north-west Wales, United Kingdom.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/88/01_Cilgerran_Castle.jpg/500px-01_Cilgerran_Castle.jpg","rating":4,"reviewCount":550,"county":"Gwynedd","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":235,"gallery":["https://img.castlecore.uk/cymer-abbey-2.jpg","https://img.castlecore.uk/cymer-abbey-3.jpg","https://img.castlecore.uk/cymer-abbey-4.jpg","https://img.castlecore.uk/cymer-abbey-5.jpg","https://img.castlecore.uk/cymer-abbey-ruins-2.jpg","https://img.castlecore.uk/cymer-abbey-ruins-3.jpg","https://img.castlecore.uk/cymer-abbey-ruins-4.jpg","https://img.castlecore.uk/cymer-abbey-ruins-5.jpg"]},{"name":"Manorbier Castle","lat":51.644,"lng":-4.7967,"country":"Wales","type":"castle","era":"12th century","condition":"partial ruin","description":"Gerald of Wales called it 'the pleasantest spot in Wales'. This well-preserved Norman castle overlooks a sandy beach in Pembrokeshire and still belongs to a private family.","history":"Manorbier Castle is a Norman castle in Manorbier, 5 miles (8.0 km) southwest of Tenby, Wales. It was founded in the late 11th century by the Anglo-Norman de Barry family. The castle was part of a mesne lordship under the control of the medieval Earls of Pembroke.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/eb/Llawhaden_Castle_from_Drim_Wood_-_geograph.org.uk_-_915795.jpg/500px-Llawhaden_Castle_from_Drim_Wood_-_geograph.org.uk_-_915795.jpg","rating":4.3,"reviewCount":1890,"county":"Pembrokeshire","tags":["dramatic-ruin","photogenic","hidden-gem"],"access":"paid","_index":236,"gallery":["https://img.castlecore.uk/manorbier-castle-2.jpg","https://img.castlecore.uk/manorbier-castle-3.jpg","https://img.castlecore.uk/manorbier-castle-4.jpg","https://img.castlecore.uk/manorbier-castle-5.jpg","https://img.castlecore.uk/manorbier-castle-interior-2.jpg","https://img.castlecore.uk/manorbier-castle-interior-3.jpg","https://img.castlecore.uk/manorbier-castle-interior-4.jpg","https://img.castlecore.uk/manorbier-castle-interior-5.jpg"]},{"name":"Carew Castle","lat":51.6899,"lng":-4.8434,"country":"Wales","type":"castle","era":"12th century","condition":"partial ruin","description":"A Norman castle converted into an Elizabethan mansion, Carew overlooks a tidal millpond with a Celtic cross. The Great Tournament of 1507, lasting five days, was held here.","history":"Carew Castle is a castle in the civil parish of Carew in Pembrokeshire, Wales. The Carew family take their name from this site and have owned the castle for more than 900 years. It is leased to the Pembrokeshire Coast National Park for administration purposes.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/a/a5/Dinefwr_castle_at_sunrise.jpg/500px-Dinefwr_castle_at_sunrise.jpg","rating":4.2,"reviewCount":1670,"county":"Pembrokeshire","tags":["dramatic-ruin","photogenic","hidden-gem"],"access":"paid","_index":237,"gallery":["https://img.castlecore.uk/carew-castle-2.jpg","https://img.castlecore.uk/carew-castle-3.jpg","https://img.castlecore.uk/carew-castle-4.jpg","https://img.castlecore.uk/carew-castle-5.jpg","https://img.castlecore.uk/carew-castle-interior-2.jpg","https://img.castlecore.uk/carew-castle-interior-3.jpg","https://img.castlecore.uk/carew-castle-interior-4.jpg","https://img.castlecore.uk/carew-castle-interior-5.jpg"]},{"name":"Cilgerran Castle","lat":52.0838,"lng":-4.6846,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"Two massive round towers guard the promontory above the Teifi gorge, painted by Turner and Richard Wilson. The castle was a key stronghold during the Welsh wars of independence.","history":"Cilgerran Castle is a 13th-century ruined castle located in Cilgerran, Pembrokeshire, Wales, near Cardigan. The first castle on the site was thought to have been built by Gerald of Windsor around 1110–1115, and it changed hands several times over the following century between English and Welsh forces. In the hands of William Marshal, 2nd Earl of Pembroke, the construction of the stone castle began after 1223.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/46/Ogmore_Castle_5085.jpg/500px-Ogmore_Castle_5085.jpg","rating":4.1,"reviewCount":1340,"county":"Pembrokeshire","tags":["dramatic-ruin","photogenic","hidden-gem"],"access":"paid","_index":238,"gallery":["https://img.castlecore.uk/cilgerran-castle-2.jpg","https://img.castlecore.uk/cilgerran-castle-3.jpg","https://img.castlecore.uk/cilgerran-castle-4.jpg","https://img.castlecore.uk/cilgerran-castle-5.jpg","https://img.castlecore.uk/cilgerran-castle-interior-2.jpg","https://img.castlecore.uk/cilgerran-castle-interior-3.jpg","https://img.castlecore.uk/cilgerran-castle-interior-4.jpg","https://img.castlecore.uk/cilgerran-castle-interior-5.jpg","https://img.castlecore.uk/cilgerran-castle-main-2.jpg","https://img.castlecore.uk/cilgerran-castle-main-3.jpg","https://img.castlecore.uk/cilgerran-castle-main-4.jpg","https://img.castlecore.uk/cilgerran-castle-main-5.jpg"]},{"name":"Llawhaden Castle","lat":51.8355,"lng":-4.7995,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A fortified palace of the medieval bishops of St David's, Llawhaden was one of the grandest residences in Wales. Its gatehouse and great hall range survive amid farmland.","history":"Llawhaden Castle is a ruined castle in Llawhaden, Pembrokeshire, Wales, 10 miles (16 km) east of Haverfordwest. A motte-and-bailey castle is thought to have previously occupied the site and the present structure was built by the bishops of the Diocese of St David in the 13th century. The castle was abandoned in the 16th century and some of the stone was removed for local building projects. The site is privately owned by the Lord of the Manor of Llawhaden and managed by Cadw.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/84/Coity_Castle.jpg/500px-Coity_Castle.jpg","rating":3.8,"reviewCount":560,"county":"Pembrokeshire","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":239,"gallery":["https://img.castlecore.uk/llawhaden-castle-2.jpg","https://img.castlecore.uk/llawhaden-castle-3.jpg","https://img.castlecore.uk/llawhaden-castle-4.jpg","https://img.castlecore.uk/llawhaden-castle-5.jpg","https://img.castlecore.uk/llawhaden-castle-ruins-2.jpg","https://img.castlecore.uk/llawhaden-castle-ruins-3.jpg","https://img.castlecore.uk/llawhaden-castle-ruins-4.jpg","https://img.castlecore.uk/llawhaden-castle-ruins-5.jpg","https://img.castlecore.uk/llawhaden-castle-keep-2.jpg","https://img.castlecore.uk/llawhaden-castle-keep-3.jpg","https://img.castlecore.uk/llawhaden-castle-keep-4.jpg","https://img.castlecore.uk/llawhaden-castle-keep-5.jpg"]},{"name":"Ogmore Castle","lat":51.4732,"lng":-3.5933,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A Norman castle beside a stepping-stone river crossing, Ogmore was one of the first stone castles in Glamorgan. Its keep and curtain wall survive above the River Ogmore.","history":"Ogmore Castle is a Grade I listed castle ruin located near the village of Ogmore in the Vale of Glamorgan, Wales, east of Ogmore-by-Sea, and south of the town of Bridgend. It is situated on the south bank of the Ewenny River and the east bank of the River Ogmore.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Castell_Rhuthun_-_adfeilion_y_goresgynwyr_%28wel_o_lia_fe_drion_nhw%29_27.JPG/500px-Castell_Rhuthun_-_adfeilion_y_goresgynwyr_%28wel_o_lia_fe_drion_nhw%29_27.JPG","rating":4.2,"reviewCount":1200,"county":"Vale of Glamorgan","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":242,"gallery":["https://img.castlecore.uk/ogmore-castle-2.jpg","https://img.castlecore.uk/ogmore-castle-3.jpg","https://img.castlecore.uk/ogmore-castle-4.jpg","https://img.castlecore.uk/ogmore-castle-5.jpg","https://img.castlecore.uk/ogmore-castle-ruins-2.jpg","https://img.castlecore.uk/ogmore-castle-ruins-3.jpg","https://img.castlecore.uk/ogmore-castle-ruins-4.jpg","https://img.castlecore.uk/ogmore-castle-ruins-5.jpg","https://img.castlecore.uk/ogmore-castle-keep-2.jpg","https://img.castlecore.uk/ogmore-castle-keep-3.jpg","https://img.castlecore.uk/ogmore-castle-keep-4.jpg","https://img.castlecore.uk/ogmore-castle-keep-5.jpg"]},{"name":"Coity Castle","lat":51.5259,"lng":-3.5491,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A Norman castle expanded over several centuries, Coity features a 14th-century round chapel tower. Legend says Payn de Turberville won the castle by marrying the Welsh lord's daughter.","history":"Coity Castle in Glamorgan, Wales, is a Norman castle built by Sir Payn \"the Demon\" de Turberville, one of the legendary Twelve Knights of Glamorgan supposed to have conquered Glamorgan under the leadership of Robert FitzHamon, Lord of Gloucester. Now in ruins, it stands in the community of Coity Higher near the town of Bridgend, in the County Borough of Bridgend. Very close to the castle is the battlemented parish Church of St Mary the Virgin, which dates from the 14th century.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/9b/Lismore_Castle_%28Lismore%2C_Co._Waterford%29.jpg/500px-Lismore_Castle_%28Lismore%2C_Co._Waterford%29.jpg","rating":4.1,"reviewCount":600,"county":"Bridgend","tags":["romantic-ruin","hidden-gem","free"],"access":"free","_index":243,"gallery":["https://img.castlecore.uk/coity-castle-2.jpg","https://img.castlecore.uk/coity-castle-3.jpg","https://img.castlecore.uk/coity-castle-4.jpg","https://img.castlecore.uk/coity-castle-5.jpg","https://img.castlecore.uk/coity-castle-ruins-2.jpg","https://img.castlecore.uk/coity-castle-ruins-3.jpg","https://img.castlecore.uk/coity-castle-ruins-4.jpg","https://img.castlecore.uk/coity-castle-ruins-5.jpg","https://img.castlecore.uk/coity-castle-keep-2.jpg","https://img.castlecore.uk/coity-castle-keep-3.jpg","https://img.castlecore.uk/coity-castle-keep-4.jpg","https://img.castlecore.uk/coity-castle-keep-5.jpg"]},{"name":"Weobley Castle","lat":51.5926,"lng":-4.166,"country":"Wales","type":"fortified house","era":"14th century","condition":"ruin","description":"A medieval fortified manor perched on the edge of the Gower marshes, where you can almost hear the wind whispering through 700-year-old stone.","history":"A 14th-century fortified manor house on the north Gower coast overlooking the Llanrhidian marshes. Built by the de la Bere family. Features a great hall, solar, and chapel arranged around a courtyard. Managed by Cadw. One of the best-preserved medieval manor houses in Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Roscrea_Castle.jpg/500px-Roscrea_Castle.jpg","rating":4,"reviewCount":780,"county":"Swansea","tags":["romantic-ruin","hidden-gem","coastal","medieval"],"access":"paid","_index":244,"gallery":["https://img.castlecore.uk/weobley-castle-2.jpg","https://img.castlecore.uk/weobley-castle-3.jpg","https://img.castlecore.uk/weobley-castle-4.jpg","https://img.castlecore.uk/weobley-castle-5.jpg","https://img.castlecore.uk/weobley-castle-interior-2.jpg","https://img.castlecore.uk/weobley-castle-interior-3.jpg","https://img.castlecore.uk/weobley-castle-interior-4.jpg","https://img.castlecore.uk/weobley-castle-interior-5.jpg","https://img.castlecore.uk/weobley-castle-main-2.jpg","https://img.castlecore.uk/weobley-castle-main-3.jpg","https://img.castlecore.uk/weobley-castle-main-4.jpg","https://img.castlecore.uk/weobley-castle-main-5.jpg"],"youtube":["b8TqZkDjkVw","vrpu1ghAIT4","5gGXtDEk0wU"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Weobley_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/weobley-castle"}]},{"name":"Pennard Castle","lat":51.566,"lng":-4.0784,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A Norman castle dramatically engulfed by sand dunes above Three Cliffs Bay on the Gower. The shifting sands have both preserved and concealed its walls over centuries.","history":"Pennard Castle is a ruined castle, near the modern village of Pennard on the Gower Peninsula, in south Wales. The castle was built in the early 12th century as a timber ringwork following the Norman invasion of Wales. The walls were rebuilt in stone by the Braose family at the turn of the 13th and 14th centuries, including a stone gatehouse. Soon afterwards, however, encroaching sand dunes caused the site to be abandoned and it fell into ruin. Restoration work was carried out during the course of the 20th century and the remains of the castle are now protected under UK law as a Grade II* listed building.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/72/Centre_of_Nenagh_-_panoramio.jpg/500px-Centre_of_Nenagh_-_panoramio.jpg","rating":4.1,"reviewCount":1230,"county":"Swansea","tags":["dramatic-ruin","photogenic","hidden-gem","free"],"access":"free","_index":245,"gallery":["https://img.castlecore.uk/pennard-castle-2.jpg","https://img.castlecore.uk/pennard-castle-3.jpg","https://img.castlecore.uk/pennard-castle-4.jpg","https://img.castlecore.uk/pennard-castle-5.jpg","https://img.castlecore.uk/pennard-castle-main-2.jpg","https://img.castlecore.uk/pennard-castle-main-3.jpg","https://img.castlecore.uk/pennard-castle-main-4.jpg","https://img.castlecore.uk/pennard-castle-main-5.jpg"]},{"name":"Ruthin Castle","lat":53.1147,"lng":-3.3124,"country":"Wales","type":"castle","era":"13th century","condition":"partial ruin","description":"Built by Dafydd ap Gruffydd's rival Edward I, Ruthin saw Owain Glyndŵr's revolt begin with an attack here in 1400. Now partly a hotel with medieval ruins in the grounds.","history":"Ruthin Castle is a medieval castle fortification in Wales, near the town of Ruthin in the Vale of Clwyd. It was constructed during the late 13th century by Dafydd ap Gruffydd, the brother of Prince Llywelyn ap Gruffudd, on a red sandstone ridge overlooking the valley. Part of the ancient walls still remain and now form part of the Ruthin Castle Hotel.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/0/02/Portumna_castle.jpg/500px-Portumna_castle.jpg","rating":4,"reviewCount":1340,"county":"Denbighshire","tags":["dramatic-ruin","hidden-gem","haunted"],"access":"paid","_index":247,"gallery":["https://img.castlecore.uk/ruthin-castle-2.jpg","https://img.castlecore.uk/ruthin-castle-3.jpg","https://img.castlecore.uk/ruthin-castle-4.jpg","https://img.castlecore.uk/ruthin-castle-5.jpg","https://img.castlecore.uk/ruthin-castle-main-2.jpg","https://img.castlecore.uk/ruthin-castle-main-3.jpg","https://img.castlecore.uk/ruthin-castle-main-4.jpg","https://img.castlecore.uk/ruthin-castle-main-5.jpg"]},{"name":"Caldicot Castle","lat":51.5833,"lng":-2.7167,"country":"Wales","type":"castle","era":"12th-14th century","condition":"intact","description":"A brooding Norman fortress with roots in Saxon legend, where royal intrigue played out behind thick stone walls in the Welsh Marches.","history":"Built c.1100 by Norman earls of Hereford near Harold Godwinson's Saxon castle site. Owned by Thomas of Woodstock, son of Edward III, until 1391. Features a 14th-century gatehouse and round tower. Grade I listed since 1953. Now a country park and museum.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/62/Caldicot_Castle_entrance_-_geograph.org.uk_-_469475.jpg/500px-Caldicot_Castle_entrance_-_geograph.org.uk_-_469475.jpg","rating":4.2,"reviewCount":1500,"county":"Monmouthshire","tags":["well-preserved","kid-friendly","medieval","norman","gardens"],"access":"paid","_index":503,"gallery":["https://img.castlecore.uk/caldicot-castle-2.jpg","https://img.castlecore.uk/caldicot-castle-3.jpg","https://img.castlecore.uk/caldicot-castle-4.jpg","https://img.castlecore.uk/caldicot-castle-5.jpg","https://img.castlecore.uk/caldicot-castle-interior-2.jpg","https://img.castlecore.uk/caldicot-castle-interior-3.jpg","https://img.castlecore.uk/caldicot-castle-interior-4.jpg","https://img.castlecore.uk/caldicot-castle-interior-5.jpg","https://img.castlecore.uk/caldicot-castle-keep-2.jpg","https://img.castlecore.uk/caldicot-castle-keep-3.jpg","https://img.castlecore.uk/caldicot-castle-keep-4.jpg","https://img.castlecore.uk/caldicot-castle-keep-5.jpg","https://img.castlecore.uk/caldicot-castle-main-2.jpg","https://img.castlecore.uk/caldicot-castle-main-3.jpg","https://img.castlecore.uk/caldicot-castle-main-4.jpg","https://img.castlecore.uk/caldicot-castle-main-5.jpg"],"youtube":["5y9On-ebFZA","PhPubudZ4SA","w6vz9riclHk"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Caldicot_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/caldicot-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95259/"}]},{"name":"Usk Castle","lat":51.7,"lng":-2.9,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A secret garden hidden inside a medieval fortress — where roses climb ancient walls and the Battle of Usk echoes through the ruins.","history":"Built in 1120 in the town of Usk, Monmouthshire. Site of the Battle of Usk during the Owain Glyndŵr uprising. Grade I listed since 1953. Castle House, incorporating parts of the gatehouse, stands within the castle walls. Famous for its award-winning castle gardens, privately owned.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/11/Garrison_Tower_and_sundial%2C_Usk_Castle_-_geograph.org.uk_-_1425960.jpg/500px-Garrison_Tower_and_sundial%2C_Usk_Castle_-_geograph.org.uk_-_1425960.jpg","rating":3.9,"reviewCount":380,"county":"Monmouthshire","tags":["romantic-ruin","hidden-gem","gardens","medieval"],"access":"paid","_index":504,"gallery":["https://img.castlecore.uk/usk-castle-2.jpg","https://img.castlecore.uk/usk-castle-3.jpg","https://img.castlecore.uk/usk-castle-4.jpg","https://img.castlecore.uk/usk-castle-5.jpg","https://img.castlecore.uk/usk-castle-keep-2.jpg","https://img.castlecore.uk/usk-castle-keep-3.jpg","https://img.castlecore.uk/usk-castle-keep-4.jpg","https://img.castlecore.uk/usk-castle-keep-5.jpg","https://img.castlecore.uk/usk-castle-main-2.jpg","https://img.castlecore.uk/usk-castle-main-3.jpg","https://img.castlecore.uk/usk-castle-main-4.jpg","https://img.castlecore.uk/usk-castle-main-5.jpg"],"youtube":["SJDv0NpGzYo","4vxbE-owyc0","KTBx-M64Ekc"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Usk_Castle"},{"name":"Usk Castle Official","url":"https://www.uskcastle.com/"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/usk-castle"}]},{"name":"Abergavenny Castle","lat":51.8167,"lng":-3.0167,"country":"Wales","type":"castle","era":"11th century","condition":"ruin","description":"A castle stained with more treachery than any other in Wales — where Norman lords massacred Welsh noblemen at a feast, and Owain Glyndwr's rebels burned the walls in righteous fury.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e3/Ruins_of_Abergavenny_Castle.jpg/500px-Ruins_of_Abergavenny_Castle.jpg","rating":3.7,"reviewCount":680,"county":"Monmouthshire","tags":["ruins-romantic","norman","atmospheric","museum","riverside","free-entry"],"access":"free","_index":505,"gallery":["https://img.castlecore.uk/abergavenny-castle-2.jpg","https://img.castlecore.uk/abergavenny-castle-3.jpg","https://img.castlecore.uk/abergavenny-castle-4.jpg","https://img.castlecore.uk/abergavenny-castle-5.jpg","https://img.castlecore.uk/abergavenny-castle-main-2.jpg","https://img.castlecore.uk/abergavenny-castle-main-3.jpg","https://img.castlecore.uk/abergavenny-castle-main-4.jpg","https://img.castlecore.uk/abergavenny-castle-main-5.jpg"],"history":"Established c.1087 by Norman lord Hamelin de Balun to overlook the River Usk. Site of an infamous massacre of Welsh noblemen in 1175. Attacked during the Glyndwr Rising in 1404. The antiquary William Camden called it the castle 'oftner stain'd with the infamy of treachery than any other in Wales.' Grade I listed since 1952. Houses a local museum.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Abergavenny_Castle"}]},{"name":"Picton Castle","lat":51.7833,"lng":-4.8667,"country":"Wales","type":"castle","era":"13th century","condition":"intact","description":"A 13th-century Pembrokeshire castle wrapped in beautiful gardens — built by a Flemish knight, still standing, still enchanting.","history":"Originally built at the end of the 13th century by a Flemish knight, later acquired by Sir John Wogan. Grade I listed castle with Grade II* gardens. Of unusual construction, remodelled several times. Now owned by Picton Castle Trust and open to the public. Features 40 acres of gardens.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/64/02_Picton_Castle_Pembrokeshire.JPG/500px-02_Picton_Castle_Pembrokeshire.JPG","rating":4.2,"reviewCount":1400,"county":"Pembrokeshire","tags":["well-preserved","photogenic","kid-friendly","gardens","medieval"],"access":"paid","_index":507,"gallery":["https://img.castlecore.uk/picton-castle-2.jpg","https://img.castlecore.uk/picton-castle-3.jpg","https://img.castlecore.uk/picton-castle-4.jpg","https://img.castlecore.uk/picton-castle-5.jpg","https://img.castlecore.uk/picton-castle-interior-2.jpg","https://img.castlecore.uk/picton-castle-interior-3.jpg","https://img.castlecore.uk/picton-castle-interior-4.jpg","https://img.castlecore.uk/picton-castle-interior-5.jpg"],"youtube":["-D3ZLFLeIP8","Owd4EfIZciY","IGBl_UctKy4"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Picton_Castle"},{"name":"Picton Castle Official","url":"https://www.pictoncastle.co.uk/"}]},{"name":"Hay Castle","lat":52.075,"lng":-3.125,"country":"Wales","type":"castle","era":"12th century","condition":"partial ruin","description":"A Norman fortress reborn in the world's most famous book town — centuries of fire, rebellion, and reinvention overlooking the Wye Valley.","history":"Built as a Norman ringwork in the late 11th or early 12th century during the invasion of Wales. Rebuilt in stone around 1200. A 17th-century mansion was built within the walls. Suffered fires in 1939 and 1977. Purchased by Hay Castle Trust and fully restored, reopening in 2022 as a cultural centre.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Hay_Castle%2C_Hay-on-Wye_-_geograph.org.uk_-_583851.jpg/500px-Hay_Castle%2C_Hay-on-Wye_-_geograph.org.uk_-_583851.jpg","rating":4,"reviewCount":650,"county":"Powys","tags":["hidden-gem","well-preserved","medieval","events-venue"],"access":"paid","_index":567,"gallery":["https://img.castlecore.uk/hay-castle-2.jpg","https://img.castlecore.uk/hay-castle-3.jpg","https://img.castlecore.uk/hay-castle-4.jpg","https://img.castlecore.uk/hay-castle-5.jpg","https://img.castlecore.uk/hay-castle-ruins-2.jpg","https://img.castlecore.uk/hay-castle-ruins-3.jpg","https://img.castlecore.uk/hay-castle-ruins-4.jpg","https://img.castlecore.uk/hay-castle-ruins-5.jpg","https://img.castlecore.uk/hay-castle-main-2.jpg","https://img.castlecore.uk/hay-castle-main-3.jpg","https://img.castlecore.uk/hay-castle-main-4.jpg","https://img.castlecore.uk/hay-castle-main-5.jpg"],"youtube":["7Hwkhih5MO8","zpU_kx5dSpc","o5oLDPb9r8I"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Hay_Castle"},{"name":"Hay Castle Official","url":"https://www.haycastle.org/"}]},{"name":"Builth Castle","lat":52.15,"lng":-3.4,"country":"Wales","type":"castle","era":"11th-13th century","condition":"ruin","description":"A grassy Norman motte above the River Wye, hauntingly close to where Llywelyn ap Gruffudd—the last native Prince of Wales—met his end in 1282.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/ba/Builth_Castle_-_geograph.org.uk_-_1025212.jpg/500px-Builth_Castle_-_geograph.org.uk_-_1025212.jpg","rating":3.3,"reviewCount":100,"county":"Powys","tags":["hilltop","free-entry","riverside","atmospheric"],"access":"free","_index":568,"gallery":["https://img.castlecore.uk/builth-castle-2.jpg","https://img.castlecore.uk/builth-castle-3.jpg","https://img.castlecore.uk/builth-castle-4.jpg","https://img.castlecore.uk/builth-castle-5.jpg"],"history":"Built by the Normans in the late 11th century, Builth Castle was repeatedly attacked and rebuilt during the Welsh wars. Edward I strengthened it in stone from 1277 as part of his campaign to subdue Wales. Near here in December 1282, Llywelyn ap Gruffudd, the last Prince of Wales, was killed at the Battle of Orewin Bridge. The castle fell into ruin by the 15th century; only earthworks survive.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk/en/site/93490"},{"name":"Castles of Wales","url":"https://www.castlesofwales.com/builth.html"}]},{"name":"Penmon Priory","lat":53.3167,"lng":-4.05,"country":"Wales","type":"abbey","era":"6th-13th century","condition":"partial ruin","description":"A serene Augustinian priory on the eastern tip of Anglesey, where a Celtic holy well, a Viking-age cross, and a Norman church stand within sight of Puffin Island.","image":"https://img.castlecore.uk/penmon-priory.jpg","rating":4.1,"reviewCount":780,"county":"Anglesey","tags":["atmospheric","coastal","celtic","medieval","free-entry","photogenic"],"access":"free","_index":569,"gallery":["https://img.castlecore.uk/penmon-priory-2.jpg","https://img.castlecore.uk/penmon-priory-3.jpg","https://img.castlecore.uk/penmon-priory-4.jpg","https://img.castlecore.uk/penmon-priory-5.jpg"],"history":"Founded as a Celtic monastery in the 6th century, possibly by St Seiriol. The site includes a 10th-century carved cross, a holy well, and a 12th-century Norman church with chevron-decorated arches. The Augustinian priory was established in the 13th century; its refectory and dovecote survive remarkably intact. Cadw manages the site, which offers views across the Menai Strait to Puffin Island.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/penmon-priory"},{"name":"Wikipedia – Penmon Priory","url":"https://en.wikipedia.org/wiki/Penmon_Priory"}]},{"name":"Dolforwyn Castle","lat":52.5333,"lng":-3.3,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"The last castle built by a native Welsh prince — a defiant hilltop ruin commanding sweeping views of the Severn Valley.","history":"Built 1273-1277 by Llywelyn ap Gruffudd, Prince of Gwynedd, to assert Welsh authority over the strategic Severn Valley. Captured by the English during the Welsh Wars. Now managed by Cadw with ongoing archaeological excavations revealing its Welsh design.","image":"https://img.castlecore.uk/dolforwyn-castle.jpg","rating":4.1,"reviewCount":500,"county":"Powys","tags":["dramatic-ruin","hidden-gem","free-entry","hilltop","medieval","remote"],"access":"free","_index":570,"gallery":["https://img.castlecore.uk/dolforwyn-castle-2.jpg","https://img.castlecore.uk/dolforwyn-castle-3.jpg","https://img.castlecore.uk/dolforwyn-castle-4.jpg","https://img.castlecore.uk/dolforwyn-castle-5.jpg","https://img.castlecore.uk/dolforwyn-castle-ruins-2.jpg","https://img.castlecore.uk/dolforwyn-castle-ruins-3.jpg","https://img.castlecore.uk/dolforwyn-castle-ruins-4.jpg","https://img.castlecore.uk/dolforwyn-castle-ruins-5.jpg","https://img.castlecore.uk/dolforwyn-castle-keep-2.jpg","https://img.castlecore.uk/dolforwyn-castle-keep-3.jpg","https://img.castlecore.uk/dolforwyn-castle-keep-4.jpg","https://img.castlecore.uk/dolforwyn-castle-keep-5.jpg","https://img.castlecore.uk/dolforwyn-castle-main-2.jpg","https://img.castlecore.uk/dolforwyn-castle-main-3.jpg","https://img.castlecore.uk/dolforwyn-castle-main-4.jpg","https://img.castlecore.uk/dolforwyn-castle-main-5.jpg"],"youtube":["46b991jpThU","ry30dJ-y4PU","-btYVvDJD78"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Dolforwyn_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/dolforwyn-castle"},{"name":"Castles of Wales","url":"https://www.castlesofwales.com/dolforwyn-castle/"}]},{"name":"Drysllwyn Castle","lat":51.8667,"lng":-4.05,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A dramatically sited Welsh fortress crowning a steep hill above the Tywi valley, its broken towers silhouetted against sweeping views of Carmarthenshire's patchwork fields.","image":"https://img.castlecore.uk/drysllwyn-castle.jpg","rating":3.9,"reviewCount":280,"county":"Carmarthenshire","tags":["hilltop","ruins-romantic","photogenic","free-entry","atmospheric"],"access":"free","_index":571,"gallery":["https://img.castlecore.uk/drysllwyn-castle-2.jpg","https://img.castlecore.uk/drysllwyn-castle-3.jpg","https://img.castlecore.uk/drysllwyn-castle-4.jpg","https://img.castlecore.uk/drysllwyn-castle-5.jpg"],"history":"A native Welsh castle built by the princes of Deheubarth in the 13th century. It was besieged by Edward I's forces in 1287; during the siege a mining tunnel collapsed, killing many attackers. The castle changed hands between Welsh and English several times before falling into ruin. The hilltop site offers commanding views of the Tywi valley, one of Wales's most beautiful river landscapes.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/dryslwyn-castle"},{"name":"Castles of Wales","url":"https://www.castlesofwales.com/dryslwyn.html"}]},{"name":"Newcastle Emlyn Castle","lat":52.0333,"lng":-4.4667,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"Atmospheric riverside ruins on a steep promontory above the Teifi — a castle that changed hands between Welsh and English more times than anyone can count.","history":"Built c.1240 by Welsh lord Maredudd ap Rhys on a steep promontory overlooking the River Teifi. Features a twin-towered gatehouse with semi-octagonal towers. Sir Rhys ap Thomas added larger windows c.1500. Damaged in the English Civil War.","image":"https://img.castlecore.uk/newcastle-emlyn-castle.jpg","rating":3.8,"reviewCount":450,"county":"Carmarthenshire","tags":["hidden-gem","free-entry","riverside","ruins-romantic","medieval"],"access":"free","_index":572,"gallery":["https://img.castlecore.uk/newcastle-emlyn-castle-2.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-3.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-4.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-5.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-ruins-2.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-ruins-3.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-ruins-4.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-ruins-5.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-keep-2.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-keep-3.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-keep-4.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-keep-5.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-main-2.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-main-3.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-main-4.jpg","https://img.castlecore.uk/newcastle-emlyn-castle-main-5.jpg"],"youtube":["vVQxsZdJoao","dWpniPCW37Y","nrWuzvblKR0"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Newcastle_Emlyn_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/newcastle-emlyn-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95070/"}]},{"name":"Narberth Castle","lat":51.7967,"lng":-4.7417,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A castle from Welsh myth and Norman stone — where the Mabinogi's Rhiannon was imprisoned and the Landsker Line divided two worlds.","history":"13th-century Norman ruins built by Andrew Perrot. Features in the Mabinogi as the court of Pwyll and where Rhiannon was punished. Forms part of the Landsker Line dividing Welsh and English-speaking Pembrokeshire. Safety restoration completed 2004-05.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/99/Narberth_castle_pembrokeshire.jpg/500px-Narberth_castle_pembrokeshire.jpg","rating":3.9,"reviewCount":500,"county":"Pembrokeshire","tags":["hidden-gem","free-entry","medieval","norman"],"access":"free","_index":573,"gallery":["https://img.castlecore.uk/narberth-castle-2.jpg","https://img.castlecore.uk/narberth-castle-3.jpg","https://img.castlecore.uk/narberth-castle-4.jpg","https://img.castlecore.uk/narberth-castle-5.jpg","https://img.castlecore.uk/narberth-castle-ruins-2.jpg","https://img.castlecore.uk/narberth-castle-ruins-3.jpg","https://img.castlecore.uk/narberth-castle-ruins-4.jpg","https://img.castlecore.uk/narberth-castle-ruins-5.jpg","https://img.castlecore.uk/narberth-castle-keep-2.jpg","https://img.castlecore.uk/narberth-castle-keep-3.jpg","https://img.castlecore.uk/narberth-castle-keep-4.jpg","https://img.castlecore.uk/narberth-castle-keep-5.jpg"],"youtube":["RiNe0lD30pk","M74OS4j_chE","H4tWKfywW_o"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Narberth_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/narberth-castle"}]},{"name":"Haverfordwest Castle","lat":51.8017,"lng":-4.9683,"country":"Wales","type":"castle","era":"12th-13th century","condition":"partial ruin","description":"A Norman stronghold on a commanding ridge above Pembrokeshire's county town — an English power base through centuries of Welsh resistance, now home to a museum and stunning town views.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/15/HaverfordwestCastle_-_geograph.org.uk_-_25363.jpg/500px-HaverfordwestCastle_-_geograph.org.uk_-_25363.jpg","rating":3.8,"reviewCount":520,"county":"Pembrokeshire","tags":["ruins-romantic","norman","hilltop","museum","atmospheric","free-entry"],"access":"free","_index":574,"gallery":["https://img.castlecore.uk/haverfordwest-castle-2.jpg","https://img.castlecore.uk/haverfordwest-castle-3.jpg","https://img.castlecore.uk/haverfordwest-castle-4.jpg","https://img.castlecore.uk/haverfordwest-castle-5.jpg","https://img.castlecore.uk/haverfordwest-castle-keep-2.jpg","https://img.castlecore.uk/haverfordwest-castle-keep-3.jpg","https://img.castlecore.uk/haverfordwest-castle-keep-4.jpg","https://img.castlecore.uk/haverfordwest-castle-keep-5.jpg"],"history":"Established in 1120 by Gilbert de Clare, Earl of Pembroke, in a naturally defensive position on an isolated ridge. Much of the remaining architecture dates from 1290 under Queen Eleanor of Castile. For centuries it served as an English stronghold. Now partially restored and controlled by the Pembrokeshire Coast National Park Authority, housing a museum.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Haverfordwest_Castle"}]},{"name":"Wiston Castle","lat":51.8333,"lng":-4.8833,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"One of Wales's finest motte-and-bailey castles, founded by a Flemish settler on land seized from Norman rebels — fifty stone steps climb to its dramatic hilltop perch.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/a/aa/Wiston_Castle%2C_from_Cadw_information_board.jpg/500px-Wiston_Castle%2C_from_Cadw_information_board.jpg","rating":3.6,"reviewCount":150,"county":"Pembrokeshire","tags":["hilltop","ruins-romantic","norman","free-entry","photogenic"],"access":"free","_index":575,"gallery":["https://img.castlecore.uk/wiston-castle-2.jpg","https://img.castlecore.uk/wiston-castle-3.jpg","https://img.castlecore.uk/wiston-castle-4.jpg","https://img.castlecore.uk/wiston-castle-5.jpg","https://img.castlecore.uk/wiston-castle-keep-2.jpg","https://img.castlecore.uk/wiston-castle-keep-3.jpg","https://img.castlecore.uk/wiston-castle-keep-4.jpg","https://img.castlecore.uk/wiston-castle-keep-5.jpg"],"history":"Founded after 1100 by Wizo, a Flemish settler granted land by Henry I. Captured by the Welsh several times but always retaken. Abandoned in the 13th century when its owners moved to nearby Picton Castle. Grade I listed building and scheduled monument in the care of Cadw.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Wiston_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/wiston-castle"}]},{"name":"Cardigan Castle","lat":52.0833,"lng":-4.6583,"country":"Wales","type":"castle","era":"11th-13th century","condition":"partial ruin","description":"The birthplace of the Eisteddfod — a beautifully restored Norman castle where Welsh culture was born above the River Teifi.","history":"First motte-and-bailey built c.1093 by Roger de Montgomery. Site of the first Eisteddfod in 1176, hosted by Lord Rhys. Rebuilt in stone in 1244. Castle Green House was built inside the walls c.1800. Fully restored and reopened to the public in 2015 as a heritage centre.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/e/e0/Cardigan_Castle_-_south_western_aspect-Geograph-6075948-by-M-J-Roscoe.jpg/500px-Cardigan_Castle_-_south_western_aspect-Geograph-6075948-by-M-J-Roscoe.jpg","rating":4.3,"reviewCount":1600,"county":"Ceredigion","tags":["hidden-gem","well-preserved","riverside","medieval","events-venue"],"access":"paid","_index":576,"gallery":["https://img.castlecore.uk/cardigan-castle-2.jpg","https://img.castlecore.uk/cardigan-castle-3.jpg","https://img.castlecore.uk/cardigan-castle-4.jpg","https://img.castlecore.uk/cardigan-castle-5.jpg","https://img.castlecore.uk/cardigan-castle-interior-2.jpg","https://img.castlecore.uk/cardigan-castle-interior-3.jpg","https://img.castlecore.uk/cardigan-castle-interior-4.jpg","https://img.castlecore.uk/cardigan-castle-interior-5.jpg","https://img.castlecore.uk/cardigan-castle-main-2.jpg","https://img.castlecore.uk/cardigan-castle-main-3.jpg","https://img.castlecore.uk/cardigan-castle-main-4.jpg","https://img.castlecore.uk/cardigan-castle-main-5.jpg"],"youtube":["kfPkfrJiAqw","KdfHz7vSmok","G7ez3OgFo6o"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Cardigan_Castle"},{"name":"Cardigan Castle Official","url":"https://www.cardigancastle.com/"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/cardigan-castle"}]},{"name":"Newport Castle","lat":51.584,"lng":-2.993,"country":"Wales","type":"castle","era":"14th century","condition":"ruin","description":"A 14th-century castle on the River Usk, built to control the crossing and collect tolls — sacked by Glyndwr, taken by Cromwell, and now a quiet Grade II* ruin in the heart of the city.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/13/Newport_Castle_-_geograph.org.uk_-_781279.jpg/500px-Newport_Castle_-_geograph.org.uk_-_781279.jpg","rating":3.5,"reviewCount":400,"county":"Newport","tags":["ruins-romantic","medieval","riverside","free-entry"],"access":"free","_index":648,"gallery":["https://img.castlecore.uk/newport-castle-2.jpg","https://img.castlecore.uk/newport-castle-3.jpg","https://img.castlecore.uk/newport-castle-4.jpg","https://img.castlecore.uk/newport-castle-5.jpg","https://img.castlecore.uk/newport-castle-ruins-2.jpg","https://img.castlecore.uk/newport-castle-ruins-3.jpg","https://img.castlecore.uk/newport-castle-ruins-4.jpg","https://img.castlecore.uk/newport-castle-ruins-5.jpg"],"history":"Built in the 14th century, probably by Hugh de Audley, 1st Earl of Gloucester, to manage the crossing of the River Usk. Served as administrative offices, residence, and garrison. Sacked by Owain Glyndwr in 1402. In disrepair by 1522. Taken by Cromwell's forces during the Civil War. Grade II* listed.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Newport_Castle"}]},{"name":"Swansea Castle","lat":51.622,"lng":-3.941,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"A defiant medieval ruin hiding in plain sight among the city streets — a thousand-year survivor of Welsh sieges, storms, and urban sprawl.","history":"Founded 1107 by Henry de Beaumont as the caput of the lordship of Gower. Survived a 10-week Welsh siege in 1192. Partially destroyed by the Welsh in 1116. Only two blocks of the original castle remain. Recently restored as a public space in the city centre. Grade I listed.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/97/Swansea2.jpg/500px-Swansea2.jpg","rating":3.5,"reviewCount":600,"county":"Swansea","tags":["hidden-gem","free-entry","medieval","norman"],"access":"free","_index":650,"gallery":["https://img.castlecore.uk/swansea-castle-2.jpg","https://img.castlecore.uk/swansea-castle-3.jpg","https://img.castlecore.uk/swansea-castle-4.jpg","https://img.castlecore.uk/swansea-castle-5.jpg","https://img.castlecore.uk/swansea-castle-ruins-2.jpg","https://img.castlecore.uk/swansea-castle-ruins-3.jpg","https://img.castlecore.uk/swansea-castle-ruins-4.jpg","https://img.castlecore.uk/swansea-castle-ruins-5.jpg","https://img.castlecore.uk/swansea-castle-main-2.jpg","https://img.castlecore.uk/swansea-castle-main-3.jpg","https://img.castlecore.uk/swansea-castle-main-4.jpg","https://img.castlecore.uk/swansea-castle-main-5.jpg"],"youtube":["lvqD0hJ1i1Q","qGmr0VdCOE8","jq4a1dyECIs"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Swansea_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/swansea-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95389/"}]},{"name":"Hawarden Castle","lat":53.187,"lng":-3.031,"country":"Wales","type":"castle","era":"13th century / 19th century","condition":"ruin","description":"Twin castles in a single park—a ruined medieval keep and a Victorian Gothic mansion that served as the beloved home of four-time Prime Minister William Gladstone.","image":"https://img.castlecore.uk/hawarden-castle.jpg","rating":3.7,"reviewCount":320,"county":"Flintshire","tags":["ruins-romantic","victorian","gardens","woodland"],"access":"exterior-only","_index":708,"gallery":["https://img.castlecore.uk/hawarden-castle-2.jpg","https://img.castlecore.uk/hawarden-castle-3.jpg"],"history":"The original castle dates from the 13th century, built during the Welsh wars. It was besieged by Llywelyn ap Gruffudd and later by Owain Glyndŵr. The medieval ruins stand in the grounds alongside a grand Victorian castellated mansion built in 1809, which became the home of William Gladstone from 1852 until his death in 1898. Gladstone's famous library nearby houses 250,000 volumes. The park is occasionally open for events.","sources":[{"name":"Hawarden Castle Estate","url":"https://www.hawardencastle.co.uk/"},{"name":"Wikipedia – Hawarden Castle","url":"https://en.wikipedia.org/wiki/Hawarden_Castle"}]},{"name":"Caergwrle Castle","lat":53.114,"lng":-3.057,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A Welsh prince's castle built in uneasy service to an English king — a hilltop ruin where loyalty and rebellion collided in flame.","history":"Built c.1277 by Dafydd ap Gruffydd in service to Edward I of England. When Dafydd rebelled, Edward sent Reginald de Grey to seize it. The castle was destroyed by fire during the conflict. Managed by Cadw. The ruins command views over the surrounding countryside.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/48/Castell_Caergwrle_-_Castle_built_by_the_Welsh_Princes%2C_in_Sir_y_Fflint_%28Flintshire%29%2C_Wales_26.png/500px-Castell_Caergwrle_-_Castle_built_by_the_Welsh_Princes%2C_in_Sir_y_Fflint_%28Flintshire%29%2C_Wales_26.png","rating":3.7,"reviewCount":280,"county":"Flintshire","tags":["hidden-gem","free-entry","hilltop","medieval"],"access":"free","_index":709,"gallery":["https://img.castlecore.uk/caergwrle-castle-2.jpg","https://img.castlecore.uk/caergwrle-castle-3.jpg","https://img.castlecore.uk/caergwrle-castle-4.jpg","https://img.castlecore.uk/caergwrle-castle-5.jpg","https://img.castlecore.uk/caergwrle-castle-ruins-2.jpg","https://img.castlecore.uk/caergwrle-castle-ruins-3.jpg","https://img.castlecore.uk/caergwrle-castle-ruins-4.jpg","https://img.castlecore.uk/caergwrle-castle-ruins-5.jpg","https://img.castlecore.uk/caergwrle-castle-main-2.jpg","https://img.castlecore.uk/caergwrle-castle-main-3.jpg","https://img.castlecore.uk/caergwrle-castle-main-4.jpg","https://img.castlecore.uk/caergwrle-castle-main-5.jpg"],"youtube":["QrD3UlpUqQ8","ZxGu3oWQD9A","VhQ7nHVRDj8"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Caergwrle_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/caergwrle-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95121/"}]},{"name":"Deganwy Castle","lat":53.294,"lng":-3.819,"country":"Wales","type":"castle","era":"6th century","condition":"ruin","description":"One of Wales' most ancient fortified sites — a volcanic plug fortress that was headquarters to the legendary 6th-century King Maelgwn Gwynedd. Only earthworks remain, but the twin hilltop views over the Conwy estuary are otherworldly.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/73/The_Site_of_Deganwy_Castle_-_aerial_2015.jpg/500px-The_Site_of_Deganwy_Castle_-_aerial_2015.jpg","rating":3.6,"reviewCount":210,"county":"Conwy","tags":["ruins-romantic","hilltop","coastal","free-entry","atmospheric","celtic","prehistoric","medieval"],"access":"free","_index":712,"gallery":["https://img.castlecore.uk/deganwy-castle-2.jpg","https://img.castlecore.uk/deganwy-castle-3.jpg","https://img.castlecore.uk/deganwy-castle-4.jpg","https://img.castlecore.uk/deganwy-castle-5.jpg","https://img.castlecore.uk/deganwy-castle-main-2.jpg","https://img.castlecore.uk/deganwy-castle-main-3.jpg","https://img.castlecore.uk/deganwy-castle-main-4.jpg","https://img.castlecore.uk/deganwy-castle-main-5.jpg"],"history":"Possibly first occupied in Roman times, became the headquarters of Maelgwn Gwynedd, King of Gwynedd (c.520-547). Rebuilt multiple times through the medieval period. A hoard of 204 silver Cnut pennies was found nearby in 1979. The 110m volcanic plug provides commanding views over the River Conwy.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Deganwy_Castle"}]},{"name":"Crickhowell Castle","lat":51.86,"lng":-3.139,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"Norman ruins rising from a green spur above the River Usk in the Brecon Beacons — a moody, overgrown motte surrounded by one of Wales' prettiest market towns. The shell keep foundations whisper of centuries of Welsh-Norman conflict.","image":"https://img.castlecore.uk/crickhowell-castle.jpg","rating":3.7,"reviewCount":350,"county":"Powys","tags":["ruins-romantic","riverside","free-entry","norman","medieval","photogenic"],"access":"free","_index":715,"gallery":["https://img.castlecore.uk/crickhowell-castle-2.jpg","https://img.castlecore.uk/crickhowell-castle-3.jpg","https://img.castlecore.uk/crickhowell-castle-4.jpg","https://img.castlecore.uk/crickhowell-castle-5.jpg","https://img.castlecore.uk/crickhowell-castle-ruins-2.jpg","https://img.castlecore.uk/crickhowell-castle-ruins-3.jpg","https://img.castlecore.uk/crickhowell-castle-ruins-4.jpg","https://img.castlecore.uk/crickhowell-castle-ruins-5.jpg"],"history":"Built c.1121 by Robert Turberville, Norman tenant of Marcher lord Bernard de Neufmarche. Attacked by Welsh rebels in 1172. Passed through the Turberville family for generations. Grade I listed building with visible motte and buried shell keep foundations.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Crickhowell_Castle"}]},{"name":"Oxwich Castle","lat":51.554,"lng":-4.148,"country":"Wales","type":"castle","era":"16th century","condition":"ruin","description":"A grand Tudor manor house in castle's clothing, perched on a wooded headland above one of Gower's most beautiful bays.","history":"Despite its name, a Tudor fortified manor house built in courtyard style on a headland overlooking Oxwich Bay. Site owned by the de Penres family from the 1230s, then the Mansel family who built the current structure in the 16th century. The famous Oxwich Brooch was found here. Managed by Cadw.","image":"https://img.castlecore.uk/oxwich-castle.jpg","rating":4,"reviewCount":500,"county":"Swansea","tags":["hidden-gem","coastal","tudor","photogenic"],"access":"paid","_index":717,"gallery":["https://img.castlecore.uk/oxwich-castle-2.jpg","https://img.castlecore.uk/oxwich-castle-3.jpg","https://img.castlecore.uk/oxwich-castle-4.jpg","https://img.castlecore.uk/oxwich-castle-5.jpg","https://img.castlecore.uk/oxwich-castle-interior-2.jpg","https://img.castlecore.uk/oxwich-castle-interior-3.jpg","https://img.castlecore.uk/oxwich-castle-interior-4.jpg","https://img.castlecore.uk/oxwich-castle-interior-5.jpg","https://img.castlecore.uk/oxwich-castle-main-2.jpg","https://img.castlecore.uk/oxwich-castle-main-3.jpg","https://img.castlecore.uk/oxwich-castle-main-4.jpg","https://img.castlecore.uk/oxwich-castle-main-5.jpg"],"youtube":["GAbaJPTNdhk","7aYnGDUWRN8","omNwrvf09G4"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Oxwich_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/oxwich-castle"}]},{"name":"Loughor Castle","lat":51.662,"lng":-4.062,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A ruined Norman ringwork perched above the River Loughor, built atop a Roman fort — where Welsh princes and English lords battled for control of the Gower.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/1/15/Loughor_Castle_-_geograph.org.uk_-_2353532.jpg/500px-Loughor_Castle_-_geograph.org.uk_-_2353532.jpg","rating":3.4,"reviewCount":110,"county":"Swansea","tags":["ruins-romantic","norman","hilltop","free-entry","riverside"],"access":"free","_index":718,"gallery":["https://img.castlecore.uk/loughor-castle-2.jpg","https://img.castlecore.uk/loughor-castle-3.jpg","https://img.castlecore.uk/loughor-castle-4.jpg","https://img.castlecore.uk/loughor-castle-5.jpg","https://img.castlecore.uk/loughor-castle-main-2.jpg","https://img.castlecore.uk/loughor-castle-main-3.jpg","https://img.castlecore.uk/loughor-castle-main-4.jpg","https://img.castlecore.uk/loughor-castle-main-5.jpg"],"history":"Built around 1106 by Anglo-Norman lord Henry de Beaumont on the site of the Roman fort Leucarum. Attacked and burnt in 1151, captured by Llywelyn the Great in 1215. John de Braose rebuilt it with stone walls after 1220. Stone tower added in the late 13th century. Now in the care of Cadw.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Loughor_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/loughor-castle"}]},{"name":"Fonmon Castle","lat":51.396,"lng":-3.448,"country":"Wales","type":"castle","era":"12th century","condition":"intact","description":"One of Wales's rarest architectural survivors — a 12th-century fortress that evolved into an elegant Georgian home and never stopped being lived in.","history":"A fortified medieval castle near the village of Fonmon in the Vale of Glamorgan. Grade I listed with Grade II gardens. Origins rooted in the 12th century, it is one of few buildings in Wales continuously inhabited since the Norman period. Privately owned with gardens open to visitors.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/a/ac/Castell_Ffwl-y-mwn.jpg/500px-Castell_Ffwl-y-mwn.jpg","rating":4,"reviewCount":400,"county":"Vale of Glamorgan","tags":["hidden-gem","well-preserved","gardens","medieval","wedding-venue"],"access":"paid","_index":721,"gallery":["https://img.castlecore.uk/fonmon-castle-2.jpg","https://img.castlecore.uk/fonmon-castle-3.jpg","https://img.castlecore.uk/fonmon-castle-4.jpg","https://img.castlecore.uk/fonmon-castle-5.jpg","https://img.castlecore.uk/fonmon-castle-interior-2.jpg","https://img.castlecore.uk/fonmon-castle-interior-3.jpg","https://img.castlecore.uk/fonmon-castle-interior-4.jpg","https://img.castlecore.uk/fonmon-castle-interior-5.jpg","https://img.castlecore.uk/fonmon-castle-main-2.jpg","https://img.castlecore.uk/fonmon-castle-main-3.jpg","https://img.castlecore.uk/fonmon-castle-main-4.jpg","https://img.castlecore.uk/fonmon-castle-main-5.jpg"],"youtube":["reC_aM5Y0gI","sVsrzHQYQ1A","He6YCacyb4A"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Fonmon_Castle"},{"name":"Fonmon Castle Official","url":"https://www.fonmoncastle.com/"}]},{"name":"Llantrithyd Place","lat":51.439,"lng":-3.415,"country":"Wales","type":"castle","era":"16th century","condition":"ruin","description":"Ivy-strangled Elizabethan ruins slumbering in a hidden Vale of Glamorgan valley—a forgotten gentry house slowly being reclaimed by nature.","image":"https://img.castlecore.uk/llantrithyd-place.jpg","rating":3.3,"reviewCount":40,"county":"Vale of Glamorgan","tags":["ruins-romantic","tudor","atmospheric","free-entry","remote"],"access":"free","_index":722,"gallery":["https://img.castlecore.uk/llantrithyd-place-2.jpg"],"history":"A Tudor and Elizabethan manor house built by the Aubrey family in the 16th century on the site of an earlier medieval dwelling. The house was a substantial gentry residence with fine architectural details. It declined in the 18th century and was abandoned, gradually falling into picturesque ruin. The atmospheric remains include gable walls and window openings amid overgrown grounds in the quiet Vale of Glamorgan.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk/en/site/19369"},{"name":"Wikipedia – Llantrithyd Place","url":"https://en.wikipedia.org/wiki/Llantrithyd_Place"}]},{"name":"Tenby Castle","lat":51.672,"lng":-4.7,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"Dramatic Norman ruins perched on a windswept headland above Tenby's pastel-painted harbour — where Welsh princes fought to reclaim their land from the sea-facing fortress walls.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/db/Tenby_Castle_-_geograph.org.uk_-_3694238.jpg/500px-Tenby_Castle_-_geograph.org.uk_-_3694238.jpg","rating":3.9,"reviewCount":520,"county":"Pembrokeshire","tags":["ruins-romantic","coastal","cliffside","photogenic","atmospheric","free-entry"],"access":"free","_index":724,"gallery":["https://img.castlecore.uk/tenby-castle-2.jpg","https://img.castlecore.uk/tenby-castle-3.jpg","https://img.castlecore.uk/tenby-castle-4.jpg","https://img.castlecore.uk/tenby-castle-5.jpg","https://img.castlecore.uk/tenby-castle-main-2.jpg","https://img.castlecore.uk/tenby-castle-main-3.jpg","https://img.castlecore.uk/tenby-castle-main-4.jpg","https://img.castlecore.uk/tenby-castle-main-5.jpg"],"history":"Founded by the Normans during their invasion of West Wales in the 12th century. A stone tower was built on the headland's highest point with curtain wall protection. Captured and destroyed in 1153 by Maredudd and Rhys ap Gruffydd, Welsh princes of Deheubarth. The remaining stone structure dates from the 13th century. Grade II* listed.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Tenby_Castle"}]},{"name":"Angle Tower","lat":51.68,"lng":-5.089,"country":"Wales","type":"castle","era":"14th century","condition":"ruin","description":"A rare Welsh tower house in a sleepy Pembrokeshire village—a pocket fortress more akin to Scotland or Ireland, standing guard near the entrance to Milford Haven.","image":"https://img.castlecore.uk/angle-tower.jpg","rating":3.3,"reviewCount":55,"county":"Pembrokeshire","tags":["medieval","well-preserved","free-entry","coastal"],"access":"exterior-only","_index":725,"gallery":["https://img.castlecore.uk/angle-tower-2.jpg","https://img.castlecore.uk/angle-tower-3.jpg","https://img.castlecore.uk/angle-tower-4.jpg","https://img.castlecore.uk/angle-tower-5.jpg","https://img.castlecore.uk/angle-tower-main-2.jpg","https://img.castlecore.uk/angle-tower-main-3.jpg","https://img.castlecore.uk/angle-tower-main-4.jpg","https://img.castlecore.uk/angle-tower-main-5.jpg"],"history":"This 14th-century tower house is a rare building type in Wales, more commonly found in Ireland and Scotland. Built near the Landsker Line dividing English and Welsh Pembrokeshire, it served as a defensible residence with arrow slits suggesting pre-1400 construction. Now managed by Pembrokeshire Coast National Park Authority, it is one of the best-preserved examples of its kind in Wales.","sources":[{"name":"Medieval Heritage","url":"https://medievalheritage.eu/en/main-page/heritage/wales/angle-tower-house/"},{"name":"Wikipedia – Welsh Tower Houses","url":"https://en.wikipedia.org/wiki/Welsh_Tower_houses"}]},{"name":"Roch Castle","lat":51.833,"lng":-5.073,"country":"Wales","type":"castle","era":"12th century","condition":"restored","description":"A striking Norman tower perched on a volcanic crag above the Pembrokeshire coast, now reborn as a boutique retreat with panoramic views over St Brides Bay.","image":"https://img.castlecore.uk/roch-castle.jpg","rating":3.8,"reviewCount":350,"county":"Pembrokeshire","tags":["norman","hilltop","photogenic","coastal"],"access":"exterior-only","_index":1023,"gallery":["https://img.castlecore.uk/roch-castle-2.jpg","https://img.castlecore.uk/roch-castle-3.jpg","https://img.castlecore.uk/roch-castle-4.jpg","https://img.castlecore.uk/roch-castle-5.jpg"],"history":"Built in the 12th century by Norman knight Adam de la Roche (de Rupe) on a volcanic outcrop near the Landsker Line. Legend says Adam built on the rock after a prophecy that he would die from a serpent's bite—only to be fatally bitten by a viper smuggled in with firewood. The castle was damaged during the Civil War and later restored. Now a luxury holiday let with sweeping coastal views.","sources":[{"name":"Wikipedia – Roch Castle","url":"https://en.wikipedia.org/wiki/Roch_Castle"},{"name":"Pembrokeshire Coast National Park","url":"https://www.pembrokeshirecoast.wales/about-the-national-park/culture-and-heritage/land-of-legends/roch-castle/"},{"name":"Roch Castle Hotel","url":"https://rochcastle.com/"}]},{"name":"Upton Castle","lat":51.714,"lng":-4.901,"country":"Wales","type":"castle","era":"13th century onwards","condition":"intact","description":"A medieval castle wrapped in magnificent subtropical gardens, where 35 acres of rare trees, champion specimens, and walled terraces cascade toward the Daugleddau estuary.","image":"https://upload.wikimedia.org/wikipedia/commons/8/8b/Upton_Castle%2C_Pembrokeshire._20.jpeg","rating":3.6,"reviewCount":280,"county":"Pembrokeshire","tags":["gardens","medieval","photogenic"],"access":"paid","_index":1024,"gallery":["https://pub-865f4a8498e64980801e4e498b53f5c0.r2.dev/wiki-upton-castle.jpg"],"history":"A medieval fortified manor house with origins in the 13th century, held by the Malefant family and later the Bowens. Rhys ap Owen, High Sheriff of Pembrokeshire, held it in 1564. In 1753 John Tasker, a Master Attendant of the Port of Bombay, bought it and built the walled garden. In 1927 ship owner Stanley Neale landscaped the terraces and arboretum. Gardens opened to the public in 1976 via the National Park.","sources":[{"name":"Wikipedia – Upton Castle","url":"https://en.wikipedia.org/wiki/Upton_Castle"},{"name":"Upton Castle Gardens","url":"https://www.uptoncastle.co.uk/history/"},{"name":"Britain Express","url":"https://www.britainexpress.com/wales/pembrokeshire/upton-castle-gardens.htm"}]},{"name":"Llandovery Castle","lat":51.995,"lng":-3.802,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A Norman ruin on a knoll above the River Towy, with a modern bronze warrior guarding what centuries of Welsh princes fought and died for. One of Wales' most contested castles — taken and retaken so many times the history reads like a war diary.","image":"https://img.castlecore.uk/llandovery-castle.jpg","rating":3.6,"reviewCount":320,"county":"Carmarthenshire","tags":["ruins-romantic","riverside","free-entry","norman","medieval"],"access":"free","_index":1026,"gallery":["https://img.castlecore.uk/llandovery-castle-2.jpg","https://img.castlecore.uk/llandovery-castle-3.jpg","https://img.castlecore.uk/llandovery-castle-4.jpg","https://img.castlecore.uk/llandovery-castle-5.jpg","https://img.castlecore.uk/llandovery-castle-ruins-2.jpg","https://img.castlecore.uk/llandovery-castle-ruins-3.jpg","https://img.castlecore.uk/llandovery-castle-ruins-4.jpg","https://img.castlecore.uk/llandovery-castle-ruins-5.jpg"],"history":"Norman motte-and-bailey probably begun in 1116 by Richard Fitz Pons. Repeatedly lost to the Princes of Deheubarth. Henry II spent heavily repairing it 1159-62 but the Welsh recaptured it. Finally fell to Edward I in 1277. Burned in the early 16th century and never repaired. Grade II* listed.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Llandovery_Castle"}]},{"name":"Aberglasney House","lat":51.856,"lng":-4.028,"country":"Wales","type":"castle","era":"16th century","condition":"restored","description":"A restored medieval manor in the Tywi Valley with one of Wales's most enchanting garden restorations — a lost garden found again.","history":"A medieval house and gardens in the Tywi Valley, Carmarthenshire. Grade II* listed house with Grade II* gardens. Restored by the Aberglasney Restoration Trust. Features a unique Elizabethan cloister garden and a subtropical indoor garden in the restored Ninfarium.","image":"https://img.castlecore.uk/aberglasney-house.jpg","rating":4.2,"reviewCount":2800,"county":"Carmarthenshire","tags":["romantic-ruin","gardens","photogenic","medieval"],"access":"paid","_index":1027,"gallery":["https://img.castlecore.uk/aberglasney-house-2.jpg","https://img.castlecore.uk/aberglasney-house-3.jpg","https://img.castlecore.uk/aberglasney-house-4.jpg","https://img.castlecore.uk/aberglasney-house-5.jpg","https://img.castlecore.uk/aberglasney-house-main-2.jpg","https://img.castlecore.uk/aberglasney-house-main-3.jpg","https://img.castlecore.uk/aberglasney-house-main-4.jpg","https://img.castlecore.uk/aberglasney-house-main-5.jpg"],"youtube":["0vZlws_cP2U","POYuYdksI5w","ga9h_ycXm_0"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Aberglasney_House"},{"name":"Aberglasney Official","url":"https://aberglasney.org/"}]},{"name":"Tregaron Castle Mound","lat":52.218,"lng":-3.931,"country":"Wales","type":"motte","era":"12th century","condition":"ruin","description":"A quiet grassy motte in the market square of Tregaron, an unassuming hillock at the heart of a small Ceredigion town steeped in the legend of Wales's own Robin Hood, Twm Siôn Cati.","image":"https://img.castlecore.uk/tregaron-castle-mound.jpg","rating":3.1,"reviewCount":20,"county":"Ceredigion","tags":["free-entry","medieval","norman"],"access":"free","_index":1028,"gallery":["https://img.castlecore.uk/tregaron-castle-mound-2.jpg","https://img.castlecore.uk/tregaron-castle-mound-3.jpg","https://img.castlecore.uk/tregaron-castle-mound-4.jpg","https://img.castlecore.uk/tregaron-castle-mound-5.jpg","https://img.castlecore.uk/tregaron-castle-mound-main-2.jpg","https://img.castlecore.uk/tregaron-castle-mound-main-3.jpg","https://img.castlecore.uk/tregaron-castle-mound-main-4.jpg","https://img.castlecore.uk/tregaron-castle-mound-main-5.jpg"],"history":"A Norman motte-and-bailey castle mound in the centre of Tregaron, Ceredigion. Little documented history survives of the castle itself, which was likely an early Norman fortification to control this remote part of mid-Wales. The town is famous as the birthplace of Twm Siôn Cati (Thomas Jones, c.1530), a legendary outlaw and trickster sometimes called the Welsh Robin Hood.","sources":[{"name":"Ceredigion Historical Society","url":"https://ceredigionhistory.wales/tregaron/"},{"name":"Discover Ceredigion","url":"https://www.discoverceredigion.wales/areas-of-ceredigion/cambrian-mountains/communities-of-the-cambrian-mountains/tregaron-and-area/"}]},{"name":"Tomen y Mur","lat":52.894,"lng":-3.894,"country":"Wales","type":"fort","era":"1st century AD / 11th century","condition":"ruin","description":"A Roman fort and medieval motte in the heart of Snowdonia — where legionaries once watched the Welsh mountains and Norman conquerors later raised their own defences.","image":"https://img.castlecore.uk/tomen-y-mur.jpg","rating":3.4,"reviewCount":75,"county":"Gwynedd","tags":["hilltop","remote","ruins-romantic","atmospheric","medieval","prehistoric"],"access":"free","_index":1029,"gallery":["https://img.castlecore.uk/tomen-y-mur-2.jpg","https://img.castlecore.uk/tomen-y-mur-3.jpg","https://img.castlecore.uk/tomen-y-mur-4.jpg","https://img.castlecore.uk/tomen-y-mur-5.jpg","https://img.castlecore.uk/tomen-y-mur-main-2.jpg","https://img.castlecore.uk/tomen-y-mur-main-3.jpg","https://img.castlecore.uk/tomen-y-mur-main-4.jpg","https://img.castlecore.uk/tomen-y-mur-main-5.jpg"],"history":"A Roman auxiliary fort (Tomen y Mur) in Gwynedd, built around 78 AD during the Roman conquest of Wales. William Rufus later constructed a Norman motte on the site around 1095. One of the most dramatically sited Roman forts in Britain, surrounded by the wild Snowdonia landscape.","sources":[]},{"name":"Castell Collen","lat":52.251,"lng":-3.551,"country":"Wales","type":"fort","era":"1st-4th century AD","condition":"ruin","description":"The grassy ramparts of a Roman auxiliary fort in the green hills near Llandrindod Wells—a frontier outpost where legionaries once watched over the rebellious tribes of central Wales.","image":"https://img.castlecore.uk/castell-collen.jpg","rating":3.3,"reviewCount":50,"county":"Powys","tags":["free-entry","riverside","prehistoric"],"access":"free","_index":1030,"gallery":["https://img.castlecore.uk/castell-collen-2.jpg","https://img.castlecore.uk/castell-collen-3.jpg","https://img.castlecore.uk/castell-collen-4.jpg","https://img.castlecore.uk/castell-collen-5.jpg","https://img.castlecore.uk/castell-collen-main-2.jpg","https://img.castlecore.uk/castell-collen-main-3.jpg","https://img.castlecore.uk/castell-collen-main-4.jpg","https://img.castlecore.uk/castell-collen-main-5.jpg"],"history":"A Roman auxiliary fort built c. AD 75 on the banks of the River Ithon near Llandrindod Wells, Powys. It was occupied intermittently until the 4th century, serving as a base for controlling the native Ordovices tribe. Excavations have revealed stone buildings, a bathhouse, and a civilian settlement (vicus) outside the walls. Finds are displayed in the Radnorshire Museum in town.","sources":[{"name":"Britain Express","url":"https://www.britainexpress.com/attractions.htm?attraction=812"},{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk/en/site/95708/"},{"name":"Ancient Monuments UK","url":"https://ancientmonuments.uk/128706-castell-collen-llandrindod-wells"}]},{"name":"Painscastle","lat":52.125,"lng":-3.242,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"Massive earthworks on a Radnorshire hilltop—once a great Marcher fortress at the volatile frontier between England and Wales, where armies clashed and legends of Maud de Braose were born.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Painscastle_-_geograph.org.uk_-_403187.jpg/500px-Painscastle_-_geograph.org.uk_-_403187.jpg","rating":3.2,"reviewCount":35,"county":"Powys","tags":["hilltop","free-entry","atmospheric","medieval"],"access":"free","_index":1031,"gallery":["https://upload.wikimedia.org/wikipedia/commons/thumb/5/5c/Painscastle_-_geograph.org.uk_-_403187.jpg/500px-Painscastle_-_geograph.org.uk_-_403187.jpg"],"history":"First built by Pain fitzJohn before his death in 1137, the castle was rebuilt by William de Braose, 4th Lord of Bramber, by 1195. Known in Welsh as Castell Paen, it was besieged by Rhys ap Gruffudd in 1196 and by Gwenwynwyn ab Owain of Powys in 1198, the latter suffering heavy defeat. Roger Mortimer seized it in 1276 but Edward I forced its return to Ralph Tosny. Only massive earthworks survive today.","sources":[{"name":"Wikipedia – Painscastle Castle","url":"https://en.wikipedia.org/wiki/Painscastle_Castle"},{"name":"Mortimer History Society","url":"https://mortimerhistorysociety.org.uk/the-mortimers/mortimer-castles/painscastle-castle/"}]},{"name":"Castell Aberlleiniog","lat":53.273,"lng":-4.121,"country":"Wales","type":"castle","era":"11th century","condition":"ruin","description":"A Norman motte rising from Anglesey woodland — built by the Earl of Chester to tame the island, now surrendered to the trees.","history":"A motte-and-bailey fortress near Llangoed on the Isle of Anglesey, built 1080-1099 by Hugh d'Avranches, 1st Earl of Chester. Sited on a steep hill about two miles from Beaumaris Castle. Currently undergoing restoration. In use from the late 11th century to the mid-17th century.","image":"https://img.castlecore.uk/castell-aberlleiniog.jpg","rating":3.6,"reviewCount":250,"county":"Anglesey","tags":["hidden-gem","free-entry","woodland","norman","medieval"],"access":"free","_index":1032,"gallery":["https://img.castlecore.uk/castell-aberlleiniog-2.jpg","https://img.castlecore.uk/castell-aberlleiniog-3.jpg","https://img.castlecore.uk/castell-aberlleiniog-4.jpg","https://img.castlecore.uk/castell-aberlleiniog-5.jpg","https://img.castlecore.uk/castell-aberlleiniog-ruins-2.jpg","https://img.castlecore.uk/castell-aberlleiniog-ruins-3.jpg","https://img.castlecore.uk/castell-aberlleiniog-ruins-4.jpg","https://img.castlecore.uk/castell-aberlleiniog-ruins-5.jpg","https://img.castlecore.uk/castell-aberlleiniog-main-2.jpg","https://img.castlecore.uk/castell-aberlleiniog-main-3.jpg","https://img.castlecore.uk/castell-aberlleiniog-main-4.jpg","https://img.castlecore.uk/castell-aberlleiniog-main-5.jpg"],"youtube":["kcx23o6GGDg","V03JnRCNeu8","Z-0mbT3qy6U"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Castell_Aberlleiniog"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/castell-aberlleiniog"},{"name":"Visit Anglesey","url":"https://www.visitanglesey.co.uk/en/things-to-do/castell-aberlleiniog/"}]},{"name":"Nevern Castle","lat":51.998,"lng":-4.768,"country":"Wales","type":"castle","era":"12th century","condition":"ruin","description":"A hidden Welsh stronghold in the Pembrokeshire countryside, shrouded in woodland and barely known outside local walking circles. The overgrown earthworks and mysterious atmosphere reward those who seek it out.","image":"https://img.castlecore.uk/nevern-castle.jpg","rating":3.9,"reviewCount":350,"county":"Pembrokeshire","tags":["ruins-romantic","woodland","hidden-gem","free-entry","norman","atmospheric"],"access":"free","_index":1301,"gallery":["https://img.castlecore.uk/nevern-castle-2.jpg","https://img.castlecore.uk/nevern-castle-3.jpg","https://img.castlecore.uk/nevern-castle-4.jpg","https://img.castlecore.uk/nevern-castle-5.jpg","https://img.castlecore.uk/nevern-castle-ruins-2.jpg","https://img.castlecore.uk/nevern-castle-ruins-3.jpg","https://img.castlecore.uk/nevern-castle-ruins-4.jpg","https://img.castlecore.uk/nevern-castle-ruins-5.jpg"],"history":"A Norman motte-and-bailey castle in Pembrokeshire, built to control the Nevern valley. Part of the network of Welsh Marcher castles. The earthworks survive in woodland near the village of Nevern, known for its ancient Celtic cross and 'bleeding yew' tree in the churchyard."},{"name":"Castell Henllys","lat":52.015,"lng":-4.728,"country":"Wales","type":"hillfort","era":"Iron Age (c.500 BC)","condition":"reconstructed","description":"A unique Iron Age inland promontory fort in the Preseli Hills with reconstructed Celtic roundhouses built on their original foundations—step inside and smell the woodsmoke of 2,000 years ago.","image":"https://img.castlecore.uk/castell-henllys.jpg","rating":4,"reviewCount":125,"county":"Pembrokeshire","tags":["prehistoric","celtic","kid-friendly","woodland","guided-tours","gift-shop"],"access":"paid","_index":1302,"gallery":["https://img.castlecore.uk/castell-henllys-2.jpg","https://img.castlecore.uk/castell-henllys-3.jpg","https://img.castlecore.uk/castell-henllys-4.jpg","https://img.castlecore.uk/castell-henllys-5.jpg"],"history":"An Iron Age hillfort dating to c.500 BC, excavated extensively since the 1980s. Uniquely, four roundhouses have been reconstructed on their exact original foundations, making this the only Iron Age fort in Britain with reconstructions in situ. Located in the Pembrokeshire Coast National Park, the site offers immersive experiences including Celtic crafts and storytelling. The River Gwaun flows below the promontory.","sources":[{"name":"Pembrokeshire Coast National Park","url":"https://www.pembrokeshirecoast.wales/castell-henllys/"},{"name":"Wikipedia – Castell Henllys","url":"https://en.wikipedia.org/wiki/Castell_Henllys"}]},{"name":"Newport Castle (Pembs Main)","lat":52.018,"lng":-4.838,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"The gaunt medieval gatehouse of a Norman castle perched above the pretty north Pembrokeshire town of Newport, framing views of the Preseli Hills beyond.","image":"https://img.castlecore.uk/newport-castle-pembs-main.jpg","rating":3.3,"reviewCount":18,"county":"Pembrokeshire","tags":["norman","medieval","hilltop"],"access":"exterior-only","_index":1303,"gallery":["https://img.castlecore.uk/newport-castle-pembs-main-2.jpg","https://img.castlecore.uk/newport-castle-pembs-main-3.jpg","https://img.castlecore.uk/newport-castle-pembs-main-4.jpg","https://img.castlecore.uk/newport-castle-pembs-main-5.jpg"],"history":"A Norman castle built in the 13th century by William fitzMartin, Baron of Cemais, after the original castle at nearby Nevern was lost to the Welsh. The impressive three-storey gatehouse with round towers is the main surviving feature. The castle sits on a ridge above the town with views to the Preseli Hills. Part of the structure is incorporated into a private residence.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/newport-castle"},{"name":"Wikipedia – Newport Castle, Pembrokeshire","url":"https://en.wikipedia.org/wiki/Newport_Castle,_Pembrokeshire"}]},{"name":"Castell Abereinion","lat":52.358,"lng":-3.718,"country":"Wales","type":"castle","era":"11th-12th century","condition":"ruin","description":"A tree-covered Norman motte rising above the Severn valley in mid-Wales, a forgotten stronghold in one of the most contested borderlands in medieval Britain.","image":"https://img.castlecore.uk/castell-abereinion.jpg","rating":3.1,"reviewCount":10,"county":"Ceredigion","tags":["hilltop","free-entry","woodland","norman"],"access":"free","_index":1304,"gallery":["https://img.castlecore.uk/castell-abereinion-2.jpg","https://img.castlecore.uk/castell-abereinion-3.jpg","https://img.castlecore.uk/castell-abereinion-4.jpg","https://img.castlecore.uk/castell-abereinion-5.jpg"],"history":"A Norman motte-and-bailey castle near Llandinam in Powys, overlooking the upper Severn valley. Built in the late 11th or 12th century as part of the Norman advance into central Wales. The earthwork mound and ditch survive, now heavily wooded. The castle was one of many small frontier fortifications in the volatile borderlands between Norman-held territory and the Welsh principalities.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Castell Gwallter","lat":52.258,"lng":-4.058,"country":"Wales","type":"motte","era":"12th century","condition":"intact","description":"A grassy mound by the River Ystwyth near Aberystwyth, once a Norman stronghold in the wild lands of Ceredigion where Welsh princes regularly swept away English fortifications.","image":"https://img.castlecore.uk/castell-gwallter.jpg","rating":3,"reviewCount":7,"county":"Ceredigion","tags":["hilltop","free-entry","riverside","norman"],"access":"free","_index":1305,"gallery":["https://pub-865f4a8498e64980801e4e498b53f5c0.r2.dev/wiki-castell-gwallter.jpg"],"history":"A Norman motte-and-bailey castle (also known as Walter's Castle) near Llanfihangel-y-Creuddyn in Ceredigion. Built in the 12th century as part of the Norman penetration of west Wales. It was repeatedly attacked and destroyed by Welsh forces during the long struggle for control of Ceredigion. Only the motte earthwork survives beside the river.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Cefnllys Castle","lat":52.268,"lng":-3.348,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A lonely hilltop castle site in the Radnorshire uplands, where only sheep and skylarks now inhabit the windswept earthworks of this once-formidable Marcher fortress.","image":"https://img.castlecore.uk/cefnllys-castle.jpg","rating":3.5,"reviewCount":28,"county":"Powys","tags":["hilltop","free-entry","remote","atmospheric","medieval"],"access":"free","_index":1307,"gallery":["https://img.castlecore.uk/cefnllys-castle-2.jpg","https://img.castlecore.uk/cefnllys-castle-3.jpg","https://img.castlecore.uk/cefnllys-castle-4.jpg","https://img.castlecore.uk/cefnllys-castle-5.jpg"],"history":"A Marcher castle near Llandrindod Wells, Powys, built and rebuilt multiple times during the 13th century. The original castle was destroyed by Llywelyn ap Gruffudd in 1262. Rebuilt by Roger Mortimer, it was attacked again during the Welsh wars. A second castle was built nearby on a higher hill. The remote hilltop location offers panoramic views of the Ithon valley and surrounding uplands.","sources":[{"name":"Castles of Wales","url":"https://www.castlesofwales.com/cefnllys.html"},{"name":"Wikipedia – Cefnllys Castle","url":"https://en.wikipedia.org/wiki/Cefnllys_Castle"}]},{"name":"Mathrafal Castle","lat":52.668,"lng":-3.408,"country":"Wales","type":"castle","era":"9th-13th century","condition":"ruin","description":"The overgrown earthworks of the principal seat of the princes of Powys—once the most important royal court in central Wales, now lost in meadows beside the River Banwy.","image":"https://img.castlecore.uk/mathrafal-castle.jpg","rating":3.4,"reviewCount":20,"county":"Powys","tags":["hilltop","free-entry","remote","celtic","medieval"],"access":"free","_index":1309,"gallery":["https://img.castlecore.uk/mathrafal-castle-2.jpg","https://img.castlecore.uk/mathrafal-castle-3.jpg","https://img.castlecore.uk/mathrafal-castle-4.jpg"],"history":"Mathrafal was the llys (royal court) of the princes of Powys from at least the 9th century, making it one of the most significant sites in medieval Welsh history. The earthwork remains include a large motte and ditches. The princes ruled from here until the 13th century. Edward I seized the site in 1277. Now marked only by grassy mounds in fields near Meifod, Powys, it is easily overlooked despite its historical importance.","sources":[{"name":"Wikipedia – Mathrafal Castle","url":"https://en.wikipedia.org/wiki/Mathrafal_Castle"},{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Penhow Castle","lat":51.598,"lng":-2.878,"country":"Wales","type":"castle","era":"12th century","condition":"intact","description":"Claimed as the oldest continuously inhabited castle in Wales, Penhow has been lived in since the Normans built it in the 12th century. A fortified manor layered with centuries of additions — from medieval tower to Tudor great hall.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/6/69/Penhow_Castle_from_Church.jpg/500px-Penhow_Castle_from_Church.jpg","rating":3.8,"reviewCount":350,"county":"Monmouthshire","tags":["well-preserved","medieval","norman","tudor","hidden-gem"],"access":"paid","_index":1310,"gallery":["https://img.castlecore.uk/penhow-castle-2.jpg","https://img.castlecore.uk/penhow-castle-3.jpg","https://img.castlecore.uk/penhow-castle-4.jpg","https://img.castlecore.uk/penhow-castle-5.jpg","https://img.castlecore.uk/penhow-castle-interior-2.jpg","https://img.castlecore.uk/penhow-castle-interior-3.jpg","https://img.castlecore.uk/penhow-castle-interior-4.jpg","https://img.castlecore.uk/penhow-castle-interior-5.jpg"],"history":"Built c.1129 by Sir Roger de St Maur (Seymour family) after the Norman invasion of Wales, on lands seized from Caradog ap Gruffydd, Prince of Gwent. Extended in the 15th and 17th centuries. Passed to the Somersets in the 16th century. Grade II* listed.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Penhow_Castle"}]},{"name":"Dinas Emrys","lat":53.028,"lng":-4.058,"country":"Wales","type":"hillfort","era":"Iron Age / 5th-6th century","condition":"ruin","description":"The legendary hillfort above Llyn Dinas where Merlin revealed two battling dragons to King Vortigern—the origin myth of the Welsh red dragon, wrapped in Snowdonia's most magical landscape.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/4a/DinasEmrys1.JPG/500px-DinasEmrys1.JPG","rating":3.8,"reviewCount":68,"county":"Gwynedd","tags":["hilltop","prehistoric","celtic","atmospheric","woodland","remote"],"access":"free","_index":1312,"gallery":["https://img.castlecore.uk/dinas-emrys-2.jpg","https://img.castlecore.uk/dinas-emrys-3.jpg","https://img.castlecore.uk/dinas-emrys-4.jpg","https://img.castlecore.uk/dinas-emrys-5.jpg"],"history":"An Iron Age and Dark Age hillfort near Beddgelert in Snowdonia. According to Nennius (c.829 AD), King Vortigern tried to build a fortress here but the walls kept collapsing. The boy Myrddin Emrys (Merlin) revealed two dragons—red and white—fighting beneath a hidden pool, symbolising the Welsh and Saxon nations. Excavations in the 1950s found a pool and Dark Age structures. Now owned by the National Trust.","sources":[{"name":"Wikipedia – Dinas Emrys","url":"https://en.wikipedia.org/wiki/Dinas_Emrys"},{"name":"National Trust – Craflwyn & Beddgelert","url":"https://www.nationaltrust.org.uk/visit/wales/craflwyn-and-beddgelert/discover-the-legend-of-two-dragons"},{"name":"Land of Legends Wales","url":"https://www.landoflegends.wales/location/dinas-emrys"}]},{"name":"Castell Prysor","lat":52.848,"lng":-3.848,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A remote Welsh mountain castle lost to the wilds of Snowdonia — one of the last native Welsh fortifications, barely visible now among the sheep and heather.","image":"https://img.castlecore.uk/castell-prysor.jpg","rating":3.3,"reviewCount":80,"county":"Gwynedd","tags":["remote","hilltop","ruins-romantic","medieval","atmospheric"],"access":"free","_index":1313,"gallery":["https://img.castlecore.uk/castell-prysor-2.jpg","https://img.castlecore.uk/castell-prysor-3.jpg","https://img.castlecore.uk/castell-prysor-4.jpg","https://img.castlecore.uk/castell-prysor-5.jpg","https://img.castlecore.uk/castell-prysor-ruins-2.jpg","https://img.castlecore.uk/castell-prysor-ruins-3.jpg","https://img.castlecore.uk/castell-prysor-ruins-4.jpg","https://img.castlecore.uk/castell-prysor-ruins-5.jpg"],"history":"A native Welsh castle in the remote uplands of Gwynedd, near Trawsfynydd. Built in the early 13th century, possibly by Llywelyn ab Iorwerth (Llywelyn the Great). One of the few castles built by the Welsh princes rather than the Norman or English invaders. Very little remains above ground.","sources":[]},{"name":"Castell Carndochan","lat":52.828,"lng":-3.748,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A wild and windswept native Welsh castle ruin above Llanuwchllyn, clinging to a crag above the head of Bala Lake—one of the last princely strongholds in Gwynedd.","image":"https://img.castlecore.uk/castell-carndochan.jpg","rating":3.5,"reviewCount":60,"county":"Gwynedd","tags":["hilltop","ruins-romantic","remote","free-entry","atmospheric"],"access":"free","_index":1314,"gallery":["https://img.castlecore.uk/castell-carndochan-2.jpg","https://img.castlecore.uk/castell-carndochan-3.jpg","https://img.castlecore.uk/castell-carndochan-4.jpg","https://img.castlecore.uk/castell-carndochan-5.jpg","https://img.castlecore.uk/castell-carndochan-ruins-2.jpg","https://img.castlecore.uk/castell-carndochan-ruins-3.jpg","https://img.castlecore.uk/castell-carndochan-ruins-4.jpg","https://img.castlecore.uk/castell-carndochan-ruins-5.jpg"],"history":"A native Welsh castle built by the princes of Gwynedd in the 13th century, perched on a rocky crag above Llyn Tegid (Bala Lake) near Llanuwchllyn. It was one of the castles of Llywelyn ab Iorwerth (Llywelyn the Great). Archaeological work has revealed more substantial remains than previously thought. The remote and dramatic setting offers panoramic views of the Aran mountains and lake.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"},{"name":"Castles of Wales","url":"https://www.castlesofwales.com/carndochan.html"}]},{"name":"Margam Castle","lat":51.558,"lng":-3.728,"country":"Wales","type":"castle","era":"19th century (site: 4,000 years)","condition":"ruin","description":"A magnificent Tudor-Gothic mansion of honey-gold sandstone set in 850 acres of parkland, where a Cistercian abbey, an Iron Age hillfort, and a ghostly reputation collide.","image":"https://img.castlecore.uk/margam-castle.jpg","rating":3.5,"reviewCount":30,"county":"Neath Port Talbot","tags":["gothic","victorian","gardens","haunted","kid-friendly","photogenic","filming-location"],"access":"paid","_index":1349,"gallery":["https://img.castlecore.uk/margam-castle-2.jpg","https://img.castlecore.uk/margam-castle-3.jpg","https://img.castlecore.uk/margam-castle-4.jpg","https://img.castlecore.uk/margam-castle-5.jpg"],"history":"Designed by Thomas Hopper for Christopher Rice Mansel Talbot and built 1830-1835 in Tudor Revival style at a cost of £50,000. The site has 4,000 years of human occupation including an Iron Age hillfort and the adjacent 12th-century Margam Abbey. The castle suffered a devastating fire in 1977 and has been partially restored. Set within Margam Country Park, it is reputedly one of the most haunted buildings in Wales.","sources":[{"name":"Wikipedia – Margam Castle","url":"https://en.wikipedia.org/wiki/Margam_Castle"},{"name":"Margam Country Park","url":"http://www.margamcountrypark.co.uk/1242"},{"name":"Britain Express","url":"https://www.britainexpress.com/attractions.htm?attraction=671"}]},{"name":"Lamphey Bishop's Palace","lat":51.668,"lng":-4.858,"country":"Wales","type":"palace","era":"13th-14th century","condition":"ruin","description":"A medieval bishops' retreat with fishponds, orchards, and deer parks — where the powerful Bishops of St David's lived in luxury behind arcaded parapets in the green heart of Pembrokeshire.","image":"https://img.castlecore.uk/lamphey-bishop-s-palace.jpg","rating":4.2,"reviewCount":800,"county":"Pembrokeshire","tags":["ruins-romantic","gardens","atmospheric","medieval","free-entry","photogenic"],"access":"paid","_index":1351,"gallery":["https://img.castlecore.uk/lamphey-bishop-s-palace-2.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-3.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-4.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-5.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-ruins-2.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-ruins-3.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-ruins-4.jpg","https://img.castlecore.uk/lamphey-bishop-s-palace-ruins-5.jpg"],"history":"Largely constructed under Bishop Henry de Gower (1328-1347) as a lavish retreat for the Bishops of St David's. Originally had over 20 rooms with fishponds, orchards, herb gardens, and parkland with grazing deer. Surrendered to the crown in 1546 during Henry VIII's reign. Now a Grade I listed ruin managed by Cadw.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Lamphey_Bishop%27s_Palace"},{"name":"Cadw","url":"http://cadw.gov.wales/daysout/lampheybishopspalace/"}]},{"name":"Dinas Bran Keep","lat":52.978,"lng":-3.168,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"The iconic silhouette of a ruined Welsh castle crowning a conical hill above Llangollen—a breathless climb rewarded with one of the finest panoramas in all of Wales.","image":"https://img.castlecore.uk/dinas-bran-keep.jpg","rating":3.9,"reviewCount":88,"county":"Denbighshire","tags":["hilltop","ruins-romantic","photogenic","atmospheric","free-entry","medieval"],"access":"free","_index":1404,"gallery":["https://img.castlecore.uk/dinas-bran-keep-2.jpg","https://img.castlecore.uk/dinas-bran-keep-3.jpg","https://img.castlecore.uk/dinas-bran-keep-4.jpg","https://img.castlecore.uk/dinas-bran-keep-5.jpg"],"history":"Built in the 1260s by Gruffydd Maelor II, prince of Powys Fadog, on the site of an earlier Iron Age hillfort. The castle was briefly besieged by English forces in 1277 and may have been deliberately slighted by the Welsh themselves. Despite its short active life, the dramatic ruins inspired Romantic poets and artists. The hill rises 1,000 feet above the Dee valley, offering views to the Berwyn Mountains.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/castell-dinas-bran"},{"name":"Wikipedia – Castell Dinas Brân","url":"https://en.wikipedia.org/wiki/Castell_Dinas_Br%C3%A2n"}]},{"name":"Llanthony Priory","lat":51.9472,"lng":-3.0358,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"Ethereal Augustinian ruins rising from the floor of the Vale of Ewyas — pointed arches frame misty Black Mountains, and a tiny pub hides in the vaulted undercroft.","image":"https://img.castlecore.uk/llanthony-priory.jpg","rating":4.6,"reviewCount":2100,"county":"Monmouthshire","tags":["ruins-romantic","atmospheric","photogenic","norman","medieval","remote","tearoom-cafe","dog-friendly","free-entry"],"access":"free","_index":1474,"gallery":["https://img.castlecore.uk/llanthony-priory-2.jpg","https://img.castlecore.uk/llanthony-priory-3.jpg","https://img.castlecore.uk/llanthony-priory-4.jpg","https://img.castlecore.uk/llanthony-priory-5.jpg"],"history":"Founded c.1100 when Norman knight William de Lacy was inspired by an existing chapel to devote himself to prayer. By 1118, about 40 Augustinian canons established the first priory of its kind in Wales. Welsh attacks in 1135 forced retreat to Gloucester. Rebuilt and flourished before dissolution in 1538. Now managed by Cadw; remarkably, a hotel and pub occupy part of the ruins.","youtube":[],"sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/llanthony-priory"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Llanthony_Priory"},{"name":"Visit Monmouthshire","url":"https://www.visitmonmouthshire.com/things-to-do/llanthony-priory-cadw-p1503171"}]},{"name":"Cwmhir Abbey","lat":52.3197,"lng":-3.3911,"country":"Wales","type":"abbey","era":"12th-13th century","condition":"ruin","description":"The evocative ruins of what would have been the largest Cistercian church in Wales, hidden in a remote valley where Llywelyn ap Gruffudd may lie in an unmarked grave.","image":"https://img.castlecore.uk/cwmhir-abbey.jpg","rating":4.1,"reviewCount":450,"county":"Powys","tags":["ruins-romantic","atmospheric","remote","medieval","free-entry","woodland"],"access":"free","_index":1475,"gallery":["https://img.castlecore.uk/cwmhir-abbey-2.jpg","https://img.castlecore.uk/cwmhir-abbey-ruins-2.jpg","https://img.castlecore.uk/cwmhir-abbey-ruins-3.jpg","https://img.castlecore.uk/cwmhir-abbey-ruins-4.jpg","https://img.castlecore.uk/cwmhir-abbey-ruins-5.jpg"],"history":"Founded in 1176 by Cadwallon ap Madog, prince of Maelienydd, for the Cistercian order. Had it been completed, the nave at 242 feet would have been the longest in Wales. The abbey was repeatedly damaged during the Welsh wars. Tradition holds that the body of Llywelyn ap Gruffudd, the last native Prince of Wales, was brought here for burial after his death in 1282. The ruins slumber in the peaceful Clywedog valley.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/abbey-cwmhir"},{"name":"Wikipedia – Abbey Cwmhir","url":"https://en.wikipedia.org/wiki/Abbey_Cwmhir"}]},{"name":"Llanblethian Castle","lat":51.4597,"lng":-3.4347,"country":"Wales","type":"castle","era":"13th-14th century","condition":"ruin","description":"A substantial ruined gatehouse looming above the village of Llanblethian in the Vale of Glamorgan—the imposing remnant of a medieval stronghold known as St Quintins Castle.","image":"https://img.castlecore.uk/llanblethian-castle.jpg","rating":3.8,"reviewCount":180,"county":"Vale of Glamorgan","tags":["ruins-romantic","medieval","free-entry"],"access":"free","_index":1476,"gallery":["https://img.castlecore.uk/llanblethian-castle-2.jpg","https://img.castlecore.uk/llanblethian-castle-3.jpg","https://img.castlecore.uk/llanblethian-castle-4.jpg","https://img.castlecore.uk/llanblethian-castle-5.jpg"],"history":"Also known as St Quintins Castle, it was built by the de St Quintin family in the 13th century. The impressive twin-towered gatehouse, dating to c.1307, is the main surviving structure and is one of the finest of its type in Glamorgan. The castle overlooks the village and the River Thaw valley near Cowbridge. It fell into ruin after the medieval period.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/llanblethian-castle"},{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Candleston Castle","lat":51.4889,"lng":-3.7264,"country":"Wales","type":"castle","era":"14th century","condition":"ruin","description":"A haunting fortified manor house half-buried in sand dunes at Merthyr Mawr, where the advancing sands of the South Wales coast slowly swallowed a medieval settlement.","image":"https://img.castlecore.uk/candleston-castle.jpg","rating":3.7,"reviewCount":320,"county":"Bridgend","tags":["ruins-romantic","atmospheric","coastal","free-entry","medieval","remote"],"access":"free","_index":1477,"gallery":["https://img.castlecore.uk/candleston-castle-2.jpg","https://img.castlecore.uk/candleston-castle-3.jpg","https://img.castlecore.uk/candleston-castle-4.jpg","https://img.castlecore.uk/candleston-castle-5.jpg"],"history":"A 14th-century fortified manor house built by the de Cantilupe family, later held by the Cantelupes (hence Candleston). Located at Merthyr Mawr Warren near Bridgend, the ruins are gradually being engulfed by one of the largest sand dune systems in Europe. The advancing sand also buried the medieval village and church. The atmospheric ruins stand amid marram grass and dunes, accessible by woodland paths.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/candleston-castle"},{"name":"Wikipedia – Candleston Castle","url":"https://en.wikipedia.org/wiki/Candleston_Castle"}]},{"name":"Llandaff Cathedral","lat":51.4958,"lng":-3.2181,"country":"Wales","type":"abbey","era":"12th century","condition":"intact","description":"One of Britain's oldest Christian sites, nestled in a hollow by the River Taff — where Celtic saints once gathered and Epstein's towering Christ still stuns.","image":"https://img.castlecore.uk/llandaff-cathedral.jpg","rating":4.5,"reviewCount":2800,"county":"Cardiff","tags":["well-preserved","atmospheric","medieval","free-entry"],"access":"free","_index":1478,"gallery":["https://img.castlecore.uk/llandaff-cathedral-2.jpg","https://img.castlecore.uk/llandaff-cathedral-3.jpg","https://img.castlecore.uk/llandaff-cathedral-4.jpg","https://img.castlecore.uk/llandaff-cathedral-5.jpg"],"history":"Stands on one of the oldest Christian sites in Britain, founded in the 6th century by St Dyfrig, succeeded by St Teilo and St Euddogwy. The current building dates from c.1120, with restorations after severe damage from a German parachute mine in January 1941 during the Cardiff Blitz. Features Jacob Epstein's striking aluminium sculpture 'Christ in Majesty'.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Llandaff_Cathedral"},{"name":"Visit Cardiff","url":"https://www.visitcardiff.com/highlights/llandaff-cathedral/"}]},{"name":"Nanteos Mansion","lat":52.3667,"lng":-3.8833,"country":"Wales","type":"historic-house","era":"18th century","condition":"restored","description":"A Georgian mansion near Aberystwyth steeped in legends of the Holy Grail—the Nanteos Cup was long revered as the sacred vessel, drawing pilgrims seeking miraculous cures.","image":"https://img.castlecore.uk/nanteos-mansion.jpg","rating":4,"reviewCount":650,"county":"Ceredigion","tags":["atmospheric","gardens"],"access":"paid","_index":1479,"gallery":["https://img.castlecore.uk/nanteos-mansion-2.jpg","https://img.castlecore.uk/nanteos-mansion-3.jpg","https://img.castlecore.uk/nanteos-mansion-4.jpg","https://img.castlecore.uk/nanteos-mansion-5.jpg"],"history":"An 18th-century Georgian mansion built by the Powell family c.1739 near Aberystwyth, Ceredigion. The house was famous for the Nanteos Cup, a medieval mazer bowl long claimed to be the Holy Grail, brought here by monks fleeing the Dissolution. The cup was believed to have healing powers. The mansion is now a luxury hotel. Composer George Powell and writer Thomas Love Peacock had connections to the estate.","sources":[{"name":"Wikipedia – Nanteos Mansion","url":"https://en.wikipedia.org/wiki/Nanteos_Mansion"}]},{"name":"Castell Dinas","lat":51.9522,"lng":-3.1578,"country":"Wales","type":"castle","era":"Iron Age / 12th century","condition":"ruin","description":"The highest castle in England and Wales, perched at 1,476 feet on a Brecon Beacons hilltop—a brooding Iron Age and medieval fortress commanding views across an oceanic landscape of mountains.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/b7/Castell_Dinas_from_the_air.jpg/500px-Castell_Dinas_from_the_air.jpg","rating":4.2,"reviewCount":380,"county":"Powys","tags":["hilltop","prehistoric","ruins-romantic","free-entry","remote","atmospheric"],"access":"free","_index":1480,"gallery":["https://img.castlecore.uk/castell-dinas-2.jpg","https://img.castlecore.uk/castell-dinas-3.jpg","https://img.castlecore.uk/castell-dinas-4.jpg","https://img.castlecore.uk/castell-dinas-5.jpg"],"history":"An Iron Age hillfort and medieval castle at 1,476 feet (450m) in the Black Mountains near Talgarth, Powys. The Norman castle was built within the earlier hillfort by the Fitz Herbert family in the 12th century. It was attacked during the Welsh wars and later by Owain Glyndŵr. As the highest castle site in England and Wales, it offers extraordinary panoramic views across the Brecon Beacons and beyond.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/castell-dinas"},{"name":"Wikipedia – Castell Dinas, Talgarth","url":"https://en.wikipedia.org/wiki/Castell_Dinas,_Talgarth"}]},{"name":"Garn Goch","lat":51.8833,"lng":-3.7833,"country":"Wales","type":"hillfort","era":"Iron Age (c.800-100 BC)","condition":"ruin","description":"One of the largest and most impressive Iron Age hillforts in Wales, its vast stone ramparts sprawling across twin summits above the upper Tywi valley like a fortress built by giants.","image":"https://img.castlecore.uk/wiki-garn-goch.jpg","rating":4.1,"reviewCount":210,"county":"Carmarthenshire","tags":["prehistoric","hilltop","free-entry","remote","atmospheric","photogenic"],"access":"free","_index":1481,"gallery":["https://img.castlecore.uk/wiki-garn-goch.jpg"],"history":"A massive Iron Age hillfort complex near Bethlehem village in Carmarthenshire, comprising two enclosures—Y Gaer Fawr (the Great Fort) and Y Gaer Fach (the Small Fort). The Great Fort covers 28 acres, making it one of the largest prehistoric enclosures in southern Britain. The stone-built ramparts are still impressive, rising to several metres in places. Dating is uncertain but likely Late Bronze Age to Iron Age (c.800-100 BC).","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk/en/site/302673"},{"name":"Wikipedia – Garn Goch","url":"https://en.wikipedia.org/wiki/Garn_Goch"}]},{"name":"Dunraven Castle","lat":51.4486,"lng":-3.6081,"country":"Wales","type":"castle","era":"19th century (site: Iron Age)","condition":"ruin","description":"Once a grand Victorian mansion on dramatic cliffs above Southerndown Beach, now demolished—but the walled gardens and stunning Glamorgan Heritage Coast remain breathtaking.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/8/8c/Dunraven_Castle_%2816567797823%29.jpg/500px-Dunraven_Castle_%2816567797823%29.jpg","rating":3.9,"reviewCount":520,"county":"Vale of Glamorgan","tags":["gardens","coastal","cliffside","photogenic","free-entry"],"access":"free","_index":1482,"gallery":["https://img.castlecore.uk/dunraven-castle-2.jpg","https://img.castlecore.uk/dunraven-castle-3.jpg","https://img.castlecore.uk/dunraven-castle-4.jpg","https://img.castlecore.uk/dunraven-castle-5.jpg"],"history":"The Dunraven estate on the Glamorgan Heritage Coast has ancient roots, with an Iron Age promontory fort on the headland. The Vaughan family built a mansion here, enlarged in the 19th century by the Earls of Dunraven. The castle was demolished in 1963 after years of decline, but the walled gardens have been restored. The dramatic limestone cliffs and beach below are a popular destination.","sources":[{"name":"Wikipedia – Dunraven Castle","url":"https://en.wikipedia.org/wiki/Dunraven_Castle"},{"name":"Vale of Glamorgan Council","url":"https://www.valeofglamorgan.gov.uk/en/enjoying/Heritage-Coast/Dunraven.aspx"}]},{"name":"Caerau Hillfort","lat":51.4667,"lng":-3.2417,"country":"Wales","type":"hillfort","era":"Iron Age / Roman / medieval","condition":"earthwork","description":"A vast Iron Age hillfort hidden in plain sight on a Cardiff housing estate—one of the largest prehistoric forts in Wales, with community archaeology revealing Roman and medieval treasures.","image":"https://img.castlecore.uk/caerau-hillfort.jpg","rating":3.6,"reviewCount":150,"county":"Cardiff","tags":["prehistoric","hilltop","free-entry"],"access":"free","_index":1483,"gallery":["https://img.castlecore.uk/caerau-hillfort-2.jpg","https://img.castlecore.uk/caerau-hillfort-3.jpg","https://img.castlecore.uk/caerau-hillfort-4.jpg","https://img.castlecore.uk/caerau-hillfort-5.jpg"],"history":"One of the largest Iron Age hillforts in Wales, covering about 5 hectares on a ridge in the Ely district of Cardiff. The CAER Heritage Project's community excavations from 2011 revealed Iron Age roundhouses, Roman structures, and a medieval ringwork. Despite its suburban setting, the earthworks are substantial and well-preserved, offering views across Cardiff to the Bristol Channel.","sources":[{"name":"CAER Heritage Project","url":"https://caerheritageproject.com/"},{"name":"Wikipedia – Caerau Hillfort","url":"https://en.wikipedia.org/wiki/Caerau_hillfort"}]},{"name":"Old Beaupre Castle","lat":51.4497,"lng":-3.4508,"country":"Wales","type":"castle","era":"13th-16th century","condition":"ruin","description":"A Tudor mansion of exquisite Renaissance detailing hidden in a quiet Vale of Glamorgan valley—its elaborate porch is one of the finest pieces of Elizabethan architecture in Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/4/48/Old_Beaupre_Castle_-_geograph.org.uk_-_2764686.jpg/500px-Old_Beaupre_Castle_-_geograph.org.uk_-_2764686.jpg","rating":4.2,"reviewCount":480,"county":"Vale of Glamorgan","tags":["ruins-romantic","tudor","photogenic","free-entry","atmospheric"],"access":"free","_index":1484,"gallery":["https://img.castlecore.uk/old-beaupre-castle-2.jpg","https://img.castlecore.uk/old-beaupre-castle-3.jpg","https://img.castlecore.uk/old-beaupre-castle-4.jpg","https://img.castlecore.uk/old-beaupre-castle-5.jpg"],"history":"A medieval and Tudor manor house near St Hilary in the Vale of Glamorgan. The earliest parts date from the 13th century, but the house was transformed by the Bassett family in the late 16th century. The magnificent Renaissance porch of c.1600, with its classical columns and elaborate carvings, is one of the finest examples of Elizabethan architecture in Wales. Managed by Cadw.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/old-beaupre-castle"},{"name":"Wikipedia – Old Beaupre Castle","url":"https://en.wikipedia.org/wiki/Old_Beaupre_Castle"}]},{"name":"St Donat's Castle","lat":51.4028,"lng":-3.5611,"country":"Wales","type":"castle","era":"12th century onwards","condition":"intact","description":"A remarkably intact medieval castle on the Glamorgan coast, bought in 1925 by press baron William Randolph Hearst and now home to Atlantic College, the world's first United World College.","image":"https://img.castlecore.uk/st-donat-s-castle.jpg","rating":4.3,"reviewCount":750,"county":"Vale of Glamorgan","tags":["well-preserved","medieval","coastal","gardens","events-venue"],"access":"exterior-only","_index":1485,"gallery":["https://img.castlecore.uk/st-donat-s-castle-2.jpg","https://img.castlecore.uk/st-donat-s-castle-3.jpg","https://img.castlecore.uk/st-donat-s-castle-4.jpg","https://img.castlecore.uk/st-donat-s-castle-5.jpg"],"history":"A medieval castle with 12th-century origins, continuously inhabited and one of the best-preserved castles in Wales. William Randolph Hearst bought it in 1925 and lavishly restored it, importing medieval woodwork and fireplaces from across Europe. Since 1962 it has been home to Atlantic College (UWC Atlantic), the pioneering international school. The castle includes a medieval tithe barn, Tudor gardens, and Arts Centre.","sources":[{"name":"Wikipedia – St Donat's Castle","url":"https://en.wikipedia.org/wiki/St_Donat%27s_Castle"},{"name":"Atlantic College","url":"https://www.atlanticcollege.org/"}]},{"name":"Sully Island Fort","lat":51.395,"lng":-3.195,"country":"Wales","type":"fort","era":"Medieval / Iron Age","condition":"ruin","description":"A tidal island in the Bristol Channel accessible at low tide, where the remains of a medieval fortification and tales of shipwrecks add danger and drama to a coastal walk.","image":"https://img.castlecore.uk/sully-island-fort.jpg","rating":3.5,"reviewCount":280,"county":"Vale of Glamorgan","tags":["island","coastal","free-entry","remote","atmospheric"],"access":"free","_index":1486,"gallery":["https://img.castlecore.uk/sully-island-fort-2.jpg","https://img.castlecore.uk/sully-island-fort-3.jpg","https://img.castlecore.uk/sully-island-fort-4.jpg","https://img.castlecore.uk/sully-island-fort-5.jpg"],"history":"A small tidal island off the coast of Sully in the Vale of Glamorgan, accessible via a rocky causeway at low tide. The island has remains of a medieval fortification and was used as a lookout point. Several people have been stranded or drowned by the fast-rising Bristol Channel tides. The island offers views across the channel to Somerset and has archaeological remains from the Iron Age.","sources":[{"name":"Wikipedia – Sully Island","url":"https://en.wikipedia.org/wiki/Sully_Island"}]},{"name":"Ruperra Castle","lat":51.5611,"lng":-3.1306,"country":"Wales","type":"castle","era":"17th century","condition":"ruin","description":"A haunting Jacobean castle ruin on a wooded ridge above Caerphilly—the first castellated country house in Wales, now a roofless shell slowly being reclaimed by nature.","image":"https://img.castlecore.uk/ruperra-castle.jpg","rating":3.6,"reviewCount":190,"county":"Caerphilly","tags":["ruins-romantic","atmospheric","woodland","free-entry"],"access":"exterior-only","_index":1487,"gallery":["https://img.castlecore.uk/ruperra-castle-2.jpg","https://img.castlecore.uk/ruperra-castle-3.jpg","https://img.castlecore.uk/ruperra-castle-4.jpg","https://img.castlecore.uk/ruperra-castle-5.jpg"],"history":"Built in 1626 by Sir Thomas Morgan, a soldier who fought at the Battle of Cadiz. It was the first known castellated mansion in Glamorgan, with corner towers and battlements. Used by the military in WWII, it was gutted by fire in 1941 and never restored. The Grade II* listed ruin stands in overgrown grounds on a ridge overlooking the Rhymney valley, subject to ongoing conservation campaigns.","sources":[{"name":"Wikipedia – Ruperra Castle","url":"https://en.wikipedia.org/wiki/Ruperra_Castle"},{"name":"Ruperra Castle Preservation Trust","url":"https://www.ruperracastle.org/"}]},{"name":"Morlais Castle","lat":51.7828,"lng":-3.3778,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"Vast and sprawling castle ruins on a windswept Brecon Beacons hilltop above Merthyr Tydfil—a hugely ambitious Marcher fortress that sparked a war between two English lords.","image":"https://img.castlecore.uk/morlais-castle.jpg","rating":4,"reviewCount":350,"county":"Merthyr Tydfil","tags":["hilltop","ruins-romantic","free-entry","atmospheric","medieval","remote"],"access":"free","_index":1488,"gallery":["https://img.castlecore.uk/morlais-castle-2.jpg","https://img.castlecore.uk/morlais-castle-3.jpg","https://img.castlecore.uk/morlais-castle-4.jpg","https://img.castlecore.uk/morlais-castle-5.jpg"],"history":"Built c.1287-1290 by Gilbert de Clare, 6th Earl of Gloucester, on disputed common land above Merthyr Tydfil. The massive castle, with its multiple round towers, was never completed. It provoked a bitter dispute with Humphrey de Bohun, Earl of Hereford, escalating into armed conflict that Edward I had to resolve. The extensive ruins command dramatic views across the Brecon Beacons and Valleys.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/morlais-castle"},{"name":"Wikipedia – Morlais Castle","url":"https://en.wikipedia.org/wiki/Morlais_Castle"}]},{"name":"Castell Morgraig","lat":51.5194,"lng":-3.2083,"country":"Wales","type":"castle","era":"13th century","condition":"ruin","description":"A mysterious and rarely visited native Welsh castle ruin on a wooded ridge north of Cardiff—possibly the last fortress built by the Welsh lords of Senghenydd before their defeat.","image":"https://img.castlecore.uk/castell-morgraig.jpg","rating":3.7,"reviewCount":120,"county":"Cardiff","tags":["ruins-romantic","woodland","remote","free-entry","medieval"],"access":"free","_index":1489,"gallery":["https://img.castlecore.uk/castell-morgraig-2.jpg","https://img.castlecore.uk/castell-morgraig-3.jpg","https://img.castlecore.uk/castell-morgraig-4.jpg","https://img.castlecore.uk/castell-morgraig-5.jpg"],"history":"A native Welsh castle on a ridge in the hills north of Cardiff, likely built by the Welsh lords of Senghenydd in the mid-13th century, shortly before their territory was conquered by Gilbert de Clare. The castle may have been unfinished when it was abandoned. The remote ruins include fragments of round towers in a style influenced by English castle design. Reached by a woodland walk from Caerphilly.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"},{"name":"Wikipedia – Castell Morgraig","url":"https://en.wikipedia.org/wiki/Castell_Morgraig"}]},{"name":"St Fagans Castle","lat":51.4872,"lng":-3.2742,"country":"Wales","type":"castle","era":"16th century","condition":"restored","description":"An Elizabethan mansion risen from Norman ruins, now the jewel of Wales's open-air museum — where centuries of Welsh life unfold across the grounds.","image":"https://img.castlecore.uk/st-fagans-castle.jpg","rating":4.5,"reviewCount":3500,"county":"Cardiff","tags":["well-preserved","museum","gardens","free-entry","kid-friendly","photogenic"],"access":"free","_index":1490,"gallery":["https://img.castlecore.uk/st-fagans-castle-2.jpg","https://img.castlecore.uk/st-fagans-castle-3.jpg","https://img.castlecore.uk/st-fagans-castle-4.jpg","https://img.castlecore.uk/st-fagans-castle-5.jpg"],"history":"Built c.1580 on the ruins of a Norman motte and bailey castle, this Grade I listed Elizabethan mansion was constructed in an E-shape. The grounds now house St Fagans National Museum of History, with over 40 re-erected historic buildings chronicling Welsh culture and architecture. Free entry, managed by Amgueddfa Cymru.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/St_Fagans_Castle"},{"name":"Museum Wales","url":"https://museum.wales/stfagans/buildings/castle/"}]},{"name":"Penrice Castle","lat":51.5778,"lng":-4.1361,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"A picturesque Norman castle ruin in the grounds of a Georgian mansion on the Gower Peninsula—set in some of the most beautiful parkland in South Wales.","image":"https://img.castlecore.uk/penrice-castle.jpg","rating":3.9,"reviewCount":280,"county":"Swansea","tags":["ruins-romantic","norman","gardens","coastal"],"access":"exterior-only","_index":1492,"gallery":["https://img.castlecore.uk/penrice-castle-2.jpg","https://img.castlecore.uk/penrice-castle-3.jpg","https://img.castlecore.uk/penrice-castle-4.jpg","https://img.castlecore.uk/penrice-castle-5.jpg"],"history":"A Norman castle on the Gower Peninsula near Oxwich, built in the 12th century by the de Penrice family. The castle was extended with a strong curtain wall and round tower in the 13th century. It was abandoned when the adjacent Penrice House was built in the 18th century. The ruins stand in the grounds of the estate, amid rolling parkland with views towards Oxwich Bay and Three Cliffs Bay.","sources":[{"name":"Wikipedia – Penrice Castle","url":"https://en.wikipedia.org/wiki/Penrice_Castle"},{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Cefn Bryn Arthur's Stone","lat":51.5917,"lng":-4.1778,"country":"Wales","type":"monument","era":"Neolithic (c.2500 BC)","condition":"intact","description":"A 25-ton Neolithic capstone on Gower's windswept ridge, where legend says King Arthur hurled a pebble from Carmarthen that grew into this massive boulder on landing.","image":"https://img.castlecore.uk/cefn-bryn-arthur-s-stone.jpg","rating":4.3,"reviewCount":950,"county":"Swansea","tags":["prehistoric","hilltop","free-entry","photogenic","remote"],"access":"free","_index":1493,"gallery":["https://img.castlecore.uk/cefn-bryn-arthur-s-stone-2.jpg","https://img.castlecore.uk/cefn-bryn-arthur-s-stone-3.jpg","https://img.castlecore.uk/cefn-bryn-arthur-s-stone-4.jpg","https://img.castlecore.uk/cefn-bryn-arthur-s-stone-5.jpg"],"history":"A Neolithic burial chamber (dolmen) dating to c.2500 BC on the ridge of Cefn Bryn, the spine of the Gower Peninsula. The enormous capstone weighs approximately 25 tons and rests on several smaller stones. Arthurian legend claims Arthur threw a stone from Carmarthen that landed here. The site commands panoramic views across Gower to the sea. One of over 100 megalithic tombs in the Swansea area.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/arthurs-stone"},{"name":"Wikipedia – Arthur's Stone, Gower","url":"https://en.wikipedia.org/wiki/Arthur%27s_Stone,_Cefn_Bryn"}]},{"name":"Llanmelin Wood Hillfort","lat":51.62,"lng":-2.75,"country":"Wales","type":"hillfort","era":"Iron Age (c.500 BC - 1st century AD)","condition":"earthwork","description":"A substantial Iron Age hillfort hidden in woodland near Caerwent, likely the tribal capital of the Silures—the fierce Celtic people who resisted Rome for decades.","image":"https://img.castlecore.uk/llanmelin-wood-hillfort.jpg","rating":3.8,"reviewCount":140,"county":"Monmouthshire","tags":["prehistoric","woodland","free-entry","hilltop"],"access":"free","_index":1494,"gallery":["https://img.castlecore.uk/llanmelin-wood-hillfort-2.jpg","https://img.castlecore.uk/llanmelin-wood-hillfort-3.jpg","https://img.castlecore.uk/llanmelin-wood-hillfort-4.jpg","https://img.castlecore.uk/llanmelin-wood-hillfort-5.jpg"],"history":"A large multivallate Iron Age hillfort near Caerwent in Monmouthshire, possibly the oppidum (tribal capital) of the Silures, the Celtic tribe that fiercely resisted the Roman conquest of Wales. The site has multiple defensive banks and ditches enclosing about 5 acres. After the Roman conquest, the nearby town of Venta Silurum (Caerwent) was established. Managed by Cadw.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/llanmelin-wood-hillfort"},{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Caerwent Roman Town","lat":51.6111,"lng":-2.7694,"country":"Wales","type":"fort","era":"Roman (1st-5th century)","condition":"ruin","description":"The best-preserved Roman town walls in Britain — a miniature Rome where the fierce Silures tribe settled into civilised life with temples, baths, and central heating.","image":"https://img.castlecore.uk/caerwent-roman-town.jpg","rating":4.3,"reviewCount":1100,"county":"Monmouthshire","tags":["well-preserved","atmospheric","prehistoric","free-entry","dog-friendly"],"access":"free","_index":1495,"gallery":["https://img.castlecore.uk/caerwent-roman-town-2.jpg","https://img.castlecore.uk/caerwent-roman-town-3.jpg","https://img.castlecore.uk/caerwent-roman-town-4.jpg","https://img.castlecore.uk/caerwent-roman-town-5.jpg"],"history":"Founded as Venta Silurum, the market town of the Silures — the fierce Celtic tribe that resisted Roman conquest for decades. The town walls, standing up to 5 metres high, are the best-preserved in Britain. Within the walls stood a forum, basilica, temple, baths, and private houses with hypocaust heating. A purely civilian settlement with no military garrison. Managed by Cadw.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Caerwent"},{"name":"Britain Express","url":"https://www.britainexpress.com/attractions.htm?attraction=810"}]},{"name":"Caerleon Amphitheatre","lat":51.6131,"lng":-2.9528,"country":"Wales","type":"fort","era":"1st century Roman","condition":"ruin","description":"The best-preserved Roman amphitheatre in Britain — once thundering with the roar of 6,000 legionaries, now a grassy bowl of silence where you can almost hear the echoes of gladiators.","image":"https://img.castlecore.uk/caerleon-amphitheatre.jpg","rating":4.4,"reviewCount":1800,"county":"Newport","tags":["prehistoric","atmospheric","free-entry","photogenic","kid-friendly","dog-friendly"],"access":"free","_index":1497,"gallery":["https://img.castlecore.uk/caerleon-amphitheatre-2.jpg","https://img.castlecore.uk/caerleon-amphitheatre-3.jpg","https://img.castlecore.uk/caerleon-amphitheatre-4.jpg","https://img.castlecore.uk/caerleon-amphitheatre-5.jpg"],"history":"Built c.90 AD as the amphitheatre for the Roman fortress of Isca Augusta, home of the Second Augustan Legion. Could hold 6,000 spectators watching military training, gladiatorial combat, and public events. The oval arena measures 56m x 41m. Part of the only complete set of Roman legionary buildings visible anywhere in Europe. Geoffrey of Monmouth later identified Caerleon as King Arthur's court. Managed by Cadw, free to visit.","youtube":[],"sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/caerleon-amphitheatre"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Caerleon"}]},{"name":"Tredegar House","lat":51.5597,"lng":-3.0167,"country":"Wales","type":"historic-house","era":"17th century","condition":"restored","description":"One of Britain's most important 17th-century mansions — where the powerful Morgan dynasty ruled South Wales for over 500 years.","image":"https://img.castlecore.uk/tredegar-house.jpg","rating":4.4,"reviewCount":3200,"county":"Newport","tags":["well-preserved","photogenic","gardens","museum","guided-tours","kid-friendly","tearoom-cafe"],"access":"paid","_index":1498,"gallery":["https://img.castlecore.uk/tredegar-house-2.jpg","https://img.castlecore.uk/tredegar-house-3.jpg","https://img.castlecore.uk/tredegar-house-4.jpg","https://img.castlecore.uk/tredegar-house-5.jpg"],"history":"A Charles II-era country house on the edge of Newport, Wales, home to the Morgan family (later Lords Tredegar) for over 500 years. Considered one of the finest Restoration houses in Britain. The Morgans commissioned a ship, the Tredegar of Newport, which traded with Barbados in 1676. Now managed by the National Trust.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Tredegar_House"},{"name":"National Trust","url":"https://www.nationaltrust.org.uk/visit/wales/tredegar-house/history-of-tredegar-house"}]},{"name":"Blaenavon Ironworks","lat":51.7739,"lng":-3.0872,"country":"Wales","type":"industrial","era":"18th century","condition":"ruin","description":"A UNESCO World Heritage Site where the fires of the Industrial Revolution still feel close — massive stone furnaces and workers' cottages tell the story of the iron that built the modern world.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/c2/Blaenafon_Ironworks-24May2008.jpg/500px-Blaenafon_Ironworks-24May2008.jpg","rating":4.3,"reviewCount":1500,"county":"Torfaen","tags":["atmospheric","museum","free-entry","kid-friendly","guided-tours"],"access":"free","_index":1499,"gallery":["https://img.castlecore.uk/blaenavon-ironworks-2.jpg","https://img.castlecore.uk/blaenavon-ironworks-3.jpg","https://img.castlecore.uk/blaenavon-ironworks-4.jpg","https://img.castlecore.uk/blaenavon-ironworks-5.jpg"],"history":"Built 1788-99 by Thomas Hill, Thomas Hopkins, and Benjamin Pratt as the first purpose-built multi-furnace ironworks in Wales. By 1796, it was Wales's second-largest ironworks. Site of the revolutionary Gilchrist-Thomas process (1878) which allowed cheap, high-sulphur iron ores to be used worldwide, transforming global steel production. Closed 1904. Part of the Blaenavon Industrial Landscape UNESCO World Heritage Site inscribed in 2000. Managed by Cadw.","youtube":[],"sources":[{"name":"UNESCO","url":"https://whc.unesco.org/en/list/984/"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Blaenavon_Ironworks"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/blaenavon-ironworks"}]},{"name":"Llangattock Escarpment","lat":51.825,"lng":-3.15,"country":"Wales","type":"monument","era":"Geological / 19th century industrial","condition":"natural","description":"A dramatic limestone escarpment above the Usk valley in the Brecon Beacons, honeycombed with caves and rich in industrial archaeology—a landscape of vertical drama.","image":"https://img.castlecore.uk/wiki-llangattock-escarpment.jpg","rating":4.2,"reviewCount":600,"county":"Powys","tags":["cliffside","free-entry","remote","atmospheric"],"access":"free","_index":1500,"history":"A limestone escarpment above the village of Llangattock in the Brecon Beacons National Park. The cliffs are honeycombed with caves including Agen Allwedd and Eglwys Faen, some of the longest cave systems in Britain. The area has extensive remains of 19th-century limestone quarrying and tramways. The escarpment is a Site of Special Scientific Interest and offers spectacular walking with views across the Usk valley.","sources":[{"name":"Brecon Beacons National Park","url":"https://www.breconbeacons.org/"},{"name":"Wikipedia – Llangattock","url":"https://en.wikipedia.org/wiki/Llangattock"}]},{"name":"Tretower Court","lat":51.8558,"lng":-3.2119,"country":"Wales","type":"historic-house","era":"12th-15th century","condition":"restored","description":"A medieval court and castle pair in the Brecon Beacons — where Norman invaders became Welsh lords and a striking circular tower dominates the Usk Valley skyline.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/be/Tretower_Court_-_geograph.org.uk_-_25906.jpg/500px-Tretower_Court_-_geograph.org.uk_-_25906.jpg","rating":4.3,"reviewCount":1200,"county":"Powys","tags":["well-preserved","atmospheric","medieval","norman","gardens","guided-tours"],"access":"paid","_index":1501,"gallery":["https://img.castlecore.uk/tretower-court-2.jpg","https://img.castlecore.uk/tretower-court-3.jpg","https://img.castlecore.uk/tretower-court-4.jpg","https://img.castlecore.uk/tretower-court-5.jpg"],"history":"The castle was begun c. 1100 by the Picard family, Norman adventurers who gradually became powerful Welsh lords. Roger Picard II built the distinctive circular tower that gave the place its Welsh name 'Tre-tŵr' (place of the tower). The adjacent court was the creation of Sir Roger Vaughan during the Wars of the Roses, when he became one of the most powerful men in Wales. Managed by Cadw.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Tretower_Court"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/tretower-court-and-castle"},{"name":"Visit Wales","url":"https://www.visitwales.com/attraction/castle/tretower-court-and-castle-cadw-680102"}]},{"name":"Craig y Nos Castle","lat":51.8361,"lng":-3.6861,"country":"Wales","type":"castle","era":"19th century","condition":"intact","description":"A Victorian Gothic castle in the upper Swansea Valley, once the private opera house of legendary diva Adelina Patti—where the greatest soprano of the 19th century held court in rural Wales.","image":"https://img.castlecore.uk/craig-y-nos-castle.jpg","rating":4.1,"reviewCount":900,"county":"Powys","tags":["gothic","victorian","wedding-venue","gardens","atmospheric"],"access":"paid","_index":1502,"gallery":["https://img.castlecore.uk/craig-y-nos-castle-2.jpg","https://img.castlecore.uk/craig-y-nos-castle-3.jpg","https://img.castlecore.uk/craig-y-nos-castle-4.jpg","https://img.castlecore.uk/craig-y-nos-castle-5.jpg"],"history":"A Gothic Revival castle purchased in 1878 by Adelina Patti, the world's most famous opera singer, who installed a private theatre (a miniature version of Drury Lane) and entertained royalty here. She lived at Craig y Nos until her death in 1919. The castle later served as a hospital and is now a wedding venue. The grounds became Craig y Nos Country Park, set in the beautiful Tawe valley below the Brecon Beacons.","sources":[{"name":"Wikipedia – Craig y Nos Castle","url":"https://en.wikipedia.org/wiki/Craig-y-Nos_Castle"},{"name":"Craig y Nos Castle","url":"https://www.craigynoscastle.com/"}]},{"name":"Dinefwr Park","lat":51.8667,"lng":-3.9917,"country":"Wales","type":"historic-house","era":"Iron Age to 17th century","condition":"restored","description":"An iconic Welsh landscape where 2,000 years of history unfold — from Iron Age hillfort to medieval castle to a grand Newton House amid a rare parkland nature reserve.","image":"https://img.castlecore.uk/dinefwr-park.jpg","rating":4.4,"reviewCount":2200,"county":"Carmarthenshire","tags":["atmospheric","photogenic","gardens","woodland","medieval","prehistoric","kid-friendly"],"access":"paid","_index":1504,"gallery":["https://img.castlecore.uk/dinefwr-park-2.jpg","https://img.castlecore.uk/dinefwr-park-3.jpg","https://img.castlecore.uk/dinefwr-park-4.jpg","https://img.castlecore.uk/dinefwr-park-5.jpg"],"history":"The park has been in use for over 2,000 years, with remains of an Iron Age fort and two Roman forts discovered on site. Dinefwr Castle, perched on a hilltop, was the principal seat of the rulers of Deheubarth. Newton House, the 17th-century mansion at the estate's heart, is surrounded by a National Nature Reserve — the only parkland NNR in Wales. Managed by the National Trust.","sources":[{"name":"National Trust","url":"https://www.nationaltrust.org.uk/visit/wales/dinefwr"},{"name":"Britain Express","url":"https://www.britainexpress.com/attractions.htm?attraction=721"}]},{"name":"Paxton's Tower","lat":51.8528,"lng":-4.0361,"country":"Wales","type":"monument","era":"19th century","condition":"ruin","description":"A dramatic triangular folly tower on a Carmarthenshire hilltop, built to honour Lord Nelson and offering one of the finest views in all of Wales across the Tywi valley.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/b/bc/Paxton_Tower.jpg/500px-Paxton_Tower.jpg","rating":4.2,"reviewCount":800,"county":"Carmarthenshire","tags":["hilltop","photogenic","free-entry","gothic"],"access":"free","_index":1505,"gallery":["https://img.castlecore.uk/paxton-s-tower-2.jpg","https://img.castlecore.uk/paxton-s-tower-3.jpg","https://img.castlecore.uk/paxton-s-tower-4.jpg","https://img.castlecore.uk/paxton-s-tower-5.jpg"],"history":"A Gothic triangular tower built in 1806-1809 by Sir William Paxton to honour Lord Nelson after Trafalgar. Standing on a prominent hilltop near Llanarthne, it offers panoramic views across the Tywi valley to the Black Mountain. Paxton was a wealthy London banker who also funded the National Botanic Garden of Wales on his former estate below. Managed by the National Trust.","sources":[{"name":"National Trust – Paxton's Tower","url":"https://www.nationaltrust.org.uk/visit/wales/paxtons-tower"},{"name":"Wikipedia – Paxton's Tower","url":"https://en.wikipedia.org/wiki/Paxton%27s_Tower"}]},{"name":"Dryslwyn Castle Viewpoint","lat":51.8611,"lng":-4.0361,"country":"Wales","type":"castle","era":"N/A (viewpoint)","condition":"ruin","description":"A companion viewpoint to the hilltop castle ruins across the Tywi valley—a place to absorb the full majesty of this quintessential Welsh landscape of river, castle, and rolling green hills.","image":"https://img.castlecore.uk/dryslwyn-castle-viewpoint.jpg","rating":4.1,"reviewCount":500,"county":"Carmarthenshire","tags":["photogenic","free-entry","riverside"],"access":"free","_index":1507,"gallery":["https://img.castlecore.uk/dryslwyn-castle-viewpoint-2.jpg","https://img.castlecore.uk/dryslwyn-castle-viewpoint-3.jpg","https://img.castlecore.uk/dryslwyn-castle-viewpoint-4.jpg","https://img.castlecore.uk/dryslwyn-castle-viewpoint-5.jpg"],"history":"A viewpoint overlooking Dryslwyn Castle across the Tywi valley in Carmarthenshire. The view encompasses one of the most celebrated landscapes in Wales: the meandering River Tywi, the castle-crowned hill, and the patchwork of green fields stretching to the Black Mountain. The area has been painted by Turner and countless other artists captivated by its pastoral beauty.","sources":[{"name":"Visit Carmarthenshire","url":"https://www.discovercarmarthenshire.com/"}]},{"name":"Whitland Abbey","lat":51.8167,"lng":-4.6139,"country":"Wales","type":"abbey","era":"12th century","condition":"ruin","description":"Faint stone foundations in a peaceful Carmarthenshire meadow mark the site of the mother house of the Cistercian order in Wales—birthplace of Welsh monastic culture.","image":"https://img.castlecore.uk/whitland-abbey.jpg","rating":3.5,"reviewCount":180,"county":"Carmarthenshire","tags":["ruins-romantic","free-entry","medieval","atmospheric"],"access":"free","_index":1508,"gallery":["https://img.castlecore.uk/whitland-abbey-2.jpg","https://img.castlecore.uk/whitland-abbey-3.jpg","https://img.castlecore.uk/whitland-abbey-4.jpg","https://img.castlecore.uk/whitland-abbey-5.jpg"],"history":"Founded c.1140 as the first Cistercian abbey in Wales (originally at Treffgarne before moving to Whitland c.1151). It was the mother house of numerous Welsh Cistercian foundations including Strata Florida and Strata Marcella. The Laws of Hywel Dda were traditionally codified at Whitland in the 10th century. Only fragmentary foundations survive, revealed by excavation in a quiet meadow. A memorial garden marks the site.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/whitland-abbey"},{"name":"Wikipedia – Whitland Abbey","url":"https://en.wikipedia.org/wiki/Whitland_Abbey"}]},{"name":"St David's Cathedral","lat":51.8819,"lng":-5.2694,"country":"Wales","type":"abbey","era":"12th century","condition":"intact","description":"Hidden in a hollow in Britain's smallest city — a purple-stoned medieval cathedral dedicated to Wales's patron saint, where two pilgrimages equalled one to Rome.","image":"https://img.castlecore.uk/st-david-s-cathedral.jpg","rating":4.7,"reviewCount":5200,"county":"Pembrokeshire","tags":["well-preserved","photogenic","atmospheric","medieval","celtic","coastal","guided-tours","gift-shop"],"access":"free","_index":1509,"gallery":["https://img.castlecore.uk/st-david-s-cathedral-2.jpg","https://img.castlecore.uk/st-david-s-cathedral-3.jpg","https://img.castlecore.uk/st-david-s-cathedral-4.jpg","https://img.castlecore.uk/st-david-s-cathedral-5.jpg"],"history":"Founded on the site of St David's 6th-century monastery. The current cathedral dates mainly from 1181, built by Bishop Peter de Leia in a distinctive local purple sandstone. Pope Calixtus II declared in 1120 that two pilgrimages to St David's equalled one to Rome. The nave floor slopes noticeably upward. Treasures include an ornate 14th-century Bishop's throne, fan-vaulted Holy Trinity Chapel ceiling, and the shrine of St David. Extensively restored by George Gilbert Scott in the 1860s.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/St_Davids_Cathedral"},{"name":"St David's Cathedral Official","url":"https://www.stdavidscathedral.org.uk/"}]},{"name":"Benton Castle Exterior","lat":51.7417,"lng":-4.9417,"country":"Wales","type":"castle","era":"13th century","condition":"restored","description":"A squat medieval tower perched on a wooded hillside above the Daugleddau waterway in Pembrokeshire—a private castle occasionally glimpsed from the water or road.","image":"https://img.castlecore.uk/benton-castle-exterior.jpg","rating":3.5,"reviewCount":120,"county":"Pembrokeshire","tags":["medieval","riverside"],"access":"exterior-only","_index":1511,"gallery":["https://img.castlecore.uk/benton-castle-exterior-2.jpg","https://img.castlecore.uk/benton-castle-exterior-3.jpg","https://img.castlecore.uk/benton-castle-exterior-4.jpg","https://img.castlecore.uk/benton-castle-exterior-5.jpg"],"history":"A medieval castle dating from the 13th century, overlooking the tidal Daugleddau estuary near Llangwm in Pembrokeshire. The castle was held by the de Benton family and later passed through various hands. The compact tower was restored in the 20th century and is now a private residence, not open to the public. Its romantic silhouette can be seen from the A4075 road and from boats on the estuary.","sources":[{"name":"Wikipedia – Benton Castle","url":"https://en.wikipedia.org/wiki/Benton_Castle"},{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"}]},{"name":"Pentre Ifan","lat":51.9986,"lng":-4.7697,"country":"Wales","type":"monument","era":"c. 3500 BC","condition":"intact","description":"The largest and most dramatic neolithic dolmen in Wales — a massive capstone balanced impossibly on slender uprights against a backdrop of Preseli Hills.","image":"https://img.castlecore.uk/pentre-ifan.jpg","rating":4.5,"reviewCount":2800,"county":"Pembrokeshire","tags":["atmospheric","photogenic","prehistoric","remote","hilltop","free-entry"],"access":"free","_index":1513,"gallery":["https://img.castlecore.uk/pentre-ifan-2.jpg","https://img.castlecore.uk/pentre-ifan-3.jpg","https://img.castlecore.uk/pentre-ifan-4.jpg","https://img.castlecore.uk/pentre-ifan-5.jpg"],"history":"The largest and best-preserved neolithic dolmen in Wales, dating to approximately 3500 BC. The enormous capstone, estimated at 16 tonnes, balances on three slender uprights. One of just three Welsh monuments to receive legal protection under the Ancient Monuments Protection Act 1882. Originally covered by an earth mound that has long since eroded away. Managed by Cadw.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Pentre_Ifan"},{"name":"Atlas Obscura","url":"https://www.atlasobscura.com/places/pentre-ifan"}]},{"name":"Carreg Coetan Arthur","lat":52.0167,"lng":-4.8333,"country":"Wales","type":"monument","era":"Neolithic (c.3000 BC)","condition":"intact","description":"A delicate Neolithic dolmen in a suburban Newport garden, its capstone balanced impossibly on slender uprights—a 5,000-year-old monument hiding in plain sight.","image":"https://img.castlecore.uk/carreg-coetan-arthur.jpg","rating":3.8,"reviewCount":350,"county":"Pembrokeshire","tags":["prehistoric","free-entry"],"access":"free","_index":1514,"gallery":["https://img.castlecore.uk/carreg-coetan-arthur-2.jpg","https://img.castlecore.uk/carreg-coetan-arthur-3.jpg","https://img.castlecore.uk/carreg-coetan-arthur-4.jpg","https://img.castlecore.uk/carreg-coetan-arthur-5.jpg"],"history":"A Neolithic portal dolmen dating to c.3000 BC, located in a residential area of Newport, Pembrokeshire. The large capstone is balanced on just two of its four uprights, creating an impossibly delicate appearance. Despite its suburban setting, it is one of the best-preserved portal dolmens in west Wales. Associated with Arthurian legend—the name means 'Arthur's Quoit'. Managed by Cadw.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/carreg-coetan-arthur"},{"name":"Wikipedia – Carreg Coetan Arthur","url":"https://en.wikipedia.org/wiki/Carreg_Coetan_Arthur"}]},{"name":"Gateholm Island","lat":51.7333,"lng":-5.2333,"country":"Wales","type":"fort","era":"Early medieval (5th-6th century)","condition":"earthwork","description":"A tidal island off the Pembrokeshire coast dotted with the remains of over 130 ancient huts—a mysterious settlement where early medieval people lived surrounded by Atlantic spray.","image":"https://img.castlecore.uk/gateholm-island.jpg","rating":3.9,"reviewCount":200,"county":"Pembrokeshire","tags":["island","coastal","prehistoric","remote","free-entry"],"access":"free","_index":1515,"gallery":["https://img.castlecore.uk/gateholm-island-2.jpg","https://img.castlecore.uk/gateholm-island-3.jpg","https://img.castlecore.uk/gateholm-island-4.jpg","https://img.castlecore.uk/gateholm-island-5.jpg"],"history":"A tidal island near Marloes in Pembrokeshire, accessible at low tide. The island contains the remains of over 130 stone huts, likely an early medieval settlement dating to the 5th-6th centuries, though some features may be older. It is one of the largest and most enigmatic settlement sites in Wales. The island is also important for nesting seabirds. Part of the Pembrokeshire Coast National Park.","sources":[{"name":"Wikipedia – Gateholm","url":"https://en.wikipedia.org/wiki/Gateholm"},{"name":"Pembrokeshire Coast National Park","url":"https://www.pembrokeshirecoast.wales/"}]},{"name":"St Non's Chapel","lat":51.8761,"lng":-5.275,"country":"Wales","type":"abbey","era":"6th century (chapel: medieval)","condition":"ruin","description":"A ruined medieval chapel and holy well on the wild Pembrokeshire clifftops, marking the traditional birthplace of St David—patron saint of Wales—amid crashing Atlantic waves.","image":"https://img.castlecore.uk/st-non-s-chapel.jpg","rating":4.3,"reviewCount":1200,"county":"Pembrokeshire","tags":["celtic","coastal","cliffside","atmospheric","free-entry"],"access":"free","_index":1516,"gallery":["https://img.castlecore.uk/st-non-s-chapel-2.jpg","https://img.castlecore.uk/st-non-s-chapel-3.jpg","https://img.castlecore.uk/st-non-s-chapel-4.jpg","https://img.castlecore.uk/st-non-s-chapel-5.jpg"],"history":"A ruined chapel and holy well on the clifftops south of St Davids, Pembrokeshire, marking the traditional birthplace of St David (Dewi Sant) in the 6th century. Legend says a violent storm raged during his birth but the spot where Non stood was bathed in calm light. The chapel ruins date to the medieval period. A nearby modern chapel was built in 1934 in a pre-Reformation style. The holy well was believed to have healing powers.","sources":[{"name":"Wikipedia – St Non's Chapel","url":"https://en.wikipedia.org/wiki/St_Non%27s_Chapel"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/st-nons-chapel"}]},{"name":"Amroth Castle","lat":51.7333,"lng":-4.65,"country":"Wales","type":"castle","era":"Medieval / 19th century","condition":"restored","description":"A castellated Regency mansion on the Carmarthenshire coast where the Pembrokeshire Coast Path begins—or ends—at the edge of a beach that sometimes reveals a prehistoric sunken forest.","image":"https://img.castlecore.uk/amroth-castle.jpg","rating":3.5,"reviewCount":250,"county":"Pembrokeshire","tags":["coastal","victorian"],"access":"exterior-only","_index":1517,"gallery":["https://img.castlecore.uk/amroth-castle-2.jpg","https://img.castlecore.uk/amroth-castle-3.jpg","https://img.castlecore.uk/amroth-castle-4.jpg","https://img.castlecore.uk/amroth-castle-5.jpg"],"history":"A castellated mansion with medieval origins, substantially rebuilt in the Regency period and again in the 19th century. Located at Amroth on the border of Pembrokeshire and Carmarthenshire, it marks the eastern terminus of the 186-mile Pembrokeshire Coast Path. The beach occasionally reveals stumps of a submerged prehistoric forest at low tide. Now divided into private apartments.","sources":[{"name":"Wikipedia – Amroth Castle","url":"https://en.wikipedia.org/wiki/Amroth_Castle"}]},{"name":"Hafod Estate","lat":52.3333,"lng":-3.8167,"country":"Wales","type":"historic-house","era":"18th century","condition":"ruin","description":"The romantic ruins and restored walks of a legendary 18th-century Picturesque landscape in the Ceredigion uplands—once celebrated as the finest designed landscape in Wales.","image":"https://img.castlecore.uk/hafod-estate.jpg","rating":4.3,"reviewCount":700,"county":"Ceredigion","tags":["gardens","woodland","riverside","atmospheric","free-entry","romantic"],"access":"free","_index":1518,"gallery":["https://img.castlecore.uk/hafod-estate-2.jpg","https://img.castlecore.uk/hafod-estate-3.jpg","https://img.castlecore.uk/hafod-estate-4.jpg","https://img.castlecore.uk/hafod-estate-5.jpg"],"history":"An 18th-century Picturesque landscape created by Thomas Johnes from 1783 in the Ystwyth valley, Ceredigion. Johnes planted millions of trees and created elaborate walks, cascades, and viewpoints inspired by Romantic ideals. The mansion (designed by Thomas Baldwin and later rebuilt after fire) was demolished in 1958. The Forestry Commission has restored many of the walks. The Hafod church by James Wyatt survives.","sources":[{"name":"Hafod Estate","url":"https://www.hafod.org/"},{"name":"Wikipedia – Hafod Estate","url":"https://en.wikipedia.org/wiki/Hafod_Estate"}]},{"name":"New Quay Honey Farm & Castle","lat":52.2153,"lng":-4.3569,"country":"Wales","type":"castle","era":"Medieval","condition":"ruin","description":"A quirky combination of a small medieval castle mound and a honey farm in the charming Ceredigion coastal town that inspired Dylan Thomas's Llareggub.","image":"https://img.castlecore.uk/new-quay-honey-farm-castle.jpg","rating":3.4,"reviewCount":120,"county":"Ceredigion","tags":["coastal","kid-friendly","free-entry"],"access":"free","_index":1519,"gallery":["https://img.castlecore.uk/new-quay-honey-farm-castle-2.jpg","https://img.castlecore.uk/new-quay-honey-farm-castle-3.jpg","https://img.castlecore.uk/new-quay-honey-farm-castle-4.jpg","https://img.castlecore.uk/new-quay-honey-farm-castle-5.jpg"],"history":"New Quay (Ceinewydd) in Ceredigion has a small castle mound from the medieval period, likely a Norman fortification. The town is best known as the inspiration for Under Milk Wood by Dylan Thomas, who lived here in 1944-45. The honey farm is a popular family attraction. The picturesque harbour town sits on Cardigan Bay, known for its population of bottlenose dolphins.","sources":[{"name":"Wikipedia – New Quay","url":"https://en.wikipedia.org/wiki/New_Quay"}]},{"name":"Dolaucothi Gold Mines","lat":52.0417,"lng":-3.9333,"country":"Wales","type":"industrial","era":"1st century Roman","condition":"ruin","description":"The UK's only known Roman gold mines, hidden in a green Welsh valley — where legionaries once dug for treasure and you can still venture underground on guided tours by candlelight.","image":"https://img.castlecore.uk/dolaucothi-gold-mines.jpg","rating":4.3,"reviewCount":1800,"county":"Carmarthenshire","tags":["atmospheric","guided-tours","kid-friendly","woodland","remote","tearoom-cafe"],"access":"paid","_index":1520,"gallery":["https://img.castlecore.uk/dolaucothi-gold-mines-2.jpg","https://img.castlecore.uk/dolaucothi-gold-mines-3.jpg","https://img.castlecore.uk/dolaucothi-gold-mines-4.jpg","https://img.castlecore.uk/dolaucothi-gold-mines-5.jpg"],"history":"Mined by the Romans from the 1st century AD, possibly a motivation for their invasion of Britain. A Roman military fort guarded the site until c.125 AD when it became civilian-operated. Evidence of sophisticated Roman engineering including aqueducts and hushing techniques survives. Mining continued intermittently through the 19th-20th centuries. Now a National Trust property with guided underground tours.","youtube":[],"sources":[{"name":"National Trust","url":"https://www.nationaltrust.org.uk/dolaucothi-gold-mines"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Dolaucothi_Gold_Mines"},{"name":"History Hit","url":"https://www.historyhit.com/locations/dolaucothi-gold-mines/"}]},{"name":"Dynevor Castle","lat":51.875,"lng":-4,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"The ancient seat of the princes of Deheubarth, perched on a wooded crag above the River Tywi in one of Wales's most storied landscapes—where Welsh independence had its proudest moments.","image":"https://img.castlecore.uk/dynevor-castle.jpg","rating":4.2,"reviewCount":950,"county":"Carmarthenshire","tags":["hilltop","ruins-romantic","medieval","woodland","atmospheric","celtic"],"access":"paid","_index":1521,"gallery":["https://img.castlecore.uk/dynevor-castle-2.jpg","https://img.castlecore.uk/dynevor-castle-3.jpg","https://img.castlecore.uk/dynevor-castle-4.jpg","https://img.castlecore.uk/dynevor-castle-5.jpg"],"history":"The principal seat of the rulers of Deheubarth, the ancient kingdom of south-west Wales. The Lord Rhys (Rhys ap Gruffydd, d.1197) held court here at the height of Welsh power. The stone castle dates mainly from the 13th century but the site's royal connections go back centuries earlier. Set in Dinefwr Park (National Trust), the castle overlooks the Tywi valley with its famous white cattle herd and Newton House.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/dinefwr-castle"},{"name":"Wikipedia – Dinefwr Castle","url":"https://en.wikipedia.org/wiki/Dinefwr_Castle"}]},{"name":"Plas Mawr","lat":53.2819,"lng":-3.8283,"country":"Wales","type":"historic-house","era":"16th century","condition":"restored","description":"Britain's finest Elizabethan townhouse — hidden behind Conwy's medieval walls, a gentleman's mansion of ornate plasterwork and peacocking Tudor ambition.","image":"https://img.castlecore.uk/plas-mawr.jpg","rating":4.5,"reviewCount":2200,"county":"Conwy","tags":["well-preserved","photogenic","tudor","museum","guided-tours"],"access":"paid","_index":1523,"gallery":["https://img.castlecore.uk/plas-mawr-2.jpg","https://img.castlecore.uk/plas-mawr-3.jpg","https://img.castlecore.uk/plas-mawr-4.jpg","https://img.castlecore.uk/plas-mawr-5.jpg"],"history":"Built 1576-1585 by Robert Wynn, a wealthy Welsh gentleman, at a cost of £800. The finest surviving Elizabethan townhouse in Britain, featuring extraordinary ornamental plasterwork throughout. The main frontage is hidden in a narrow lane, with only the High Street gatehouse hinting at the grandeur within. Managed by Cadw, the Welsh heritage body.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Plas_Mawr"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/plas-mawr"}]},{"name":"Gwydir Castle","lat":53.1506,"lng":-3.7978,"country":"Wales","type":"castle","era":"15th-16th century","condition":"restored","description":"A haunted Tudor manor in the Conwy Valley where peacocks strut through ancient gardens and a thousand-year-old yew tree guards secrets of the powerful Wynn dynasty.","image":"https://img.castlecore.uk/gwydir-castle.jpg","rating":4.3,"reviewCount":1400,"county":"Conwy","tags":["atmospheric","haunted","photogenic","gardens","guided-tours","tudor","romantic"],"access":"paid","_index":1524,"gallery":["https://img.castlecore.uk/gwydir-castle-2.jpg","https://img.castlecore.uk/gwydir-castle-3.jpg","https://img.castlecore.uk/gwydir-castle-4.jpg","https://img.castlecore.uk/gwydir-castle-5.jpg"],"history":"One of the finest Tudor houses in Wales, ancestral home of the powerful Wynn family. Features a 'Lovers Tree' yew estimated at 600-1,000 years old. King Charles I visited in 1645 as guest of Sir Richard Wynn. Contains a remarkable 1640s dining room that was sold to William Randolph Hearst in 1921, returned from the Metropolitan Museum of Art in the 1990s and reinstalled. Reputedly one of the most haunted houses in Wales.","sources":[{"name":"Gwydir Castle","url":"https://www.gwydircastle.co.uk/"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Gwydir_Castle"},{"name":"Gwydir Castle History","url":"https://www.gwydircastle.co.uk/history/"}]},{"name":"Bodysgallen Hall","lat":53.275,"lng":-3.8167,"country":"Wales","type":"historic-house","era":"13th-17th century","condition":"restored","description":"A Grade I listed Welsh manor with a medieval watchtower commanding views to Conwy Castle and Snowdonia — now a luxurious National Trust hotel wrapped in walled gardens and ancient woodland.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/9/92/Bodysgallenhallcmichaelhoganlowres.jpg/500px-Bodysgallenhallcmichaelhoganlowres.jpg","rating":4.5,"reviewCount":1800,"county":"Conwy","tags":["well-preserved","medieval","gardens","photogenic","romantic","tearoom-cafe","wedding-venue"],"access":"paid","_index":1525,"gallery":["https://img.castlecore.uk/bodysgallen-hall-2.jpg","https://img.castlecore.uk/bodysgallen-hall-3.jpg","https://img.castlecore.uk/bodysgallen-hall-4.jpg","https://img.castlecore.uk/bodysgallen-hall-5.jpg"],"history":"The core is a late 13th-century watchtower, probably built to support the defence of nearby Conwy Castle. First recorded in mid-14th century. The hall grew through the 16th-17th centuries around this tower, built from on-site quarried pink sandstone. Used as a recruiting ground for the Royal Welsh Fusiliers in WWI. Now a luxury hotel owned by the National Trust with rare 17th-century parterre gardens and a 200-year-old stone pine.","youtube":[],"sources":[{"name":"Bodysgallen Hall","url":"https://www.bodysgallen.com/hotel-gardens/history/"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Bodysgallen_Hall"},{"name":"Britain Express","url":"https://www.britainexpress.com/attractions.htm?attraction=695"}]},{"name":"Segontium Roman Fort","lat":53.1361,"lng":-4.2806,"country":"Wales","type":"fort","era":"1st-4th century AD","condition":"ruin","description":"The foundations of a Roman auxiliary fort on the outskirts of Caernarfon, where legionaries guarded the Menai Strait and the western frontier of Britannia for three centuries.","image":"https://img.castlecore.uk/segontium-roman-fort.jpg","rating":4,"reviewCount":800,"county":"Gwynedd","tags":["well-preserved","prehistoric","museum","free-entry"],"access":"free","_index":1526,"gallery":["https://img.castlecore.uk/segontium-roman-fort-2.jpg","https://img.castlecore.uk/segontium-roman-fort-3.jpg","https://img.castlecore.uk/segontium-roman-fort-4.jpg","https://img.castlecore.uk/segontium-roman-fort-5.jpg"],"history":"A Roman auxiliary fort built c. AD 77-78 by Gnaeus Julius Agricola to control the Menai Strait and northwest Wales. Occupied until c. AD 394, making it one of the longest-occupied Roman sites in Britain. The visible foundations reveal the layout of barracks, granaries, and a commandant's house. A small museum displays finds. The fort's name gives Caernarfon its Welsh name (Caer yn Arfon).","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/segontium-roman-fort"},{"name":"Wikipedia – Segontium","url":"https://en.wikipedia.org/wiki/Segontium"}]},{"name":"Penrhyn Castle","lat":53.2278,"lng":-4.0917,"country":"Wales","type":"castle","era":"19th century","condition":"intact","description":"A colossal Norman Revival fantasy built on slate money — an extravagant Victorian folly bristling with turrets, hiding the largest bed in Britain and a railway museum in its stables.","image":"https://img.castlecore.uk/penrhyn-castle.jpg","rating":4.5,"reviewCount":4500,"county":"Gwynedd","tags":["well-preserved","photogenic","norman","victorian","museum","gardens","guided-tours","tearoom-cafe","gift-shop","kid-friendly"],"access":"paid","_index":1527,"gallery":["https://img.castlecore.uk/penrhyn-castle-2.jpg","https://img.castlecore.uk/penrhyn-castle-3.jpg","https://img.castlecore.uk/penrhyn-castle-4.jpg","https://img.castlecore.uk/penrhyn-castle-5.jpg"],"history":"Built 1820-1833 for George Hay Dawkins-Pennant using profits from the massive Penrhyn slate quarry and Jamaican sugar plantations worked by enslaved people. Designed by Thomas Hopper in an extraordinary Norman Revival style. Contains a one-ton slate bed made for Queen Victoria (she refused to sleep in it). The stable block houses a railway museum with industrial locomotives. The castle was the scene of a bitter 3-year quarry workers' strike (1900-1903). National Trust since 1951.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Penrhyn_Castle"},{"name":"National Trust","url":"https://www.nationaltrust.org.uk/visit/wales/penrhyn-castle-and-garden"}]},{"name":"Aber Falls Fort","lat":53.2167,"lng":-3.9833,"country":"Wales","type":"fort","era":"Iron Age","condition":"earthwork","description":"The faint remains of a hillfort near the spectacular Aber Falls waterfall in the Snowdonia foothills—where a 120-foot cascade and ancient earthworks share the same dramatic valley.","image":"https://img.castlecore.uk/aber-falls-fort.jpg","rating":3.8,"reviewCount":200,"county":"Gwynedd","tags":["prehistoric","free-entry","woodland","remote","photogenic"],"access":"free","_index":1528,"gallery":["https://img.castlecore.uk/aber-falls-fort-2.jpg","https://img.castlecore.uk/aber-falls-fort-3.jpg","https://img.castlecore.uk/aber-falls-fort-4.jpg","https://img.castlecore.uk/aber-falls-fort-5.jpg"],"history":"An Iron Age or early medieval hillfort near Rhaeadr Fawr (Aber Falls), one of the finest waterfalls in Wales, where the Afon Goch plunges 120 feet. The hillfort occupies a defensive position near the falls. The area was part of the territory of the princes of Gwynedd and the nearby royal court of Abergwyngregyn was Llywelyn ap Gruffudd's principal residence. The walk to the falls passes through ancient oak woodland.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"},{"name":"Snowdonia National Park","url":"https://www.snowdonia.gov.wales/"}]},{"name":"Bryn Celli Ddu","lat":53.2072,"lng":-4.2361,"country":"Wales","type":"monument","era":"Neolithic","condition":"intact","description":"Step inside a 5,000-year-old passage tomb on Anglesey — 'The Mound in the Dark Grove' aligns with the summer solstice sunrise, flooding its ancient chamber with golden light.","image":"https://img.castlecore.uk/bryn-celli-ddu.jpg","rating":4.4,"reviewCount":1800,"county":"Anglesey","tags":["prehistoric","atmospheric","free-entry","photogenic","remote"],"access":"free","_index":1529,"gallery":["https://img.castlecore.uk/bryn-celli-ddu-2.jpg","https://img.castlecore.uk/bryn-celli-ddu-3.jpg","https://img.castlecore.uk/bryn-celli-ddu-4.jpg","https://img.castlecore.uk/bryn-celli-ddu-5.jpg"],"history":"Originally a Neolithic henge with a stone circle, later converted into a passage tomb c.3000 BC. The mound measures 26m in diameter with a stone-lined passage leading to a central burial chamber. Aligned with the summer solstice sunrise when light penetrates the passage. Excavated 1928-29; a mysterious carved 'Pattern Stone' was found behind the chamber (replica on site, original in National Museum Wales). Managed by Cadw, free to visit.","youtube":[],"sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/bryn-celli-ddu-chambered-tomb"},{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Bryn_Celli_Ddu"},{"name":"Anglesey History","url":"https://www.anglesey-history.co.uk/places/prehistoric-monuments/bryn-celli-ddu/"}]},{"name":"Barclodiad y Gawres","lat":53.225,"lng":-4.5083,"country":"Wales","type":"monument","era":"Neolithic (c.3000 BC)","condition":"intact","description":"A mysterious Neolithic passage tomb on the Anglesey coast, its inner stones carved with rare prehistoric spirals and chevrons—one of only two decorated passage tombs in Wales.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/d/d1/BarclodiadyGawres.JPG/500px-BarclodiadyGawres.JPG","rating":4.2,"reviewCount":600,"county":"Anglesey","tags":["prehistoric","coastal","atmospheric"],"access":"free","_index":1530,"gallery":["https://img.castlecore.uk/barclodiad-y-gawres-2.jpg","https://img.castlecore.uk/barclodiad-y-gawres-3.jpg","https://img.castlecore.uk/barclodiad-y-gawres-4.jpg","https://img.castlecore.uk/barclodiad-y-gawres-5.jpg"],"history":"A Neolithic passage grave on the west coast of Anglesey dating to c.3000 BC. One of only two passage graves in Wales with decorated stones (the other being Bryn Celli Ddu). The interior stones bear carved spirals, zigzags, and chevrons similar to those at Newgrange in Ireland. Excavations in the 1950s found a cremation deposit. The tomb was reconstructed with a concrete dome. Access by key from nearby café.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/barclodiad-y-gawres-burial-chamber"},{"name":"Wikipedia – Barclodiad y Gawres","url":"https://en.wikipedia.org/wiki/Barclodiad_y_Gawres"}]},{"name":"Din Lligwy","lat":53.35,"lng":-4.2667,"country":"Wales","type":"fort","era":"3rd-4th century AD","condition":"ruin","description":"A remarkably well-preserved Romano-British settlement on Anglesey, where thick-walled stone houses and a fortified enclosure reveal how people lived at the edge of the Roman Empire.","image":"https://img.castlecore.uk/din-lligwy.jpg","rating":4.1,"reviewCount":500,"county":"Anglesey","tags":["well-preserved","prehistoric","free-entry","atmospheric"],"access":"free","_index":1532,"gallery":["https://img.castlecore.uk/din-lligwy-2.jpg","https://img.castlecore.uk/din-lligwy-3.jpg","https://img.castlecore.uk/din-lligwy-4.jpg","https://img.castlecore.uk/din-lligwy-5.jpg"],"history":"A Romano-British enclosed settlement in eastern Anglesey, occupied during the 3rd-4th centuries AD. The site contains two rectangular and several circular stone buildings within a pentagonal enclosure wall up to 1.5 metres thick. One rectangular building may have been the house of a local chief. The quality of construction and finds of coins and pottery suggest relative prosperity. Managed by Cadw and freely accessible.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/din-lligwy-hut-group"},{"name":"Wikipedia – Din Lligwy","url":"https://en.wikipedia.org/wiki/Din_Lligwy"}]},{"name":"Lligwy Burial Chamber","lat":53.3528,"lng":-4.2667,"country":"Wales","type":"monument","era":"Neolithic (c.3000 BC)","condition":"intact","description":"A massive Neolithic capstone weighing 28 tons, resting on low uprights in an Anglesey field—one of the most impressive megalithic monuments in Wales.","image":"https://img.castlecore.uk/lligwy-burial-chamber.jpg","rating":4.2,"reviewCount":550,"county":"Anglesey","tags":["prehistoric","free-entry","atmospheric"],"access":"free","_index":1533,"gallery":["https://img.castlecore.uk/lligwy-burial-chamber-2.jpg","https://img.castlecore.uk/lligwy-burial-chamber-3.jpg","https://img.castlecore.uk/lligwy-burial-chamber-4.jpg","https://img.castlecore.uk/lligwy-burial-chamber-5.jpg"],"history":"A Neolithic burial chamber near Moelfre on Anglesey, dating to c.3000 BC. The enormous capstone, weighing approximately 28 tons, is one of the largest in Wales. Excavation in 1909 revealed the bones of between 15 and 30 individuals. The chamber is near Din Lligwy settlement and the ruined Lligwy Chapel, making the area a remarkable concentration of ancient sites. Managed by Cadw.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/lligwy-burial-chamber"},{"name":"Wikipedia – Lligwy Burial Chamber","url":"https://en.wikipedia.org/wiki/Lligwy_Burial_Chamber"}]},{"name":"Holyhead Mountain Hut Group","lat":53.3194,"lng":-4.6861,"country":"Wales","type":"fort","era":"2nd-4th century AD","condition":"ruin","description":"A cluster of stone roundhouses on Anglesey's highest point, where people lived with views of Ireland across the sea—one of the best-preserved ancient settlement groups in Britain.","image":"https://img.castlecore.uk/holyhead-mountain-hut-group.jpg","rating":4,"reviewCount":400,"county":"Anglesey","tags":["prehistoric","hilltop","free-entry","coastal","remote"],"access":"free","_index":1534,"gallery":["https://img.castlecore.uk/holyhead-mountain-hut-group-2.jpg","https://img.castlecore.uk/holyhead-mountain-hut-group-3.jpg","https://img.castlecore.uk/holyhead-mountain-hut-group-4.jpg","https://img.castlecore.uk/holyhead-mountain-hut-group-5.jpg"],"history":"A group of about 20 stone roundhouses on the slopes of Holyhead Mountain (Mynydd Twr), Anglesey, dating mainly to the Romano-British period (2nd-4th century AD). The settlement was likely agricultural, with circular stone huts featuring internal fittings. The site offers panoramic views across the Irish Sea. It lies near the Iron Age hillfort of Caer y Twr on the summit. Managed by Cadw.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/holyhead-mountain-hut-group"},{"name":"Wikipedia – Holyhead Mountain Hut Group","url":"https://en.wikipedia.org/wiki/Ty_Mawr_Hut_Group"}]},{"name":"Caer y Twr","lat":53.3194,"lng":-4.6889,"country":"Wales","type":"hillfort","era":"Iron Age","condition":"ruin","description":"An Iron Age hillfort crowning the summit of Holyhead Mountain on Anglesey, where ancient stone walls encircle the highest ground with sweeping views to Ireland, Snowdonia, and the Isle of Man.","image":"https://img.castlecore.uk/caer-y-twr.jpg","rating":4.2,"reviewCount":650,"county":"Anglesey","tags":["prehistoric","hilltop","free-entry","coastal","photogenic","remote"],"access":"free","_index":1535,"gallery":["https://img.castlecore.uk/caer-y-twr-2.jpg","https://img.castlecore.uk/caer-y-twr-3.jpg","https://img.castlecore.uk/caer-y-twr-4.jpg","https://img.castlecore.uk/caer-y-twr-5.jpg"],"history":"An Iron Age hillfort on the summit of Holyhead Mountain (Mynydd Twr) at 220 metres, the highest point on Anglesey. The fort's stone walls follow the cliff edges on a roughly triangular plan. Though never fully excavated, it likely dates to the Iron Age or Romano-British period. The panoramic views extend to Ireland, the Llŷn Peninsula, Snowdonia, and on clear days the Isle of Man. Managed by Cadw.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/caer-y-twr"},{"name":"Wikipedia – Caer y Twr","url":"https://en.wikipedia.org/wiki/Caer_y_Twr"}]},{"name":"South Stack Lighthouse","lat":53.3069,"lng":-4.6989,"country":"Wales","type":"monument","era":"19th century","condition":"intact","description":"A white lighthouse clinging to a sea-battered islet off Anglesey — descend 400 steps down the cliff face to reach it, with puffins wheeling overhead and the Irish Sea crashing below.","image":"https://img.castlecore.uk/south-stack-lighthouse.jpg","rating":4.6,"reviewCount":4200,"county":"Anglesey","tags":["photogenic","coastal","cliffside","remote","atmospheric","kid-friendly"],"access":"paid","_index":1536,"gallery":["https://img.castlecore.uk/south-stack-lighthouse-2.jpg","https://img.castlecore.uk/south-stack-lighthouse-3.jpg","https://img.castlecore.uk/south-stack-lighthouse-4.jpg","https://img.castlecore.uk/south-stack-lighthouse-5.jpg"],"history":"Built in 1809 by Trinity House to warn ships navigating the treacherous waters around Holy Island, Anglesey. The original oil lamp was replaced by electric light in 1938 and the lighthouse was automated in 1984. Accessed via a dramatic descent of approximately 400 steps down the cliff and across a bridge to the tiny island. The surrounding RSPB reserve is a major seabird colony, home to puffins, guillemots, razorbills, and choughs. An Ellin's Tower visitor centre overlooks the colony.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/South_Stack_Lighthouse"},{"name":"RSPB South Stack","url":"https://www.rspb.org.uk/reserves-and-events/reserves-a-z/south-stack-cliffs/"}]},{"name":"Plas Newydd","lat":53.175,"lng":-4.2167,"country":"Wales","type":"historic-house","era":"18th century","condition":"intact","description":"An elegant estate on the Menai Strait with Snowdonia as its backdrop — home to the Marquess who lost his leg at Waterloo and the one who lost his fortune.","image":"https://img.castlecore.uk/plas-newydd.jpg","rating":4.5,"reviewCount":3000,"county":"Anglesey","tags":["well-preserved","photogenic","coastal","gardens","museum","guided-tours","gift-shop"],"access":"paid","_index":1537,"gallery":["https://img.castlecore.uk/plas-newydd-2.jpg","https://img.castlecore.uk/plas-newydd-3.jpg","https://img.castlecore.uk/plas-newydd-4.jpg","https://img.castlecore.uk/plas-newydd-5.jpg"],"history":"Set on the shores of the Menai Strait on Anglesey, continuously inhabited since 1470. Refaced in Gothic and neo-Classical style by James Wyatt in the late 18th century. The 1st Marquess of Anglesey lost his leg at Waterloo (1815). The 5th Marquess nearly bankrupted the estate. Features a famous Rex Whistler mural. Now National Trust.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Plas_Newydd_(Anglesey)"},{"name":"National Trust","url":"https://www.nationaltrust.org.uk/visit/wales/plas-newydd-house-and-garden/history-of-plas-newydd"}]},{"name":"Portmeirion","lat":52.8028,"lng":-4.0833,"country":"Wales","type":"historic-house","era":"20th century","condition":"intact","description":"A fantastical Italianate village on the Welsh coast — pastel colonnades, secret gardens, and whimsical follies that feel like stepping into a Mediterranean dream on Snowdonia's doorstep.","image":"https://img.castlecore.uk/portmeirion.jpg","rating":4.5,"reviewCount":8500,"county":"Gwynedd","tags":["well-preserved","photogenic","filming-location","gardens","coastal","romantic","atmospheric","tearoom-cafe","gift-shop","dog-friendly"],"access":"paid","_index":1540,"gallery":["https://img.castlecore.uk/portmeirion-2.jpg","https://img.castlecore.uk/portmeirion-3.jpg","https://img.castlecore.uk/portmeirion-4.jpg","https://img.castlecore.uk/portmeirion-5.jpg"],"history":"Built by architect Sir Clough Williams-Ellis between 1925 and 1975 to demonstrate how a naturally beautiful site could be developed without spoiling it. Inspired by Portofino and other Mediterranean villages. Famous as the filming location for the 1960s TV series The Prisoner. Features rescued architectural elements from demolished buildings across Britain. Now a conservation village with hotel and self-catering cottages.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Portmeirion"},{"name":"Portmeirion Official","url":"https://portmeirion.wales/"}]},{"name":"Beddgelert Dinas Emrys Walk","lat":53.0139,"lng":-4.1083,"country":"Wales","type":"hillfort","era":"Iron Age / Dark Age","condition":"ruin","description":"A magical woodland walk through the Glaslyn valley to the legendary fortress of Dinas Emrys—threading past waterfalls, ancient oaks, and the ghost of Gelert the faithful hound.","image":"https://img.castlecore.uk/beddgelert-dinas-emrys-walk.jpg","rating":4.3,"reviewCount":700,"county":"Gwynedd","tags":["woodland","atmospheric","free-entry","celtic","riverside"],"access":"free","_index":1541,"gallery":["https://img.castlecore.uk/beddgelert-dinas-emrys-walk-2.jpg","https://img.castlecore.uk/beddgelert-dinas-emrys-walk-3.jpg","https://img.castlecore.uk/beddgelert-dinas-emrys-walk-4.jpg","https://img.castlecore.uk/beddgelert-dinas-emrys-walk-5.jpg"],"history":"A circular walk from the picturesque village of Beddgelert in Snowdonia, passing through the Glaslyn and Colwyn valleys to Dinas Emrys hillfort. Beddgelert itself is named for the legendary hound Gelert, faithful dog of Prince Llywelyn. The route passes through ancient sessile oak woodland, alongside the river, and climbs to the hillfort associated with Merlin and Vortigern's dragons. National Trust land.","sources":[{"name":"National Trust – Craflwyn & Beddgelert","url":"https://www.nationaltrust.org.uk/visit/wales/craflwyn-and-beddgelert"},{"name":"Snowdonia National Park","url":"https://www.snowdonia.gov.wales/"}]},{"name":"Eliseg's Pillar","lat":52.9889,"lng":-3.1861,"country":"Wales","type":"monument","era":"9th century (site: Bronze Age)","condition":"ruin","description":"A Dark Age inscribed stone cross near Valle Crucis Abbey, erected by a Welsh prince to proclaim his royal lineage back to the Roman emperor Magnus Maximus—a manifesto in stone.","image":"https://img.castlecore.uk/eliseg-s-pillar.jpg","rating":4,"reviewCount":450,"county":"Denbighshire","tags":["celtic","medieval","free-entry","atmospheric"],"access":"free","_index":1542,"gallery":["https://img.castlecore.uk/eliseg-s-pillar-2.jpg","https://img.castlecore.uk/eliseg-s-pillar-3.jpg","https://img.castlecore.uk/eliseg-s-pillar-4.jpg","https://img.castlecore.uk/eliseg-s-pillar-5.jpg"],"history":"A 9th-century stone cross erected by Cyngen ap Cadell, last king of Powys, in honour of his great-grandfather Eliseg (Elisedd). The lengthy Latin inscription traced the royal lineage of the kings of Powys back to Magnus Maximus, Roman emperor. The cross was broken during the Civil War; only the base survives on its original mound. Excavation in 2010-12 revealed a Bronze Age cairn and early medieval burials beneath.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/elisegs-pillar"},{"name":"Wikipedia – Eliseg's Pillar","url":"https://en.wikipedia.org/wiki/Pillar_of_Eliseg"}]},{"name":"Mold Bailey Hill","lat":53.1667,"lng":-3.1417,"country":"Wales","type":"castle","era":"11th-13th century","condition":"earthwork","description":"A substantial Norman motte in the heart of Mold town centre, crowned by a bowling green—the ancient stronghold that gives the Flintshire county town its Welsh name, Yr Wyddgrug.","image":"https://img.castlecore.uk/mold-bailey-hill.jpg","rating":3.5,"reviewCount":250,"county":"Flintshire","tags":["hilltop","free-entry","norman"],"access":"free","_index":1545,"gallery":["https://img.castlecore.uk/mold-bailey-hill-2.jpg","https://img.castlecore.uk/mold-bailey-hill-3.jpg","https://img.castlecore.uk/mold-bailey-hill-4.jpg","https://img.castlecore.uk/mold-bailey-hill-5.jpg"],"history":"A large Norman motte-and-bailey castle in the centre of Mold, Flintshire. Built by Robert de Montalt in the late 11th century, it was the caput of the lordship of Montalt. The castle was attacked and destroyed by Owain Gwynedd in 1144 and rebuilt. It was captured by Llywelyn ab Iorwerth in 1199. The motte survives as an impressive mound with a bowling green on its flat summit. The Welsh name Yr Wyddgrug means 'the mound'.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/mold-bailey-hill"},{"name":"Wikipedia – Mold, Flintshire","url":"https://en.wikipedia.org/wiki/Mold,_Flintshire"}]},{"name":"Erddig Hall","lat":53.0361,"lng":-3.0083,"country":"Wales","type":"historic-house","era":"17th century","condition":"restored","description":"A remarkably preserved country house that tells the story from both sides of the green baize door — where servant portraits hang alongside masters in a touching record of household life.","image":"https://img.castlecore.uk/erddig-hall.jpg","rating":4.6,"reviewCount":5200,"county":"Wrexham","tags":["well-preserved","photogenic","gardens","guided-tours","tearoom-cafe","gift-shop","museum","kid-friendly"],"access":"paid","_index":1546,"gallery":["https://img.castlecore.uk/erddig-hall-2.jpg","https://img.castlecore.uk/erddig-hall-3.jpg","https://img.castlecore.uk/erddig-hall-4.jpg","https://img.castlecore.uk/erddig-hall-5.jpg"],"history":"Built 1684-1687 for Joshua Edisbury, then acquired by the Yorke family in 1733 who held it for over 240 years. Unique for its extraordinary collection of servant portraits spanning 200 years, reflecting the close relationship between the Yorke family and their staff. The house became increasingly dilapidated as the family's fortunes declined. The National Trust rescued it in 1973 in a near-derelict state. Features an 18th-century Chinese wallpaper room and restored formal garden.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Erddig"},{"name":"National Trust","url":"https://www.nationaltrust.org.uk/visit/wales/erddig"}]},{"name":"Holt Castle","lat":53.0667,"lng":-2.8667,"country":"Wales","type":"castle","era":"13th-14th century","condition":"ruin","description":"The fragmentary ruins of a pentagonal Edwardian castle on the Welsh bank of the River Dee, its unusual five-sided plan making it one of the most architecturally distinctive castles in Wales.","image":"https://img.castlecore.uk/holt-castle.jpg","rating":3.6,"reviewCount":180,"county":"Wrexham","tags":["ruins-romantic","riverside","medieval","free-entry"],"access":"free","_index":1547,"gallery":["https://img.castlecore.uk/holt-castle-2.jpg","https://img.castlecore.uk/holt-castle-3.jpg","https://img.castlecore.uk/holt-castle-4.jpg","https://img.castlecore.uk/holt-castle-5.jpg"],"history":"Built c.1282-1311 by John de Warenne, Earl of Surrey, after Edward I's conquest of Wales. Its unusual pentagonal plan with five drum towers was a sophisticated and expensive design. Much of the stone was robbed in the 17th century to build Eaton Hall across the river. The surviving fragments overlook the River Dee on the Welsh-English border. Community efforts have improved access to the ruins.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/holt-castle"},{"name":"Wikipedia – Holt Castle","url":"https://en.wikipedia.org/wiki/Holt_Castle"}]},{"name":"Aberedw Castle Rocks","lat":52.1417,"lng":-3.375,"country":"Wales","type":"castle","era":"13th century (legend)","condition":"ruin","description":"Dramatic sandstone crags and cave above the Wye valley where Llywelyn ap Gruffudd, the last native Prince of Wales, supposedly sheltered on the night before his death.","image":"https://img.castlecore.uk/aberedw-castle-rocks.jpg","rating":3.4,"reviewCount":80,"county":"Powys","tags":["cliffside","atmospheric","free-entry","medieval","remote"],"access":"free","_index":1551,"gallery":["https://img.castlecore.uk/aberedw-castle-rocks-2.jpg","https://img.castlecore.uk/aberedw-castle-rocks-3.jpg","https://img.castlecore.uk/aberedw-castle-rocks-4.jpg","https://img.castlecore.uk/aberedw-castle-rocks-5.jpg"],"history":"Rocky crags above the village of Aberedw in Powys, associated with the last hours of Llywelyn ap Gruffudd (Llywelyn the Last). According to tradition, the prince hid in a cave here on the night of 10 December 1282, having his horse shod backwards to mislead pursuers, before riding to his death at Cilmeri the next day. The atmospheric rocks and cave overlook the Wye valley near Builth Wells.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"},{"name":"Wikipedia – Aberedw","url":"https://en.wikipedia.org/wiki/Aberedw"}]},{"name":"Brecon Cathedral","lat":51.9472,"lng":-3.3944,"country":"Wales","type":"abbey","era":"11th century onwards","condition":"intact","description":"A 900-year-old sanctuary in the Brecon Beacons — built on a Celtic holy site by Norman conquerors, with a golden rood screen and centuries of Welsh devotion soaked into ancient stone.","image":"https://img.castlecore.uk/brecon-cathedral.jpg","rating":4.3,"reviewCount":1100,"county":"Powys","tags":["well-preserved","atmospheric","medieval","norman","free-entry"],"access":"free","_index":1554,"gallery":["https://img.castlecore.uk/brecon-cathedral-2.jpg","https://img.castlecore.uk/brecon-cathedral-3.jpg","https://img.castlecore.uk/brecon-cathedral-4.jpg","https://img.castlecore.uk/brecon-cathedral-5.jpg"],"history":"Built on the site of an earlier Celtic church, the new church was ordered by Bernard de Neufmarché, the Norman knight who conquered the kingdom of Brycheiniog, c. 1093. Originally a Benedictine priory. A magnificent 'golden rood' screen was erected in the 15th century. Restored in the Victorian era by Sir George Gilbert Scott. Elevated to cathedral status in 1923 as the seat of the Diocese of Swansea and Brecon.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Brecon_Cathedral"},{"name":"Brecon Cathedral","url":"https://www.breconcathedral.org.uk/"},{"name":"Visit Wales","url":"https://www.visitwales.com/attraction/historic-site/brecon-cathedral-530021"}]},{"name":"Bleddfa Castle Mound","lat":52.3,"lng":-3.1333,"country":"Wales","type":"castle","era":"12th century","condition":"earthwork","description":"A lonely Norman motte in the quiet Radnorshire hills, one of the most remote and least-visited castle sites in Wales—pure borderland solitude.","image":"https://img.castlecore.uk/bleddfa-castle-mound.jpg","rating":3,"reviewCount":40,"county":"Powys","tags":["hilltop","free-entry","remote","norman"],"access":"free","_index":1556,"gallery":["https://img.castlecore.uk/bleddfa-castle-mound-2.jpg","https://img.castlecore.uk/bleddfa-castle-mound-3.jpg","https://img.castlecore.uk/bleddfa-castle-mound-4.jpg","https://img.castlecore.uk/bleddfa-castle-mound-5.jpg"],"history":"A Norman motte-and-bailey castle mound in the hamlet of Bleddfa, Powys, in the remote Radnorshire hills near the English border. Part of the chain of small castles built to control the Welsh Marches. The earthwork mound and ditch survive in a peaceful agricultural landscape. Bleddfa's church of St Mary Magdalene is also of medieval origin. One of the least-visited heritage sites in Wales.","sources":[{"name":"Coflein – RCAHMW","url":"https://coflein.gov.uk"},{"name":"Wikipedia – Bleddfa","url":"https://en.wikipedia.org/wiki/Bleddfa"}]},{"name":"Monmouth Castle","lat":51.8111,"lng":-2.7139,"country":"Wales","type":"castle","era":"11th-14th century","condition":"ruin","description":"The birthplace of Henry V—England's warrior king—though only the Great Tower and castle ruins survive amid the streets of this handsome Monmouthshire border town.","image":"https://img.castlecore.uk/monmouth-castle.jpg","rating":3.8,"reviewCount":600,"county":"Monmouthshire","tags":["norman","medieval","free-entry"],"access":"free","_index":1559,"gallery":["https://img.castlecore.uk/monmouth-castle-2.jpg","https://img.castlecore.uk/monmouth-castle-3.jpg","https://img.castlecore.uk/monmouth-castle-4.jpg","https://img.castlecore.uk/monmouth-castle-5.jpg"],"history":"A Norman castle founded by William fitzOsbern c.1067. Henry V, the victor of Agincourt, was born here in 1386. The castle was the principal seat of the Duchy of Lancaster in the Welsh Marches. It was slighted after the Civil War; the Great Tower survives alongside later buildings now used by the Royal Monmouthshire Royal Engineers militia. Geoffrey of Monmouth, chronicler of Arthurian legend, may have been associated with the castle.","sources":[{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/monmouth-castle"},{"name":"Wikipedia – Monmouth Castle","url":"https://en.wikipedia.org/wiki/Monmouth_Castle"}]},{"name":"Monnow Bridge Gate","lat":51.8083,"lng":-2.7167,"country":"Wales","type":"castle","era":"13th century","condition":"intact","description":"The only surviving medieval fortified river bridge in Britain — a stone sentinel guarding Monmouth's crossing since the days of Edward I.","image":"https://img.castlecore.uk/monnow-bridge-gate.jpg","rating":4.4,"reviewCount":2200,"county":"Monmouthshire","tags":["well-preserved","photogenic","medieval","free-entry"],"access":"free","_index":1560,"gallery":["https://img.castlecore.uk/monnow-bridge-gate-2.jpg","https://img.castlecore.uk/monnow-bridge-gate-3.jpg","https://img.castlecore.uk/monnow-bridge-gate-4.jpg","https://img.castlecore.uk/monnow-bridge-gate-5.jpg"],"history":"Construction began in 1272 to replace a 12th-century Norman timber bridge. The gatehouse was added in the late 13th or early 14th century, funded by a medieval tax ('murage') raised by Edward I. The only remaining medieval fortified river bridge in Great Britain with its gate tower still standing. Has played a role in defending Monmouth through the English Civil War and the Chartist uprising.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Monnow_Bridge"},{"name":"Visit Monmouthshire","url":"https://www.visitmonmouthshire.com/things-to-do/monnow-gate-and-bridge-p1504521"}]},{"name":"Piercefield Walks","lat":51.65,"lng":-2.6833,"country":"Wales","type":"historic-house","era":"18th century","condition":"ruin","description":"An 18th-century Picturesque landscape walk high above the Wye valley near Chepstow, where carefully framed views of cliffs, river, and Tintern Abbey once astonished Georgian tourists.","image":"https://img.castlecore.uk/piercefield-walks.jpg","rating":4.2,"reviewCount":600,"county":"Monmouthshire","tags":["woodland","cliffside","riverside","atmospheric","free-entry","photogenic"],"access":"free","_index":1563,"gallery":["https://img.castlecore.uk/piercefield-walks-2.jpg","https://img.castlecore.uk/piercefield-walks-3.jpg","https://img.castlecore.uk/piercefield-walks-4.jpg","https://img.castlecore.uk/piercefield-walks-5.jpg"],"history":"Created by Valentine Morris from the 1750s, Piercefield Walks were among the most celebrated Picturesque pleasure grounds in Britain. The circuit walk along the cliffs above the Wye Gorge offered a sequence of dramatic viewpoints—the Alcove, the Giant's Cave, the Lover's Leap—framing views of the river, Lancaut peninsula, and distant Tintern Abbey. The walks fell into neglect but have been partially restored and reopened.","sources":[{"name":"Wikipedia – Piercefield House","url":"https://en.wikipedia.org/wiki/Piercefield_House"},{"name":"Wye Valley AONB","url":"https://www.wyevalleyaonb.org.uk/"}]},{"name":"Dylan Thomas Boathouse","lat":51.7667,"lng":-4.4583,"country":"Wales","type":"historic-house","era":"20th century","condition":"restored","description":"The clifftop writing shed where Dylan Thomas penned Under Milk Wood — perched above the Tâf estuary in the 'timeless, beautiful, barmy town' of Laugharne.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/c/cb/Dylan_Boathouse.jpg/500px-Dylan_Boathouse.jpg","rating":4.5,"reviewCount":2800,"county":"Carmarthenshire","tags":["atmospheric","photogenic","coastal","museum"],"access":"paid","_index":1568,"gallery":["https://img.castlecore.uk/dylan-thomas-boathouse-2.jpg","https://img.castlecore.uk/dylan-thomas-boathouse-3.jpg","https://img.castlecore.uk/dylan-thomas-boathouse-4.jpg","https://img.castlecore.uk/dylan-thomas-boathouse-5.jpg"],"history":"The Boathouse in Laugharne was Dylan Thomas's home during his last four years (1949-1953). Set in a cliff overlooking the Tâf estuary, it's where he wrote many of his major works, including Under Milk Wood and much of his late poetry. Thomas first arrived in Laugharne aged 19 in 1934. The house is now a museum dedicated to his life and work.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Dylan_Thomas_Boathouse"},{"name":"Visit Wales","url":"https://www.visitwales.com/attraction/visitor-centre/dylan-thomas-boat-house-829119"}]},{"name":"Aberconwy House","lat":53.2806,"lng":-3.8278,"country":"Wales","type":"historic-house","era":"14th century","condition":"restored","description":"The oldest surviving medieval merchant's house in Conwy, a timber-framed gem tucked beneath the shadow of Edward I's mighty castle walls—a rare survivor of 14th-century Welsh town life.","image":"https://img.castlecore.uk/aberconwy-house.jpg","rating":4.1,"reviewCount":800,"county":"Conwy","tags":["well-preserved","medieval","museum","gift-shop"],"access":"paid","_index":1579,"gallery":["https://img.castlecore.uk/aberconwy-house-2.jpg","https://img.castlecore.uk/aberconwy-house-3.jpg","https://img.castlecore.uk/aberconwy-house-4.jpg","https://img.castlecore.uk/aberconwy-house-5.jpg"],"history":"A 14th-century merchant's house in Conwy, the oldest surviving building in the town after the castle and walls. The timber-framed house has been used as a bakery, antiques shop, and temperance hotel over the centuries. It was acquired by the National Trust in 1934 and restored. The rooms are furnished to show different periods of its history from medieval to Victorian times.","sources":[{"name":"National Trust – Aberconwy House","url":"https://www.nationaltrust.org.uk/visit/wales/aberconwy-house"},{"name":"Wikipedia – Aberconwy House","url":"https://en.wikipedia.org/wiki/Aberconwy_House"}]},{"name":"Bodnant Garden","lat":53.225,"lng":-3.8,"country":"Wales","type":"historic-house","era":"19th century","condition":"intact","description":"One of the finest gardens in the UK — 80 acres of Italianate terraces, wild glens, and the famous Laburnum Arch that transforms into a golden tunnel every May.","image":"https://img.castlecore.uk/bodnant-garden.jpg","rating":4.7,"reviewCount":6000,"county":"Conwy","tags":["well-preserved","photogenic","gardens","romantic","woodland","riverside","tearoom-cafe","gift-shop"],"access":"paid","_index":1580,"gallery":["https://img.castlecore.uk/bodnant-garden-2.jpg","https://img.castlecore.uk/bodnant-garden-3.jpg","https://img.castlecore.uk/bodnant-garden-4.jpg","https://img.castlecore.uk/bodnant-garden-5.jpg"],"history":"Created from 1874 by Henry Pochin, a Victorian industrialist, and developed over five generations of the McLaren/Aberconwy family. The formal Italianate terraces descend toward the River Hiraethlyn. The famous Laburnum Arch, planted in 1880, is 55 metres long and draws thousands of visitors each May-June. Given to the National Trust in 1949 by the 2nd Lord Aberconwy. Contains a remarkable collection of rhododendrons, magnolias, and rare trees.","sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Bodnant_Garden"},{"name":"National Trust","url":"https://www.nationaltrust.org.uk/visit/wales/bodnant-garden"}]},{"name":"Neath Castle","lat":51.661,"lng":-3.806,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"A Norman stronghold tucked into a Welsh town centre — where the ghost of Granville's fortress still anchors the streets of Neath.","history":"Construction begun between 1114-1130 by Robert, Earl of Gloucester, Lord of Glamorgan. Also known as Granville's Castle after Richard de Grenville. The original timber motte-and-bailey near the Roman fort of Nidum was abandoned when Neath Abbey was founded nearby. The stone castle in the town centre survives as a ruin.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/7c/Neath_Castle_-_geograph.org.uk_-_42391.jpg/500px-Neath_Castle_-_geograph.org.uk_-_42391.jpg","rating":3.6,"reviewCount":300,"county":"Neath Port Talbot","tags":["hidden-gem","free-entry","norman","medieval"],"access":"free","_index":649,"gallery":["https://img.castlecore.uk/neath-castle-2.jpg","https://img.castlecore.uk/neath-castle-3.jpg","https://img.castlecore.uk/neath-castle-4.jpg","https://img.castlecore.uk/neath-castle-5.jpg","https://img.castlecore.uk/neath-castle-ruins-2.jpg","https://img.castlecore.uk/neath-castle-ruins-3.jpg","https://img.castlecore.uk/neath-castle-ruins-4.jpg","https://img.castlecore.uk/neath-castle-ruins-5.jpg","https://img.castlecore.uk/neath-castle-keep-2.jpg","https://img.castlecore.uk/neath-castle-keep-3.jpg","https://img.castlecore.uk/neath-castle-keep-4.jpg","https://img.castlecore.uk/neath-castle-keep-5.jpg"],"youtube":["tLKbwrnwZ1o","y7S9evEdMLg","igocsPjJ5Ac"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Neath_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/neath-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95296/"}]},{"name":"Neath Castle","lat":51.661,"lng":-3.806,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"A Norman stronghold tucked into a Welsh town centre — where the ghost of Granville's fortress still anchors the streets of Neath.","history":"Construction begun between 1114-1130 by Robert, Earl of Gloucester, Lord of Glamorgan. Also known as Granville's Castle after Richard de Grenville. The original timber motte-and-bailey near the Roman fort of Nidum was abandoned when Neath Abbey was founded nearby. The stone castle in the town centre survives as a ruin.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/7c/Neath_Castle_-_geograph.org.uk_-_42391.jpg/500px-Neath_Castle_-_geograph.org.uk_-_42391.jpg","rating":3.6,"reviewCount":300,"county":"Neath Port Talbot","tags":["hidden-gem","free-entry","norman","medieval"],"access":"free","_index":649,"gallery":["https://img.castlecore.uk/neath-castle-2.jpg","https://img.castlecore.uk/neath-castle-3.jpg","https://img.castlecore.uk/neath-castle-4.jpg","https://img.castlecore.uk/neath-castle-5.jpg","https://img.castlecore.uk/neath-castle-ruins-2.jpg","https://img.castlecore.uk/neath-castle-ruins-3.jpg","https://img.castlecore.uk/neath-castle-ruins-4.jpg","https://img.castlecore.uk/neath-castle-ruins-5.jpg","https://img.castlecore.uk/neath-castle-keep-2.jpg","https://img.castlecore.uk/neath-castle-keep-3.jpg","https://img.castlecore.uk/neath-castle-keep-4.jpg","https://img.castlecore.uk/neath-castle-keep-5.jpg"],"youtube":["tLKbwrnwZ1o","y7S9evEdMLg","igocsPjJ5Ac"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Neath_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/neath-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95296/"}]},{"name":"Neath Castle","lat":51.661,"lng":-3.806,"country":"Wales","type":"castle","era":"12th-13th century","condition":"ruin","description":"A Norman stronghold tucked into a Welsh town centre — where the ghost of Granville's fortress still anchors the streets of Neath.","history":"Construction begun between 1114-1130 by Robert, Earl of Gloucester, Lord of Glamorgan. Also known as Granville's Castle after Richard de Grenville. The original timber motte-and-bailey near the Roman fort of Nidum was abandoned when Neath Abbey was founded nearby. The stone castle in the town centre survives as a ruin.","image":"https://upload.wikimedia.org/wikipedia/commons/thumb/7/7c/Neath_Castle_-_geograph.org.uk_-_42391.jpg/500px-Neath_Castle_-_geograph.org.uk_-_42391.jpg","rating":3.6,"reviewCount":300,"county":"Neath Port Talbot","tags":["hidden-gem","free-entry","norman","medieval"],"access":"free","_index":649,"gallery":["https://img.castlecore.uk/neath-castle-2.jpg","https://img.castlecore.uk/neath-castle-3.jpg","https://img.castlecore.uk/neath-castle-4.jpg","https://img.castlecore.uk/neath-castle-5.jpg","https://img.castlecore.uk/neath-castle-ruins-2.jpg","https://img.castlecore.uk/neath-castle-ruins-3.jpg","https://img.castlecore.uk/neath-castle-ruins-4.jpg","https://img.castlecore.uk/neath-castle-ruins-5.jpg","https://img.castlecore.uk/neath-castle-keep-2.jpg","https://img.castlecore.uk/neath-castle-keep-3.jpg","https://img.castlecore.uk/neath-castle-keep-4.jpg","https://img.castlecore.uk/neath-castle-keep-5.jpg"],"youtube":["tLKbwrnwZ1o","y7S9evEdMLg","igocsPjJ5Ac"],"sources":[{"name":"Wikipedia","url":"https://en.wikipedia.org/wiki/Neath_Castle"},{"name":"Cadw","url":"https://cadw.gov.wales/visit/places-to-visit/neath-castle"},{"name":"Coflein","url":"https://coflein.gov.uk/en/site/95296/"}]}]
